export const QB_FED_SYSTEMES = [
  {id:"fed_s1",prompt:"Le protocole KNX (anciennement EIB) est un standard de :",choices:["Plomberie","Domotique et GTB (Gestion Technique du Bâtiment) — bus de communication","Génie climatique uniquement","Sécurité incendie"],answer:1,diff:1,explication:"KNX = protocole de bus domotique standardisé (ISO/IEC 14543). Gère éclairage, chauffage, volets, sécurité, énergie. Topologie en bus (2 fils) ou IP.",tags:["Domotique","KNX","GTB","Protocoles"]},
  {id:"fed_s2",prompt:"Un capteur de présence (détecteur de mouvement) en domotique KNX envoie sur le bus :",choices:["Un signal analogique 4-20 mA","Un télégramme (trame numérique) sur le bus KNX","Un signal 0-10V","Un signal Wi-Fi"],answer:1,diff:2,explication:"KNX : communication par télégrammes numériques sur le bus (TP = paire torsadée ou IP). Chaque composant possède une adresse individuelle et peut communiquer avec des adresses de groupe.",tags:["Domotique","KNX","Télégramme","Capteur"]},
  {id:"fed_s3",prompt:"Dans un système KNX, l'adresse de groupe sert à :",choices:["Identifier physiquement un appareil","Définir la fonction logique (relier un bouton poussoir à un actionneur de lumière)","Paramétrer la vitesse du bus","Identifier le fabricant"],answer:1,diff:2,explication:"Adresse individuelle : localisation physique (1.1.5). Adresse de groupe : association fonctionnelle (entrée/sortie). Un bouton (groupe 0/1/1) commande un actionneur (même adresse de groupe).",tags:["Domotique","KNX","Adressage","Programmation"]},
  {id:"fed_s4",prompt:"Le protocole Modbus est principalement utilisé pour :",choices:["La domotique résidentielle haut de gamme","La communication industrielle et GTB (supervision des équipements techniques)","Les réseaux Wi-Fi","La téléphonie"],answer:1,diff:2,explication:"Modbus RTU/TCP : protocole maître-esclave industriel. Très répandu en GTB pour supervision des automates, compteurs d'énergie, CVC. Simple, robuste, mais peu sécurisé.",tags:["GTB","Modbus","Protocoles industriels","Supervision"]},
  {id:"fed_s5",prompt:"Le BACnet (Building Automation and Control Networks) est un protocole ouvert dédié à :",choices:["La domotique résidentielle","L'automatisation des bâtiments tertiaires (GTB, CVC, énergie)","La vidéosurveillance","La voix sur IP"],answer:1,diff:2,explication:"BACnet (ASHRAE 135) : protocole ouvert pour GTB bâtiments tertiaires. Interopérabilité entre constructeurs. Gère CVC, éclairage, comptage énergie, contrôle d'accès. Peut fonctionner sur IP (BACnet/IP).",tags:["GTB","BACnet","Bâtiment tertiaire","Protocoles"]},
  {id:"fed_s6",prompt:"Une GTB (Gestion Technique du Bâtiment) permet de :",choices:["Uniquement contrôler l'éclairage","Superviser, contrôler et optimiser tous les équipements techniques d'un bâtiment (CVC, éclairage, énergie, sécurité)","Uniquement gérer les accès","Effectuer la maintenance uniquement"],answer:1,diff:1,explication:"GTB : supervision centralisée (postes opérateur), contrôle commande (automates programmables), collecte données (compteurs, capteurs), optimisation énergie, maintenance préventive.",tags:["GTB","Bâtiment","Supervision","Énergie"]},
  {id:"fed_s7",prompt:"Le BIM (Building Information Modeling) est :",choices:["Un logiciel de dessin 2D uniquement","Une maquette numérique tridimensionnelle et collaborative intégrant toutes les données du bâtiment","Un protocole de communication","Un système de ventilation"],answer:1,diff:1,explication:"BIM : maquette numérique 3D + données (matériaux, coûts, planning, équipements). Collaboration entre tous les acteurs (archi, BE, GTB). Logiciels : Revit, ArchiCAD. Niveaux de développement (LOD).",tags:["BIM","Numérique","Collaboration","Bâtiment"]},
  {id:"fed_s8",prompt:"SysML (Systems Modeling Language) est utilisé pour :",choices:["La programmation des automates uniquement","La modélisation des systèmes complexes (diagrammes de blocs, d'exigences, de séquences)","La conception des réseaux Wi-Fi","La modélisation des fluides uniquement"],answer:1,diff:2,explication:"SysML : langage de modélisation pour systèmes complexes. 9 types de diagrammes (exigences, blocs, activités, séquences...). Utilisé en ingénierie systèmes, analyse des exigences.",tags:["SysML","Modélisation","Systèmes complexes","Diagrammes"]},
  {id:"fed_s9",prompt:"Un TGBT (Tableau Général Basse Tension) contient :",choices:["Uniquement des prises électriques","Les protections électriques principales (disjoncteur général, sectionneurs, jeux de barres) et la distribution vers les tableaux divisionnaires","Uniquement des compteurs","Les équipements de domotique"],answer:1,diff:2,explication:"TGBT : armoire électrique principale alimentée depuis le transformateur HTA/BT. Protections principales (disjoncteur général), jeux de barres, départ divisionnaires, compteurs énergie.",tags:["Électrotechnique","TGBT","Distribution électrique","Protection"]},
  {id:"fed_s10",prompt:"La norme NF C 15-100 concerne :",choices:["Les installations de plomberie","Les installations électriques basse tension en France (règles de conception, réalisation, vérification)","Les équipements de ventilation","Les réseaux de communication"],answer:1,diff:1,explication:"NF C 15-100 : norme française pour installations électriques basse tension (locaux d'habitation et tertiaire). Sections de câbles, protections, tableaux, prises, liaisons équipotentielles.",tags:["Électrotechnique","NF C 15-100","Réglementation","Installation électrique"]},
  {id:"fed_s11",prompt:"Un variateur de fréquence (VFD) permet de :",choices:["Protéger contre les courts-circuits","Faire varier la vitesse d'un moteur asynchrone en modifiant la fréquence d'alimentation","Mesurer la puissance consommée","Compenser l'énergie réactive"],answer:1,diff:2,explication:"VFD (Variable Frequency Drive) : convertit la fréquence secteur (50 Hz) en fréquence variable → vitesse moteur variable. Économies d'énergie importantes sur pompes et ventilateurs (loi des ventilateurs).",tags:["Électrotechnique","Variateur","Moteur","Économie d'énergie"]},
  {id:"fed_s12",prompt:"La loi des ventilateurs (affinité) indique que :",choices:["Le débit est proportionnel au carré de la vitesse","La puissance consommée est proportionnelle au cube de la vitesse (P ∝ n³)","La pression est indépendante de la vitesse","Le débit est constant quelle que soit la vitesse"],answer:1,diff:3,explication:"Lois des ventilateurs : Q ∝ n, ΔP ∝ n², P ∝ n³. Réduire la vitesse de 20% → économie de puissance de 50% ! Justifie les variateurs de fréquence en CVC.",tags:["Électrotechnique","Loi des ventilateurs","Variateur","CVC"]},
  {id:"fed_s13",prompt:"Un câble de communication paire torsadée blindée (FTP) se distingue d'un câble non blindé (UTP) par :",choices:["Sa couleur","Sa résistance aux interférences électromagnétiques (EMI) grâce au blindage","Son débit plus faible","Sa couleur rouge obligatoire"],answer:1,diff:1,explication:"FTP (Foiled Twisted Pair) : blindage aluminium autour des paires. Protection contre EMI. Obligatoire en environnement industriel (VDI, bus KNX dans armoires avec variateurs, etc.).",tags:["Réseaux","Câblage","FTP","Perturbations EM"]},
  {id:"fed_s14",prompt:"Le câblage VDI (Voix-Données-Images) en étoile utilise un point de concentration appelé :",choices:["TGBT","Baie de brassage (patch panel) dans un local technique","Box internet","Switch WiFi"],answer:1,diff:1,explication:"VDI en étoile : chaque prise (RJ45) reliée par câble catégorie 6 jusqu'au local technique. Baie de brassage (patch panel) + switch PoE. Permet reconfiguration facile.",tags:["VDI","Câblage structuré","Réseaux","Baie de brassage"]},
  {id:"fed_s15",prompt:"Le protocole DALI (Digital Addressable Lighting Interface) est utilisé pour :",choices:["La gestion du chauffage","Le contrôle numérique de l'éclairage (gradation, groupes, scènes)","La gestion des accès","La supervision des pompes"],answer:1,diff:2,explication:"DALI : protocole numérique dédié à l'éclairage. Adressage individuel de chaque luminaire. Gradation (0-100%), groupes, scènes préprogrammées. Interfaçable avec KNX.",tags:["Domotique","DALI","Éclairage","Gradation"]},
];

export const QB_FED_ENERGIE = [
  {id:"fed_e1",prompt:"La puissance active (P) s'exprime en :",choices:["Volt-Ampères (VA)","Watts (W) — énergie réellement consommée/transformée","Volt-Ampères réactifs (VAR)","Kilowattheures (kWh)"],answer:1,diff:1,explication:"P (W) = puissance active = énergie transformée en chaleur, mécanique, lumière. Q (VAR) = puissance réactive (champs magnétiques). S (VA) = puissance apparente. S² = P² + Q².",tags:["Énergie","Puissance","Électrotechnique"]},
  {id:"fed_e2",prompt:"Le facteur de puissance (cos φ) idéal est :",choices:["0","0.5","1 (toute la puissance apparente est active)","2"],answer:2,diff:1,explication:"cos φ = P/S = 1 → pas de puissance réactive. Si cos φ < 0.93, le distributeur peut pénaliser l'abonné. Compensation par batterie de condensateurs (injection Q capacitive contre Q inductrice des moteurs).",tags:["Énergie","Facteur de puissance","Compensation réactive"]},
  {id:"fed_e3",prompt:"La réglementation thermique RE 2020 succède à la RT 2012 en imposant :",choices:["Uniquement une meilleure isolation","Un bilan carbone positif + confort d'été + seuil énergie primaire (Ep < 100 kWh/m²/an)","L'utilisation obligatoire du gaz","Aucune nouvelle exigence"],answer:1,diff:2,explication:"RE 2020 : 3 indicateurs principaux. 1) IC (Impact Carbone) — bilan carbone du bâtiment. 2) Bbio (besoin bioclimatique). 3) Cep (consommation énergie primaire < 100 kWh/m²/an). Focus sur chaleur d'été.",tags:["Énergie","RE 2020","Thermique","Réglementation"]},
  {id:"fed_e4",prompt:"La pompe à chaleur (PAC) air-air prélève des frigories de l'air extérieur pour :",choices:["Refroidir uniquement en été","Chauffer le bâtiment en hiver (cycle frigorifique inversé)","Produire de l'eau chaude sanitaire uniquement","Ventiler le bâtiment"],answer:1,diff:1,explication:"PAC : cycle frigorifique. En hiver (mode chauffe) : l'évaporateur prélève la chaleur de l'air extérieur, le condenseur restitue la chaleur à l'intérieur. COP > 1 (typiquement 3-4).",tags:["Énergie","Pompe à chaleur","Thermodynamique","COP"]},
  {id:"fed_e5",prompt:"Le COP (Coefficient de Performance) d'une PAC est :",choices:["Toujours inférieur à 1","Le rapport puissance thermique fournie / puissance électrique consommée (COP > 1)","Le taux de compression du frigorigène","La température de la source froide"],answer:1,diff:2,explication:"COP = Pthermique/Pélectrique. COP = 3 : pour 1 kW électrique, 3 kW thermiques fournis (2 kW gratuits prélevés sur l'environnement). SCOP = COP saisonnier (conditions réelles).",tags:["Énergie","COP","PAC","Thermodynamique"]},
  {id:"fed_e6",prompt:"La VMC double flux se distingue de la simple flux par :",choices:["Elle ventile seulement les pièces humides","Elle récupère la chaleur de l'air extrait pour préchauffer l'air neuf entrant (échangeur)","Elle ne filtre pas l'air","Elle consomme plus d'énergie sans bénéfice"],answer:1,diff:2,explication:"VMC double flux : échangeur air-air (rendement > 80%) récupère la chaleur de l'air vicié pour préchauffer l'air neuf. Économie d'énergie + meilleure qualité d'air. Obligatoire en maisons passives.",tags:["Énergie","VMC","Ventilation","Récupération de chaleur"]},
  {id:"fed_e7",prompt:"Le DPE (Diagnostic de Performance Énergétique) classe les bâtiments de :",choices:["A à E","A (< 70 kWh/m²/an) à G (> 420 kWh/m²/an)","1 à 10","Rouge à vert"],answer:1,diff:1,explication:"DPE : étiquette énergie A (très performant, < 70 kWh/m²/an) → G (passoire thermique, > 420 kWh/m²/an). Aussi étiquette GES (CO₂). Opposable depuis 2021. Passoires (F et G) en cours d'interdiction à la location.",tags:["Énergie","DPE","Réglementation","Bâtiment"]},
  {id:"fed_e8",prompt:"L'isolation thermique par l'extérieur (ITE) est préférable à l'isolation par l'intérieur car :",choices:["Elle est moins chère","Elle supprime les ponts thermiques et conserve l'inertie thermique de la structure","Elle est plus rapide à poser","Elle n'existe pas"],answer:1,diff:2,explication:"ITE : isolation enveloppant la structure. Avantages : suppression ponts thermiques (angles, liaisons plancher/mur), conservation inertie thermique de la structure, pas de perte de surface habitable.",tags:["Énergie","Isolation","ITE","Ponts thermiques"]},
  {id:"fed_e9",prompt:"Un compteur communicant Linky permet à ENEDIS de :",choices:["Fixer le prix de l'électricité","Relever la consommation à distance (via CPL), détecter les incidents, activer les options tarifaires","Alimenter le bâtiment directement","Stocker l'énergie solaire"],answer:1,diff:1,explication:"Linky : compteur communicant CPL (Courant Porteur en Ligne). Télé-relevé des données, coupure à distance, activation heures creuses/pointe, détection pannes. 35 millions déployés en France.",tags:["Énergie","Linky","Smart metering","ENEDIS"]},
  {id:"fed_e10",prompt:"La mise à la terre (liaison équipotentielle principale) protège contre :",choices:["Les surintensités","Les contacts indirects (défaut d'isolement vers la masse : la fuite est écoulée à la terre)","Les sous-tensions","La surtension harmonique"],answer:1,diff:2,explication:"Mise à la terre : toutes les masses (parties conductrices d'équipements) reliées à la terre. En cas de défaut d'isolement, le courant s'écoule via la terre → déclenchement disjoncteur différentiel. Protection contact indirect.",tags:["Électrotechnique","Mise à la terre","Protection","Sécurité électrique"]},
  {id:"fed_e11",prompt:"Le schéma TN-S se distingue du TN-C par :",choices:["La présence d'un transformateur","La séparation du neutre (N) et du conducteur de protection (PE) sur tout le circuit (sécurité accrue)","L'absence de prise de terre","La tension d'alimentation"],answer:1,diff:3,explication:"TN-S : N et PE séparés dès l'origine. TN-C : N et PE combinés (PEN). TN-C interdit en France pour installations neuves (NF C 15-100). TN-S préféré pour sa sécurité (courants parasites séparés).",tags:["Électrotechnique","Schéma TN","Neutre","Protection"]},
  {id:"fed_e12",prompt:"Un onduleur (UPS) est utilisé pour :",choices:["Améliorer le facteur de puissance","Alimenter sans interruption des équipements critiques (serveurs, blocs opératoires) en cas de coupure secteur","Convertir le courant continu en courant alternatif photovoltaïque","Stabiliser la tension d'un réseau longue distance"],answer:1,diff:1,explication:"UPS (Uninterruptible Power Supply) : stocke de l'énergie (batteries) et prend le relai en cas de microcoupure ou coupure. Temps d'autonomie variable (minutes à heures). Usage : datacenters, chirurgie, télécom.",tags:["Électrotechnique","UPS","Onduleur","Continuité d'alimentation"]},
  {id:"fed_e13",prompt:"La valeur nominale d'un disjoncteur différentiel résidentiel de type A est choisie pour :",choices:["Détecter uniquement les courants alternatifs sinusoïdaux","Détecter les courants de fuite alternatifs ET pulsatoires (appareils avec alimentations à découpage : lave-linge, TV)","Détecter uniquement les courants continus","Mesurer la consommation électrique"],answer:1,diff:3,explication:"Type AC : courants sinusoïdaux seulement. Type A : sinusoïdaux + pulsatoires (DC pulsé). Obligatoire pour les cuisinières, lave-vaisselle, lave-linge, véhicules électriques (VE). Type F : pour bornes VE.",tags:["Électrotechnique","Disjoncteur différentiel","Type A","Protection"]},
  {id:"fed_e14",prompt:"Un système photovoltaïque raccordé réseau nécessite obligatoirement :",choices:["Un onduleur DC/AC + démarches ENEDIS + convention de raccordement","Uniquement des panneaux solaires","Un compteur Linky spécifique","Un générateur de secours"],answer:0,diff:2,explication:"PV raccordé réseau : onduleur (DC→AC), démarches ENEDIS (dossier CACSI), convention de raccordement, compteur bidirectionnel. L'excédent peut être revendu ou autoconsommé.",tags:["Énergie","Photovoltaïque","Raccordement","ENEDIS"]},
  {id:"fed_e15",prompt:"La thermographie infrarouge en maintenance préventive permet de :",choices:["Mesurer la résistance des câbles","Détecter les points chauds (connexions défectueuses, surchauffes) sans contact","Contrôler l'étanchéité pneumatique","Mesurer le débit des fluides"],answer:1,diff:2,explication:"Thermographie IR : caméra infrarouge détecte les différences de température. Connexions oxydées/desserrées → points chauds → risque incendie. Contrôle TGBT, tableaux électriques, armoires.",tags:["Maintenance","Thermographie","Prévention","Électrotechnique"]},
];

export const QB_FED_PHYSIQUE = [
  {id:"fed_p1",prompt:"La loi d'Ohm pour un circuit résistif pur est :",choices:["U = R × I²","U = R × I (tension = résistance × intensité)","U = I / R","I = U²/R"],answer:1,diff:1,explication:"Loi d'Ohm : U (V) = R (Ω) × I (A). La résistance s'oppose au passage du courant. Puissance dissipée : P = U×I = R×I² = U²/R. Analogie hydraulique : U=pression, I=débit, R=résistance tuyau.",tags:["Électricité","Loi d'Ohm","Résistance","FED"]},
  {id:"fed_p2",prompt:"Les lois de Kirchhoff stipulent :",choices:["Que la tension est la même partout dans le circuit","La loi des nœuds (somme des courants = 0) et la loi des mailles (somme des tensions = 0)","Que la résistance est constante","Que la puissance est toujours maximale"],answer:1,diff:2,explication:"Kirchhoff 1 (nœuds) : ΣI entrants = ΣI sortants. Kirchhoff 2 (mailles) : algèbre des tensions dans une boucle fermée = 0. Base de toute l'analyse des circuits électriques.",tags:["Électricité","Kirchhoff","Circuits","Analyse"]},
  {id:"fed_p3",prompt:"En courant alternatif sinusoïdal 50 Hz, la valeur efficace (RMS) d'une tension de 230 V correspond à une amplitude de :",choices:["230 V","325 V (Umax = Ueff × √2 ≈ 230 × 1.414)","115 V","460 V"],answer:1,diff:2,explication:"Valeur efficace (RMS) = Umax/√2 → Umax = Ueff × √2 ≈ 230 × 1.414 ≈ 325 V. La valeur efficace est l'équivalent continu en termes d'énergie dissipée dans une résistance.",tags:["Électricité","Courant alternatif","Valeur efficace","RMS"]},
  {id:"fed_p4",prompt:"L'énergie stockée par un condensateur est :",choices:["E = L × I²/2","E = C × U²/2 (C en farads, U en volts)","E = R × I²","E = P × t"],answer:1,diff:2,explication:"Condensateur : stocke énergie électrostatique E = ½CU². S'oppose aux variations de tension. En alternatif : réactance Xc = 1/(2πfC). L'inductance stocke E = ½LI² (énergie magnétique).",tags:["Électricité","Condensateur","Énergie","Réactance"]},
  {id:"fed_p5",prompt:"En thermodynamique, le premier principe stipule que :",choices:["L'entropie d'un système isolé augmente toujours","L'énergie totale d'un système fermé est conservée (ΔU = W + Q)","La chaleur ne peut aller que du chaud vers le froid","La température absolue ne peut être négative"],answer:1,diff:2,explication:"1er principe : conservation de l'énergie. ΔU = W (travail) + Q (chaleur). Application : bilan thermique d'un bâtiment (pertes + gains = 0 à l'équilibre). PAC : ΔH = W_compresseur + Q_évaporateur.",tags:["Thermodynamique","Premier principe","Bilan thermique","FED"]},
  {id:"fed_p6",prompt:"La résistance thermique (Rth) d'une paroi est calculée par :",choices:["Rth = λ × e","Rth = e / λ (e = épaisseur en m, λ = conductivité thermique en W/m.K)","Rth = U × I","Rth = λ / e²"],answer:1,diff:2,explication:"Résistance thermique : Rth = e/λ (m²K/W). Plus Rth est élevé, meilleure est l'isolation. Résistances en série s'additionnent (parois multicouches). Coefficient U = 1/ΣRth (W/m²K).",tags:["Thermodynamique","Isolation","Résistance thermique","RE 2020"]},
  {id:"fed_p7",prompt:"Le coefficient de transmission thermique U (anciennement K) s'exprime en :",choices:["W/m.K (conductivité)","W/m²K — flux thermique par unité de surface et de différence de température","kJ/kg.K (chaleur massique)","Pa (pression)"],answer:1,diff:1,explication:"U (W/m²K) = coefficient global de transmission (anciennement K). Mur très isolé : U < 0.15 W/m²K. Fenêtre double vitrage : U ≈ 1.4. Triple vitrage : U ≈ 0.7. RE 2020 impose des valeurs U max par composant.",tags:["Thermodynamique","Coefficient U","Isolation","RE 2020"]},
  {id:"fed_p8",prompt:"La formule de Bernoulli (hydraulique) exprime :",choices:["La conservation de la masse","La conservation de l'énergie dans un fluide parfait (P + ρgh + ½ρv² = constante)","La loi des gaz parfaits","La loi de Darcy"],answer:1,diff:2,explication:"Bernoulli : énergie totale conservée le long d'une ligne de courant. P (pression statique) + ρgh (énergie potentielle) + ½ρv² (énergie cinétique) = constante. Application : Venturi, écoulements dans tuyaux.",tags:["Hydraulique","Bernoulli","Fluides","Mécanique des fluides"]},
  {id:"fed_p9",prompt:"La loi de Poiseuille décrit l'écoulement laminaire dans un tuyau. Le débit volumique Q est proportionnel à :",choices:["La longueur du tuyau","La 4ème puissance du rayon (Q ∝ r⁴) et au gradient de pression","La viscosité","La vitesse de l'écoulement turbulent"],answer:1,diff:3,explication:"Poiseuille : Q = π×r⁴×ΔP / (8×η×L). Doublement du rayon → ×16 le débit ! Explique l'importance du dimensionnement des canalisations. Valable si régime laminaire (Re < 2300).",tags:["Hydraulique","Poiseuille","Débit","Tuyaux"]},
  {id:"fed_p10",prompt:"Le nombre de Reynolds (Re) détermine si un écoulement est :",choices:["Stationnaire ou non","Laminaire (Re < 2300) ou turbulent (Re > 4000), transitoire entre les deux","Compressible ou incompressible","Isotherme ou adiabatique"],answer:1,diff:2,explication:"Re = ρ×v×D/η. Laminaire (< 2300) : couches parallèles, faibles pertes de charge. Turbulent (> 4000) : mélanges, pertes de charge élevées. Transitoire (2300-4000) : instable. Applications : CVC, plomberie.",tags:["Hydraulique","Nombre de Reynolds","Turbulence","Écoulement"]},
  {id:"fed_p11",prompt:"Les pertes de charge régulières dans une canalisation suivent la loi de :",choices:["Bernoulli uniquement","Darcy-Weisbach (ΔP = f × L/D × ρv²/2)","Poiseuille pour les régimes turbulents","Kirchhoff pour les fluides"],answer:1,diff:3,explication:"Darcy-Weisbach : ΔP = f × (L/D) × (ρv²/2). f = facteur de frottement (Moody chart : dépend Re et rugosité). Utilisé pour dimensionner les réseaux de chauffage, climatisation, eau sanitaire.",tags:["Hydraulique","Pertes de charge","Darcy-Weisbach","Dimensionnement"]},
  {id:"fed_p12",prompt:"En acoustique, le niveau de pression sonore en dB est calculé par :",choices:["L = P/P₀","L = 10 × log(I/I₀) en dB (I₀ = 10⁻¹² W/m²)","L = P² × f","L = 20 × log(I/I₀)"],answer:1,diff:2,explication:"Niveau sonore : L = 10×log(I/I₀) dB. Doublement de l'intensité → +3 dB. Doublement de la pression sonore → +6 dB (L = 20×log(p/p₀)). 0 dB = seuil d'audibilité. 140 dB = seuil douleur.",tags:["Acoustique","Décibel","Son","FED"]},
  {id:"fed_p13",prompt:"L'indice d'affaiblissement acoustique Rw mesure :",choices:["L'isolation thermique d'une paroi","La capacité d'une paroi à atténuer la transmission des sons aériens (en dB)","La réverbération d'une salle","L'absorption acoustique d'un matériau"],answer:1,diff:2,explication:"Rw (dB) : isolement aux bruits aériens. Plus Rw est élevé, meillleure l'isolation. Briques pleines : Rw ≈ 50 dB. Cloison plâtre : Rw ≈ 36 dB. Réglementation acoustique NF S 31-032.",tags:["Acoustique","Isolation phonique","Rw","Bâtiment"]},
  {id:"fed_p14",prompt:"La puissance apparente S en triphasé équilibré est :",choices:["S = U×I","S = √3 × U_ligne × I_ligne","S = 3 × P","S = U²/R"],answer:1,diff:3,explication:"Triphasé équilibré : S = √3 × U_L × I_L (VA) ou S = 3 × U_phase × I_phase. Puissance active P = √3 × U_L × I_L × cos φ. Très utilisé en électrotechnique industrielle et tertiaire.",tags:["Électrotechnique","Triphasé","Puissance apparente","FED"]},
  {id:"fed_p15",prompt:"La compensation de l'énergie réactive par batterie de condensateurs permet :",choices:["D'augmenter la tension","D'améliorer le facteur de puissance → réduire les pertes en ligne et éviter les pénalités du distributeur","De stocker l'énergie solaire","D'alimenter le réseau pendant les coupures"],answer:1,diff:2,explication:"Batterie de condensateurs : inject Q capacitive compensant Q inductrice (moteurs). cos φ → 1. Réduit l'intensité dans les câbles (pertes Joule ∝ I²R) et les pénalités énergie réactive du fournisseur.",tags:["Électrotechnique","Énergie réactive","Condensateur","Facteur de puissance"]},
];

export const QB_FED_THERMO2024 = [
  {id:"fed_t1",prompt:"Les 3 modes de transfert thermique sont :",choices:["Conduction, convection et rayonnement","Radiation, advection et diffusion","Absorption, réflexion et transmission","Évaporation, condensation et sublimation"],answer:0,diff:1,explication:"(1) Conduction : transfert dans un solide (ex : mur) par agitation moléculaire. (2) Convection : transfert par mouvement d'un fluide (air chaud qui monte). (3) Rayonnement : transfert électromagnétique (infrarouge) sans milieu matériel (ex : soleil → Terre). En bâtiment, les 3 modes coexistent.",tags:["Thermique","Transfert thermique","Conduction","Convection","Rayonnement"]},
  {id:"fed_t2",prompt:"La résistance thermique d'une paroi monocouche est calculée par :",choices:["Rth = λ/e","Rth = e/λ","Rth = e × λ","Rth = 1/(λ × S)"],answer:1,diff:1,explication:"Rth (m²·K/W) = e (épaisseur en m) / λ (conductivité thermique en W/m·K). Pour une paroi multicouche, les résistances s'additionnent en série : Rtot = ΣRth. Plus Rth est grand, plus l'isolation est bonne.",tags:["Thermique","Résistance thermique","Isolation","Formule"]},
  {id:"fed_t3",prompt:"Le coefficient de transmission thermique U d'une paroi (en W/m²·K) est :",choices:["U = Rtotal × S","U = 1 / R_total","U = λ × e","U = ΔT / Φ"],answer:1,diff:1,explication:"U = 1/Rtotal (W/m²·K). Plus U est petit → paroi mieux isolée. Réglementation RE 2020 : U mur extérieur ≤ 0.20 W/m²·K, U toiture ≤ 0.13, U vitrage ≤ 1.4. Anciennement nommé K.",tags:["Coefficient U","Thermique","Isolation","RE 2020"]},
  {id:"fed_t4",prompt:"Les déperditions thermiques Φ à travers une paroi sont calculées par :",choices:["Φ = U × S × ΔT (avec U en W/m²·K, S en m², ΔT en K)","Φ = λ × e × ΔT","Φ = R × S × ΔT","Φ = S / (R × ΔT)"],answer:0,diff:2,explication:"Φ (W) = U × S × ΔT = S × ΔT / Rtotal. Équivalent à la loi de Fourier en régime permanent. Ex : mur de 100 m² avec U=0.30, ΔT=15K : Φ = 0.30 × 100 × 15 = 450 W.",tags:["Déperditions thermiques","Formule","Φ","Puissance calorifique"]},
  {id:"fed_t5",prompt:"L'eau glycolée (MPG — mono propylène glycol) est utilisée dans les circuits frigorifiques car :",choices:["Elle a un meilleur pouvoir calorifique que l'eau pure","Elle abaisse le point de congélation, protégeant les circuits contre le gel","Elle améliore le transfert de chaleur","Elle est moins corrosive que l'eau"],answer:1,diff:1,explication:"Le MPG (propylène glycol, noté aussi PG) abaisse le point de congélation de l'eau : 30% vol → Tgel ≈ -15°C. Il protège les circuits exposés au froid (terrasses, extérieur). Contrairement à l'éthylène glycol, le MPG est non toxique (utilisé en agroalimentaire). Inconvénient : viscosité plus élevée → calcul Reynolds nécessaire.",tags:["Eau glycolée","MPG","Antigel","Hydraulique FED"]},
  {id:"fed_t6",prompt:"Le nombre de Reynolds Re permet de caractériser le régime d'écoulement. Re est calculé par :",choices:["Re = ρ × v × D / μ (avec ρ masse volumique, v vitesse, D diamètre, μ viscosité dynamique)","Re = v × D / ρ","Re = μ × D / v","Re = P / (ρ × v²)"],answer:0,diff:2,explication:"Re = ρ × v × D / μ (adimensionnel). Régimes : Re < 2300 = laminaire (Poiseuille), 2300 < Re < 4000 = transitoire, Re > 4000 = turbulent. Pour l'eau glycolée (viscosité μ plus élevée), Re est plus faible → régime laminaire plus probable.",tags:["Reynolds","Hydraulique","Régime d'écoulement","FED"]},
  {id:"fed_t7",prompt:"La dureté de l'eau (TH — titre hydrotimétrique) mesure la concentration en :",choices:["Chlorures (Cl⁻) et sulfates (SO₄²⁻)","Ions calcium (Ca²⁺) et magnésium (Mg²⁺)","Nitrates (NO₃⁻)","Dioxyde de carbone dissous"],answer:1,diff:1,explication:"TH = teneur en Ca²⁺ + Mg²⁺ exprimée en degrés français (°f). 1°f = 0.1 mmol/L de CaCO₃ équivalent. Eau douce < 15°f, eau dure > 25°f. L'eau dure forme du tartre (CaCO₃) dans les circuits de chauffage et bouilloires → réduction des échanges thermiques.",tags:["TH","Titre hydrotimétrique","Dureté de l'eau","Chimie eau"]},
  {id:"fed_t8",prompt:"Dans un adoucisseur d'eau à résine échangeuse de cations, la phase de régénération consiste à :",choices:["Filtrer les particules solides avec un filtre mécanique","Injecter de la saumure (eau salée NaCl) pour régénérer la résine saturée en Ca²⁺ et Mg²⁺","Ajouter des antitartre chimiques","Chauffer la résine pour libérer les ions captés"],answer:1,diff:2,explication:"Adoucisseur : résine Na⁺ capte Ca²⁺ et Mg²⁺ → résine se sature. Régénération : saumure NaCl → Na⁺ en excès déplace Ca²⁺/Mg²⁺ → résine rechargée en Na⁺. Phases : (1) adoucissement (R-Na + Ca²⁺ → R-Ca + Na⁺), (2) saturation (capacité épuisée), (3) régénération (retour Na⁺).",tags:["Adoucisseur","Résine échangeuse","Régénération","Chimie eau FED"]},
  {id:"fed_t9",prompt:"La réaction de combustion complète du méthane (CH4) produit :",choices:["CO + H2O (monoxyde de carbone + eau)","CO2 + 2H2O (dioxyde de carbone + eau)","C + H2O (carbone + eau)","CO2 + H2 (dioxyde de carbone + dihydrogène)"],answer:1,diff:1,explication:"CH4 + 2O2 → CO2 + 2H2O (ΔH = -890 kJ/mol). Combustion complète : présence suffisante de O2. Combustion incomplète (manque O2) : formation de CO (monoxyde de carbone) + suies → danger mortel par intoxication au CO (affinité CO-hémoglobine >> O2). Ventilation obligatoire des chaufferies.",tags:["Combustion","Méthane","CH4","CO2","Chaudière"]},
  {id:"fed_t10",prompt:"Le monoxyde de carbone (CO) est dangereux car :",choices:["Il est explosive et s'enflamme spontanément","Il est inodore, incolore et se fixe sur l'hémoglobine avec une affinité 200× supérieure à l'oxygène → intoxication silencieuse","Il est corrosif et attaque les canalisations","Il fait chuter la pression dans les circuits"],answer:1,diff:2,explication:"Le CO (monoxyde de carbone) est produit par la combustion incomplète (manque d'air). Il est inodore et incolore → indétectable sans capteur. Il se fixe sur l'hémoglobine (COHb) 200-240 fois plus fort que O₂ → hypoxie. Cause principale d'intoxications mortelles en habitation (chaudières, poêles). Détecteur CO obligatoire.",tags:["CO","Monoxyde de carbone","Combustion incomplète","Sécurité chaufferie"]},
  {id:"fed_t11",prompt:"Une centrale de traitement d'air (CTA) double flux avec récupérateur de chaleur est utilisée car :",choices:["Elle ne nécessite pas de maintenance","Elle récupère l'énergie de l'air vicié extrait pour préchauffer/prérefroidir l'air neuf entrant, réduisant les consommations de 60 à 90%","Elle filtre les polluants chimiques","Elle humidifie l'air"],answer:1,diff:2,explication:"CTA double flux : l'air extrait (soufflage chaud en hiver) et l'air neuf (froid en hiver) passent dans un échangeur thermique. L'énergie est transférée sans mélange d'air. Rendement échangeur : 60-90%. Obligatoire en RE 2020 pour les bâtiments tertiaires. Les CTA peuvent aussi comporter des batteries de chauffe/refroid et de l'humidification.",tags:["CTA","Double flux","Récupérateur de chaleur","RE 2020","VMC"]},
  {id:"fed_t12",prompt:"En GTB (Gestion Technique du Bâtiment), la régulation d'une installation CVC (Chauffage Ventilation Climatisation) repose typiquement sur :",choices:["Un simple interrupteur marche/arrêt","Un correcteur PID (Proportionnel Intégral Dérivé) qui compare la mesure au point de consigne et calcule une commande corrective","Un minuteur uniquement","Une décision humaine à chaque cycle"],answer:1,diff:2,explication:"Régulation PID : mesure (capteur T°) → comparaison à la consigne (setpoint) → calcul écart (erreur) → correcteur PID → commande sur actionneur (vanne, pompe). P (proportionnel) : action proportionnelle à l'erreur ; I (intégral) : élimine l'erreur statique ; D (dérivé) : anticipe les variations. Utilisé pour la régulation de température, pression, débit en GTB.",tags:["GTB","Régulation PID","CVC","Automatique FED"]},
];

export const QB_FED_PAC = [
  {id:"fed_pac1",prompt:"Une pompe à chaleur (PAC) thermodynamique fonctionne en :",choices:["Brûlant un combustible pour produire de la chaleur","Captant les calories d'une source froide (air, eau, sol) et les restituant à une source chaude grâce à un compresseur électrique","Convertissant directement l'électricité en chaleur par effet Joule","Stockant de l'énergie solaire en journée pour la restituer la nuit"],answer:1,diff:1,explication:"Une PAC capte des calories dans une source froide (air extérieur, eau, sol) et les restitue à une source chaude (logement). Elle utilise un cycle frigorifique alimenté par un compresseur électrique. Le principe : pour 1 kW électrique consommé, elle fournit 3 à 5 kW thermiques.",tags:["PAC","Principe","Cycle frigorifique","Thermodynamique"]},
  {id:"fed_pac2",prompt:"Le COP (Coefficient of Performance) d'une PAC en mode chauffage est défini par :",choices:["COP = P_électrique / P_thermique","COP = P_thermique_utile / P_électrique_consommée","COP = T_source_chaude / T_source_froide","COP = P_froid / P_élec"],answer:1,diff:1,explication:"COP = P_thermique_utile / P_électrique_consommée. Un COP de 4 signifie que pour 1 kW électrique consommé, 4 kW thermiques sont fournis. En mode froid (PAC réversible), on parle d'EER (Energy Efficiency Ratio) = P_froid / P_élec. Le SCOP est le COP saisonnier moyen.",tags:["COP","EER","PAC","Performance"]},
  {id:"fed_pac3",prompt:"Dans le cycle thermodynamique à compression d'une PAC, l'ordre des 4 étapes est :",choices:["Compression → Évaporation → Condensation → Détente","Évaporation → Compression → Condensation → Détente","Condensation → Détente → Évaporation → Compression","Détente → Condensation → Compression → Évaporation"],answer:1,diff:2,explication:"Le cycle frigorifique : (1) Évaporation : fluide absorbe la chaleur de la source froide à basse pression → vaporisation. (2) Compression : compresseur élève la pression et la température du vapeur. (3) Condensation : fluide restitue la chaleur à la source chaude → liquéfaction. (4) Détente : détendeur abaisse la pression pour revenir à l'état initial.",tags:["Cycle frigorifique","Compression","Évaporation","Condensation"]},
  {id:"fed_pac4",prompt:"Le fluide frigorigène R32 remplace progressivement le R410A car :",choices:["Il est moins cher à fabriquer","Son PRG (Potentiel de Réchauffement Global) est de 675 contre 2088 pour le R410A","Il est plus stable chimiquement","Il nécessite une pression plus basse"],answer:1,diff:2,explication:"Le R32 (HFC) a un PRG de 675, bien inférieur aux 2088 du R410A. Le règlement F-gas UE 517/2014 impose des restrictions progressives des fluides à fort PRG. Autres fluides bas-PRG : R290 (propane, PRG=3), R744 (CO₂, PRG=1). Le R22 est déjà interdit depuis 2015.",tags:["Fluides frigorigènes","R32","R410A","PRG","F-gas"]},
  {id:"fed_pac5",prompt:"Le règlement européen F-gas (UE 517/2014 révisé 2024) impose notamment :",choices:["L'utilisation exclusive du R22","Des interdictions progressives des fluides HFC à fort PRG et l'obligation de récupérer les fluides frigorigènes","La suppression de toutes les PAC d'ici 2025","L'utilisation obligatoire du CO₂ comme fluide frigorigène"],answer:1,diff:2,explication:"Le règlement F-gas impose : des quotas puis interdictions progressives des HFC à fort PRG (GWP), la récupération obligatoire des fluides frigorigènes lors des interventions, des certifications pour les techniciens manipulant les fluides. Le R22 est interdit, le R410A est en cours de remplacement.",tags:["F-gas","Réglementation","HFC","PRG","Environnement"]},
  {id:"fed_pac6",prompt:"Une PAC air/air a un COP qui diminue quand la température extérieure baisse parce que :",choices:["Le compresseur consomme plus d'électricité à basse température","L'écart de température entre source froide et source chaude augmente, rendant le cycle moins efficace","Le fluide frigorigène gèle","Les ventilateurs consomment plus d'énergie"],answer:1,diff:2,explication:"Plus l'écart de température ΔT entre source froide (air extérieur) et source chaude (logement) est grand, plus le cycle thermodynamique est pénalisé — le compresseur doit travailler davantage pour élever le niveau d'énergie. Avec T_ext = -5°C et T_intérieur = 20°C, le COP chute. La PAC air/air est également réversible (climatisation en été).",tags:["PAC air/air","COP","Température","Réversible"]},
  {id:"fed_pac7",prompt:"Pour une PAC air/eau couplée à un plancher chauffant, la température d'eau en circuit est typiquement de :",choices:["75-90°C (haute température, comme une chaudière)","35-45°C (basse température, compatible avec un COP élevé)","10-15°C (eau froide)","55-65°C (température intermédiaire)"],answer:1,diff:2,explication:"Le plancher chauffant fonctionne en basse température (35-45°C), ce qui est idéal pour les PAC air/eau car l'écart avec la source froide est réduit → COP élevé (3-4). Les radiateurs classiques fonctionnent à 55-75°C (moins favorable). La RE 2020 encourage les systèmes basse température.",tags:["PAC air/eau","Plancher chauffant","Basse température","COP"]},
  {id:"fed_pac8",prompt:"La PAC géothermique eau/eau capte les calories du sol grâce à :",choices:["Des panneaux solaires thermiques","Des capteurs enterrés (horizontaux en nappe surfacique ou sondes géothermiques verticales)","Des puits artésiens profonds","Des échangeurs dans la ventilation"],answer:1,diff:1,explication:"La PAC géothermique exploite la stabilité thermique du sol (12-15°C toute l'année). Les capteurs horizontaux sont enterrés à 0.8-1.2 m de profondeur (grande surface nécessaire). Les sondes verticales (50-150 m) nécessitent moins de surface mais un forage. Le COP est très élevé (4-5) grâce à la source froide stable.",tags:["PAC géothermique","Capteurs enterrés","Sol","Sonde géothermique"]},
  {id:"fed_pac9",prompt:"Le SCOP (Seasonal COP) se distingue du COP instantané car :",choices:["Il mesure uniquement la performance en été","Il est le COP moyen calculé sur l'ensemble de la saison de chauffe, prenant en compte les températures variables","Il ne tient pas compte de la consommation électrique","Il est toujours supérieur au COP instantané"],answer:1,diff:2,explication:"Le SCOP intègre les variations de température extérieure sur toute la saison (températures douces → COP élevé, températures froides → COP bas). Il est donc plus représentatif de la performance réelle que le COP à une température donnée. La RE 2020 impose un SCOP ≥ 2.5.",tags:["SCOP","COP saisonnier","RE 2020","Performance"]},
  {id:"fed_pac10",prompt:"Un détendeur électronique (par rapport à un détendeur thermostatique) permet :",choices:["D'augmenter la pression du fluide frigorigène","Une régulation plus précise du débit de fluide entre condenseur et évaporateur, améliorant le rendement en charge partielle","De supprimer le besoin de fluide frigorigène","De contrôler la vitesse du compresseur"],answer:1,diff:3,explication:"Le détendeur régule le débit de fluide frigorigène entre condenseur et évaporateur (laminage de pression). Le détendeur électronique (DX ou EEV) est piloté électroniquement avec précision, adapté aux charges partielles. Il améliore le COP sur l'ensemble de la plage de fonctionnement comparé au thermostatique.",tags:["Détendeur","Électronique","Régulation","Rendement partiel"]},
  {id:"fed_pac11",prompt:"Un chiller (groupe de production d'eau glacée) produit typiquement de l'eau à :",choices:["0°C pour congélation","7/12°C pour la climatisation tertiaire (bâtiments de bureaux, hôpitaux)","35-45°C pour le chauffage","55-65°C pour l'eau chaude sanitaire"],answer:1,diff:2,explication:"Le chiller est une PAC en mode froid produisant de l'eau glacée (7°C départ / 12°C retour en standard) pour alimenter des ventilo-convecteurs ou centrales de traitement d'air en tertiaire. Il peut être à condensation à air (plus simple) ou avec tour aéroréfrigérante (meilleur rendement).",tags:["Chiller","Eau glacée","Climatisation","Tertiaire"]},
  {id:"fed_pac12",prompt:"Pour une PAC avec COP = 4 consommant P_élec = 3 kW, la puissance thermique fournie et la puissance captée sur la source froide sont :",choices:["P_chaud = 3 kW, P_froid = 0 kW","P_chaud = 12 kW, P_froid = 9 kW","P_chaud = 4 kW, P_froid = 1 kW","P_chaud = 7 kW, P_froid = 3 kW"],answer:1,diff:2,explication:"Bilan thermique PAC : P_chaud = COP × P_élec = 4 × 3 = 12 kW. P_froid (énergie captée source froide) = P_chaud - P_élec = 12 - 3 = 9 kW. Vérification : P_chaud = P_froid + P_élec → 12 = 9 + 3. C'est la conservation de l'énergie appliquée au cycle frigorifique.",tags:["Bilan thermique","COP","Calcul","PAC"]},
];

export const QB_FED_ELECTRO2 = [
  {id:"fed_el1",prompt:"Le moteur asynchrone triphasé à cage d'écureuil est le plus utilisé en industrie car :",choices:["Il consomme moins d'électricité qu'un moteur à courant continu","Il est robuste, simple (pas de contact glissant), peu onéreux, et facile à alimenter depuis le réseau triphasé","Il tourne exactement à la vitesse de synchronisme","Il ne nécessite aucun démarreur"],answer:1,diff:1,explication:"Le moteur asynchrone triphasé cage d'écureuil (rotor en court-circuit) est universel en industrie/tertiaire : robustesse, absence de balais, faible maintenance. Le glissement s = (Ns-N)/Ns (quelques %). Le courant d'appel au démarrage direct = 5-8 × In, ce qui peut perturber le réseau.",tags:["Moteur asynchrone","Cage d'écureuil","Démarrage","Triphasé"]},
  {id:"fed_el2",prompt:"Un variateur de fréquence (VFD) contrôle la vitesse d'un moteur asynchrone en :",choices:["Modifiant la tension d'alimentation uniquement","Convertissant le courant AC en DC (redresseur), puis en AC de fréquence et tension variables (onduleur)","Modifiant la résistance du stator","Changeant le nombre de pôles du moteur"],answer:1,diff:2,explication:"Le VFD comprend : (1) Redresseur : AC réseau → DC. (2) Filtre capacitif (bus DC). (3) Onduleur IGBT : DC → AC fréquence/tension variables. Le rapport V/f constant maintient le flux magnétique. Génère des harmoniques → nécessite différentiels de type A ou B.",tags:["Variateur de fréquence","VFD","Onduleur","Moteur"]},
  {id:"fed_el3",prompt:"La loi des quadratiques (loi cubique) pour pompes centrifuges et ventilateurs stipule que :",choices:["La puissance est proportionnelle à la vitesse","La puissance absorbée est proportionnelle au CUBE de la vitesse (P ∝ N³)","Le débit est proportionnel au carré de la vitesse","La puissance est indépendante de la vitesse"],answer:1,diff:2,explication:"Lois d'affinité : Q ∝ N, ΔP ∝ N², P ∝ N³. Réduire la vitesse de 20% (N' = 0.8N) → P' = (0.8)³ × P = 0.512P → économie de 48.8% ! C'est pourquoi les variateurs de fréquence sur pompes et ventilateurs CVC sont si efficaces énergétiquement.",tags:["Loi cubique","Ventilateurs","Pompes","Économie d'énergie"]},
  {id:"fed_el4",prompt:"La norme NF C 15-100 régit :",choices:["Les installations électriques haute tension (HTA)","Les installations électriques basse tension en France (conception, réalisation, vérification des locaux résidentiels et tertiaires)","Uniquement les réseaux de communication","Les équipements de protection individuelle électrique"],answer:1,diff:1,explication:"NF C 15-100 : norme française pour les installations électriques BT (≤ 1000 V AC). Elle définit les règles de conception : sections de câbles (tableau B52), types de protections, nombre de prises et circuits, tableaux, liaisons équipotentielles, vérification initiale.",tags:["NF C 15-100","Norme","Installation électrique","BT"]},
  {id:"fed_el5",prompt:"Le schéma de liaison à la terre (SLT) IT se distingue par :",choices:["Le neutre directement mis à la terre","Le neutre isolé de la terre (ou lié par une impédance), ce qui rend la première faute non dangereuse","La séparation du neutre N et du PE","L'absence de disjoncteur différentiel"],answer:1,diff:3,explication:"IT (Isolé Terre) : neutre isolé ou impédant. 1ère faute → pas de courant de défaut → pas de danger immédiat, mais alarme par contrôleur permanent d'isolement (CPI). Utilisé en milieux où la continuité de service est critique (hôpitaux, industrie). TT = neutre direct à la terre (résidentiel France). TN-S = neutre direct + N et PE séparés (tertiaire).",tags:["Schéma TT","TN-S","IT","SLT","Neutre"]},
  {id:"fed_el6",prompt:"Un disjoncteur différentiel de type B (vs type A) est requis pour :",choices:["Les installations résidentielles classiques","Les véhicules électriques et systèmes avec onduleurs pouvant produire des courants de fuite continus","Les éclairages fluorescents","Toutes les installations industrielles"],answer:1,diff:3,explication:"Type AC : courants sinusoïdaux seuls. Type A : + pulsatoires (appareils avec alimentations à découpage). Type B : + courants continus (VE, photovoltaïque, certains variateurs). Le seuil 30 mA protège les personnes (contact indirect), 300 mA protège contre l'incendie.",tags:["Différentiel","Type B","Véhicule électrique","Protection"]},
  {id:"fed_el7",prompt:"La puissance réactive Q (en kVAR) est consommée par :",choices:["Les résistances de chauffage électrique","Les bobines et moteurs électriques (charges inductives) qui créent un champ magnétique","Les ampoules à incandescence","Les alimentations DC des équipements informatiques"],answer:1,diff:2,explication:"P (kW) = puissance active (travail utile). Q (kVAR) = puissance réactive, échangée sans être consommée, nécessaire aux champs magnétiques (moteurs, transformateurs). S (kVA) = √(P²+Q²). cos φ = P/S. Un cos φ bas signifie beaucoup de Q → courant total élevé → pertes Joule → câbles surdimensionnés.",tags:["Puissance réactive","Q","cos φ","Inductif"]},
  {id:"fed_el8",prompt:"La compensation d'énergie réactive par batterie de condensateurs permet de :",choices:["Supprimer les disjoncteurs différentiels","Améliorer le facteur de puissance cos φ → réduire l'intensité dans les câbles et éviter les pénalités tarifaires (cos φ < 0.93)","Stocker l'énergie pour les coupures secteur","Réduire la tension d'alimentation"],answer:1,diff:2,explication:"Les condensateurs injectent de la puissance réactive capacitive Q_C qui compense la Q inductive des moteurs. cos φ → 1 → S se rapproche de P → même puissance utile mais courant I plus faible → pertes Joule ∝ I²R réduites → économies sur facture (pénalité ENEDIS si cos φ < 0.93).",tags:["Compensation réactive","Condensateurs","cos φ","Économie d'énergie"]},
  {id:"fed_el9",prompt:"Le TGBT (Tableau Général Basse Tension) est alimenté directement par :",choices:["Le réseau HTA sans transformation","Le transformateur HTA/BT (ou directement depuis le réseau BT pour les petits bâtiments)","Un groupe électrogène en fonctionnement normal","Les panneaux photovoltaïques"],answer:1,diff:1,explication:"TGBT : armoire principale BT alimentée depuis le transformateur HTA/BT (poste de transformation). Contient : disjoncteur général (protection principale), jeux de barres (distribution), départs divisionnaires (disjoncteurs calibrés), compteurs d'énergie. Protège l'ensemble de l'installation.",tags:["TGBT","Distribution","Transformateur","BT"]},
  {id:"fed_el10",prompt:"Le sous-comptage d'énergie électrique par usage (éclairage, CVC, informatique) est la première étape d'une démarche :",choices:["RE 2020","ISO 50001 (Système de Management de l'Énergie)","NF C 15-100","BIM niveau LOD 400"],answer:1,diff:2,explication:"ISO 50001 : norme de management de l'énergie. Première étape = mesurer les consommations par usage (sous-comptage). Identification des gisements d'économies. Compteurs communicants Modbus ou Linky. Dashboard énergie (kWh/m²/an). Indicateurs de performance énergétique (IPE).",tags:["Comptage d'énergie","ISO 50001","Sous-comptage","Management énergie"]},
  {id:"fed_el11",prompt:"La tarification électrique Tempo (EDF) présente des jours rouges pendant lesquels :",choices:["L'électricité est gratuite","Le kWh est très cher (heures de pointe nationale) — incitation au délestage et au stockage","La puissance souscrite est réduite automatiquement","Le réseau est coupé pour maintenance"],answer:1,diff:2,explication:"Tarif Tempo : 300 jours bleus (bas coût), 43 jours blancs (coût moyen), 22 jours rouges (coût très élevé, x10 par rapport au bleu en HP). Les jours rouges correspondent aux pics de consommation nationaux (vague de froid). Intérêt : délester les gros consommateurs (CVC) en jours rouges → économies importantes.",tags:["Tarification","Tempo","HP/HC","Optimisation tarifaire"]},
  {id:"fed_el12",prompt:"Un luminaire LED avec driver courant constant alimenté en DALI permet :",choices:["Uniquement l'allumage et l'extinction","Un contrôle numérique individuel : gradation 0-100%, adressage unique, scènes préprogrammées, télémaintenance"],answer:1,diff:2,explication:"DALI (Digital Addressable Lighting Interface) : protocole numérique 2 fils, adresse individuelle par luminaire. Driver courant constant : maintient l'intensité LED constante (pas de scintillement). Fonctions : gradation précise, groupes, scènes, détection défauts, intégration GTB/KNX. LED = 80-120 lm/W vs halogène 15 lm/W.",tags:["DALI","LED","Driver","Éclairage","GTB"]},
];

export const QB_FED_GTB2 = [
  {id:"fed_gtb1",prompt:"Le protocole BACnet/IP (ASHRAE 135) se distingue du BACnet MS/TP par :",choices:["BACnet/IP fonctionne uniquement en Wi-Fi","BACnet/IP fonctionne sur TCP/IP (couche 3, réseau Ethernet standard) tandis que MS/TP fonctionne sur RS485 (couche 2, bus série)","BACnet/IP est plus lent","BACnet MS/TP est le seul standard reconnu"],answer:1,diff:2,explication:"BACnet (Building Automation and Control Network) est le standard ASHRAE 135 pour les bâtiments tertiaires. BACnet/IP : couche réseau (Ethernet/IP), longues distances, intégration réseau informatique. MS/TP : bus RS485 2 fils, jusqu'à 127 maîtres, économique. Objets BACnet : Analog Input, Binary Output, Schedule, Trend Log.",tags:["BACnet","BACnet/IP","MS/TP","RS485","Protocoles GTB"]},
  {id:"fed_gtb2",prompt:"Dans Modbus RTU, les 'holding registers' (registres 4xxxx) sont :",choices:["En lecture seule (uniquement mesures)","En lecture et en écriture (consignes, paramètres configurables par le maître)","Réservés aux alarmes","Utilisés uniquement pour le comptage d'énergie"],answer:1,diff:2,explication:"Modbus RTU (RS485) : protocole maître-esclave. Registres : (1) Input registers (3xxxx) = lecture seule (mesures, capteurs). (2) Holding registers (4xxxx) = lecture/écriture (consignes, paramètres). (3) Coils (0xxxx) = sorties TOR R/W. (4) Discrete inputs (1xxxx) = entrées TOR lecture seule. Adresses 1 à 65535.",tags:["Modbus","Holding registers","RTU","Registres"]},
  {id:"fed_gtb3",prompt:"Dans KNX, l'adresse individuelle '1.2.5' signifie :",choices:["Groupe 1, sous-groupe 2, instance 5 (adresse fonctionnelle)","Zone 1, ligne 2, appareil 5 (localisation physique de l'appareil sur le bus)","Bâtiment 1, étage 2, local 5","Version 1.2 du firmware, appareil 5"],answer:1,diff:2,explication:"KNX adresse individuelle = zone.ligne.appareil (ex: 1.2.5 = zone 1, ligne 2, appareil 5). Cette adresse identifie physiquement l'emplacement. L'adresse de groupe (ex: 0/1/1) relie fonctionnellement des émetteurs et récepteurs (bouton → actionneur de lumière). Programmation via ETS (Engineering Tool Software).",tags:["KNX","Adresse individuelle","Adresse de groupe","ETS"]},
  {id:"fed_gtb4",prompt:"Les langages de programmation des automates (IEC 61131-3) incluent le Ladder (LD), qui est :",choices:["Un langage texte structuré similaire au Pascal","Une représentation graphique en échelle (contacts et bobines) inspirée des schémas électriques à relais","Un langage de blocs fonctionnels","Un diagramme d'états séquentiels"],answer:1,diff:2,explication:"IEC 61131-3 définit 5 langages API : Ladder (LD) = schémas à contacts électriques ; FBD (Function Block Diagram) = blocs fonctionnels ; ST (Structured Text) = texte Pascal-like ; IL (Instruction List) = assembleur ; SFC (Sequential Function Chart) = Grafcet pour processus séquentiels. Le cycle automate : lecture E/S → traitement → écriture sorties.",tags:["API","PLC","Ladder","IEC 61131","Automate"]},
  {id:"fed_gtb5",prompt:"La GTC (Gestion Technique Centralisée) d'un bâtiment permet notamment de :",choices:["Uniquement commander l'éclairage","Superviser en temps réel toutes les installations (synoptiques, alarmes, historiques, courbes de tendance) via OPC-UA","Réaliser les travaux de maintenance","Programmer les accès des occupants"],answer:1,diff:1,explication:"La GTC offre : synoptiques animés (vue temps réel), gestion des alarmes (avec acquittement), historique des données (trends), rapports énergétiques. Le standard OPC-UA (Unified Architecture) permet l'interopérabilité entre automates, superviseurs et systèmes IoT. Protocoles sous-jacents : Modbus, BACnet, KNX.",tags:["GTC","Supervision","OPC-UA","Alarmes","Synoptiques"]},
  {id:"fed_gtb6",prompt:"Une régulation tout-ou-rien (TOR) avec hystérésis commande une chaudière avec Tconsigne = 20°C et hystérésis ±1°C. La chaudière s'allume à :",choices:["20°C exactement (pas d'hystérésis)","19°C (chaudière ON) et s'éteint à 21°C (chaudière OFF)","18°C et s'éteint à 22°C","21°C et s'éteint à 19°C"],answer:1,diff:1,explication:"TOR avec hystérésis : bande morte autour de la consigne évitant un fonctionnement marche/arrêt trop fréquent (usure). Avec ±1°C : chaudière ON quand T < 19°C, OFF quand T > 21°C. L'hystérésis est un compromis entre confort (bande étroite) et durée de vie équipement (bande large). Inconvénient : oscillations autour de la consigne.",tags:["Régulation TOR","Hystérésis","Thermostat","Chaudière"]},
  {id:"fed_gtb7",prompt:"Un correcteur proportionnel (P) présente une erreur statique résiduelle car :",choices:["Il oscille sans jamais se stabiliser","La commande u = Kp × erreur : quand l'erreur est nulle, la commande est nulle — or il faut une commande non nulle pour maintenir l'équilibre, donc une erreur permanente subsiste","Il n'est pas adapté aux systèmes lents","Il fait osciller le système"],answer:1,diff:3,explication:"Correcteur P : u = Kp × e(t). En régime permanent, pour maintenir une vanne à 30% d'ouverture, il faut u = 30% ≠ 0, donc e ≠ 0 → écart permanent de consigne (bande proportionnelle). L'action intégrale (I) élimine cette erreur statique en accumulant l'erreur dans le temps : u_I = Ki × ∫e dt.",tags:["Régulation P","Erreur statique","Proportionnel","Automatique"]},
  {id:"fed_gtb8",prompt:"Dans un correcteur PID, l'action dérivée (D) permet de :",choices:["Annuler l'erreur statique résiduelle","Anticiper les variations rapides de la mesure (réagit à la vitesse de variation de l'erreur de/dt), améliorant la stabilité et la rapidité","Augmenter le gain statique","Compenser les perturbations constantes"],answer:1,diff:2,explication:"PID = P + I + D. Action D = Kd × de/dt : réagit à la vitesse de changement de l'erreur. Si la mesure monte rapidement vers la consigne, D anticipe et réduit la commande → moins de dépassement. Utilité : systèmes avec inertie (grandes pièces, grand volume d'eau). Inconvénient : amplifie le bruit de mesure → filtrage nécessaire.",tags:["PID","Action dérivée","Anticipation","Stabilité"]},
  {id:"fed_gtb9",prompt:"Un capteur PT1000 en GTB mesure :",choices:["La pression différentielle","La température par variation de résistance électrique (résistance = 1000 Ω à 0°C, variation ~3.85 Ω/°C)","L'humidité relative","Le débit volumique"],answer:1,diff:2,explication:"PT1000 (et PT100) : sondes à résistance de platine (RTD). PT1000 : R = 1000 Ω à 0°C (PT100 = 100 Ω à 0°C). Variation linéaire : ~3.85 Ω/°C. Signal analogique 4 fils (précision) ou 2 fils. Avantages : précision, stabilité, large plage. Autres capteurs GTB : 4-20 mA (température, pression, CO₂ NDIR), 0-10V, contacts TOR.",tags:["PT1000","Capteur température","RTD","Analogique"]},
  {id:"fed_gtb10",prompt:"Un compteur d'eau avec sortie impulsion fournit 1 impulsion par litre. Pour mesurer un débit de 2 m³/h, la fréquence d'impulsions attendue est :",choices:["2 impulsions/min","33.3 impulsions/min (2000 L/h ÷ 60 min/h)","120 impulsions/min","1 impulsion/seconde"],answer:1,diff:2,explication:"2 m³/h = 2000 L/h = 2000 L/60 min = 33.33 L/min → 33.33 impulsions/min. La GTB compte les impulsions par unité de temps pour calculer le débit, et cumule les impulsions pour le volume total. Compteurs d'énergie thermique (calorie) : similaire + mesure ΔT. Compteurs électriques communicants : Modbus.",tags:["Compteur d'eau","Impulsion","Débit","Calcul GTB"]},
  {id:"fed_gtb11",prompt:"Le câblage structuré VDI en topologie étoile impose une distance maximale entre la prise murale et le panneau de brassage de :",choices:["50 m","90 m pour le câble de distribution (+ 10 m de cordons = 100 m total)","150 m","200 m avec câble Cat 7"],answer:1,diff:1,explication:"Standard câblage structuré (ISO 11801 / EN 50173) : distance max poste de travail = 100 m total. Décomposé en : 90 m câble horizontal (de la prise murale au panneau de brassage) + 5 m cordon côté baie + 5 m cordon côté utilisateur. Cat 6A (500 MHz) supporte 10 Gbit/s sur 100 m. Topologie étoile centralisée sur baie 19\".",tags:["VDI","Câblage structuré","Cat 6A","Baie de brassage","100m"]},
  {id:"fed_gtb12",prompt:"LoRaWAN est utilisé en smart building pour :",choices:["Le câblage des capteurs dans les armoires électriques","Des capteurs sans-fil à longue portée et très faible consommation (T°, CO₂, occupation), communiquant via des passerelles vers des plateformes cloud (MQTT/REST)","La communication vidéosurveillance","Le contrôle des variateurs de fréquence"],answer:1,diff:2,explication:"LoRaWAN (Long Range Wide Area Network) : réseau sans-fil IoT, portée 1-15 km, débit faible (250 bps à 50 kbps), batterie 5-10 ans. Idéal pour capteurs dispersés dans un bâtiment ou campus. Alternative : Zigbee (courte portée, maillé). Plateformes cloud : The Things Network, AWS IoT. Protocoles applicatifs : MQTT, REST API.",tags:["LoRaWAN","IoT","Smart building","Capteurs sans-fil","MQTT"]},
];

// ─── BANQUE QB_FED_THERMIQUE_BAT ───
export const QB_FED_THERMIQUE_BAT = [
  {id:"fed_tb1",prompt:"Les déperditions totales d'un bâtiment (ΦT) sont la somme de :",choices:["Uniquement les pertes par les murs extérieurs","Les déperditions par transmission (parois, ponts thermiques) + par renouvellement d'air (ventilation + infiltrations)","Les déperditions par les fenêtres uniquement","Les déperditions par convection naturelle uniquement"],answer:1,diff:1,explication:"ΦT = ΦT_transmission + ΦT_renouvellement d'air. Transmission : parois (murs, toit, plancher bas, fenêtres) + ponts thermiques linéiques (ψ × L). Renouvellement d'air : débit × ρair × Cp_air × ΔT. La méthode de calcul est définie par la méthode Th-BCE (RT 2012/RE 2020).",tags:["Thermique bâtiment","Déperditions","Transmission","Ventilation"]},
  {id:"fed_tb2",prompt:"Un pont thermique linéique (ψ en W/m·K) apparaît principalement :",choices:["Au centre d'un mur bien isolé","Aux liaisons entre parois (plancher/mur, refend/façade, acrotère/toit) où l'isolant est interrompu ou réduit","Dans les vitrages à faible émissivité","Dans les ventilateurs de VMC"],answer:1,diff:2,explication:"Ponts thermiques : discontinuités de l'isolation aux jonctions (angles, refends, menuiseries). ψ (W/m·K) = coefficient linéique du pont thermique. Déperdition : ΦPT = ψ × L × ΔT. L'ITE (isolation thermique par l'extérieur) supprime la majorité des ponts thermiques structurels.",tags:["Pont thermique","ψ linéique","Isolation","ITE"]},
  {id:"fed_tb3",prompt:"Le Bbio (Besoin Bioclimatique) de la RE 2020 mesure :",choices:["La consommation d'énergie primaire annuelle du bâtiment","Les besoins de chauffage, refroidissement et éclairage intrinsèques du bâtiment (indépendamment des systèmes)","L'empreinte carbone du bâtiment sur 50 ans","Le débit de ventilation minimum réglementaire"],answer:1,diff:2,explication:"Bbio (exprimé en Bbio-points) = indicateur bioclimatique RE 2020 évaluant les besoins de chauffage + refroidissement + éclairage du bâtiment seul (enveloppe, orientation, compacité, surfaces vitrées). Il encourage l'architecture bioclimatique avant même les systèmes techniques. Bbio_max à respecter.",tags:["RE 2020","Bbio","Bioclimatique","Enveloppe"]},
  {id:"fed_tb4",prompt:"L'inertie thermique d'un bâtiment à forte masse (béton, pierre) permet :",choices:["D'augmenter les déperditions hivernales","De stocker la chaleur/fraîcheur et d'amortir les variations de température extérieure (déphasage thermique) → confort d'été amélioré","D'accélérer le chauffage par effet Joule","De réduire la ventilation nécessaire"],answer:1,diff:2,explication:"Inertie thermique : capacité d'un matériau à stocker et restituer la chaleur. Caractérisée par l'effusivité (b = √(λρCp)) et la diffusivité (a = λ/ρCp). Fort déphasage (> 10h) : le pic de chaleur extérieur arrive très atténué la nuit. RE 2020 valorise l'inertie pour le confort d'été (IC_été).",tags:["Inertie thermique","Déphasage","Confort d'été","RE 2020"]},
  {id:"fed_tb5",prompt:"La valeur maximale du coefficient U pour un vitrage neuf en RE 2020 (maison individuelle) est de :",choices:["0.80 W/m²·K","1.40 W/m²·K pour les vitrages neufs (double vitrage à faible émissivité)","2.50 W/m²·K (simple vitrage)","0.50 W/m²·K (standard triple vitrage)"],answer:1,diff:2,explication:"RE 2020 : Uw (vitrage + cadre) ≤ 1.40 W/m²·K pour les menuiseries. Triple vitrage : Uw ≈ 0.7 W/m²·K. Simple vitrage : Uw ≈ 5.8 W/m²·K. Le facteur solaire g du vitrage influe aussi sur le bilan thermique (apports solaires passifs en hiver, protection en été).",tags:["Coefficient U","Vitrage","RE 2020","Double vitrage"]},
  {id:"fed_tb6",prompt:"Le flux thermique à travers une paroi multicouche (mur de 20 cm béton λ=1.8 + 12 cm laine de roche λ=0.04) avec ΔT = 15°C est de :",choices:["Environ 5 W/m²","Environ 4.1 W/m² (Rtot = 0.111 + 3 = 3.111 m²K/W → U = 0.321 → Φ = 0.321 × 15 ≈ 4.8 W/m²)","Environ 50 W/m²","Environ 0.5 W/m²"],answer:1,diff:3,explication:"Calcul : R_béton = 0.20/1.8 = 0.111 m²K/W. R_LDR = 0.12/0.04 = 3.0 m²K/W. Rtot = 0.111 + 3.0 = 3.111 m²K/W (sans les résistances superficielles ≈ 0.17). U ≈ 1/3.28 ≈ 0.305 W/m²K. Φ = U × ΔT ≈ 0.305 × 15 ≈ 4.6 W/m². Sans l'isolant : Φ = (1.8/0.20) × 15 = 135 W/m² → l'isolation divise le flux par ~30.",tags:["Calcul thermique","Flux","Résistance thermique","Application numérique"]},
  {id:"fed_tb7",prompt:"L'étiquette Energie DPE est passée à opposable depuis 2021. Une 'passoire thermique' est classée :",choices:["A ou B","F ou G (> 330 kWh/m²/an en énergie primaire ou > 70 kg CO₂/m²/an)","C ou D","E uniquement"],answer:1,diff:1,explication:"DPE obligatoire et opposable depuis 01/07/2021 (réforme). Classes : A (< 70), B (70-110), C (111-180), D (181-250), E (251-330), F (331-420), G (> 420 kWh/m²/an). G et F = passoires thermiques. Interdiction progressive de location : G en 2025, F en 2028, E en 2034.",tags:["DPE","Passoire thermique","Réglementation","Logement"]},
  {id:"fed_tb8",prompt:"Le ratio entre les apports de chaleur internes et solaires gratuits (apports/pertes) dans le bilan thermique d'un bâtiment influence :",choices:["Uniquement la consommation d'eau chaude sanitaire","Le besoin réel de chauffage (besoins = déperditions - apports gratuits) → réduit la puissance de chauffage nécessaire","Le niveau sonore de la VMC","La résistance mécanique des parois"],answer:1,diff:2,explication:"Bilan thermique : Besoins de chauffage = Déperditions - Apports gratuits (solaires + internes). Apports solaires (orientations S/SE/SO, facteur g vitrage), apports internes (occupants ≈ 80 W, électroménager, éclairage). Un bâtiment bioclimatique maximise ces apports → réduit la consommation de chauffage.",tags:["Bilan thermique","Apports solaires","Apports internes","Bioclimatique"]},
  {id:"fed_tb9",prompt:"La méthode des 5 usages réglementaires de la RE 2020 (pour le calcul Cep) comprend :",choices:["Chauffage, ECS, éclairage, VMC, domotique","Chauffage, refroidissement, eau chaude sanitaire, éclairage, auxiliaires (pompes, ventilateurs)","Chauffage, PAC, photovoltaïque, VMC, cuisine","Chauffage, isolation, vitrage, plancher, toiture"],answer:1,diff:2,explication:"RE 2020 (5 usages réglementaires) : (1) Chauffage, (2) Refroidissement, (3) ECS (eau chaude sanitaire), (4) Éclairage, (5) Auxiliaires (ventilateurs, pompes de circulation, régulation). Cep (consommation d'énergie primaire) en kWh_ep/m²/an. Coefficients d'énergie primaire : élec = 2.3, gaz = 1.0, bois = 0.6.",tags:["RE 2020","5 usages","Cep","Énergie primaire"]},
  {id:"fed_tb10",prompt:"Un label BEPOS (Bâtiment à Énergie POSitive) signifie que :",choices:["Le bâtiment ne consomme pas d'eau chaude sanitaire","La production d'énergie renouvelable sur site est supérieure à la consommation des 5 usages réglementaires","Le bâtiment est entièrement autonome en eau","Il n'y a aucune émission de CO₂ pendant la construction"],answer:1,diff:2,explication:"BEPOS (ou E+C- niveau E3-E4) : production locale d'EnR (PV, éolien, géothermie) > consommation réglementaire. Précurseur de la RE 2020. Label E+C- : 4 niveaux d'énergie (E1→E4) + 2 niveaux carbone (C1, C2). BEPOS = E3 ou E4 + bonne isolation + production EnR.",tags:["BEPOS","Énergie positive","E+C-","EnR"]},
  {id:"fed_tb11",prompt:"L'efficacité d'un isolant est principalement caractérisée par :",choices:["Sa densité (kg/m³) uniquement","Sa conductivité thermique λ (W/m·K) : plus λ est faible, plus l'isolant est performant","Sa couleur et son aspect de surface","Sa résistance au feu uniquement"],answer:1,diff:1,explication:"λ (W/m·K) = conductivité thermique. Valeurs typiques : laine de verre λ ≈ 0.035-0.04, laine de roche λ ≈ 0.033-0.040, PSE (polystyrène expansé) λ ≈ 0.030-0.038, polyuréthane λ ≈ 0.022-0.025. Les matériaux naturels (ouate de cellulose λ ≈ 0.038, liège λ ≈ 0.040) ont des performances comparables.",tags:["Conductivité thermique","λ","Isolant","Matériaux"]},
  {id:"fed_tb12",prompt:"Le test de perméabilité à l'air (blower door test) d'un bâtiment mesure :",choices:["Le débit de ventilation de la VMC en fonctionnement normal","Le débit de fuite d'air à 4 Pa et à 50 Pa sous-pression pour évaluer l'étanchéité à l'air de l'enveloppe","La résistance thermique des murs","La puissance consommée par le système de chauffage"],answer:1,diff:2,explication:"Test de perméabilité (n50 en vol/h ou Q4Pa_surf en m³/h.m²) : mesure de l'étanchéité à l'air de l'enveloppe. BBC Effinergie : Q4Pa ≤ 0.60 m³/h.m² (maison) ou 1.0 (appartement). RE 2020 : exigence renforcée. Infiltrations = déperditions non contrôlées + inconfort. Joints d'étanchéité (ITI+pare-vapeur).",tags:["Perméabilité à l'air","Blower door","Étanchéité","BBC"]},
];

// ─── BANQUE QB_FED_AERO_VENTIL ───
export const QB_FED_AERO_VENTIL = [
  {id:"fed_av1",prompt:"La VMC simple flux hygroréglable de type B (SF-B) module les débits d'air en fonction de :",choices:["La température extérieure uniquement","L'humidité relative de l'air dans les pièces (bouches hygrorégables sensibles à l'HR)","La consommation électrique des occupants","Le taux de CO₂ ambiant"],answer:1,diff:2,explication:"VMC SF-B (hygroréglable type B) : extraction variable dans les pièces humides (bouches d'extraction hygrorégables) ET entrées d'air modulées dans les pièces sèches. Plus économique que la DF (double flux) mais moins efficace énergétiquement. SF-A : débits fixes. Réglementation : arrêté du 24 mars 1982 modifié.",tags:["VMC","Simple flux","Hygroréglable","Ventilation"]},
  {id:"fed_av2",prompt:"Les débits réglementaires minimaux d'extraction d'air en VMC pour une cuisine sont définis par :",choices:["Le DTU 45.11 uniquement","L'arrêté du 24 mars 1982 (modifié) et le DTU 68.3 : cuisine = 45 m³/h minimum en débit maximal (hygro-B) ou 90 m³/h (débit fixe)","La RE 2020 uniquement","Le fabricant de la VMC"],answer:1,diff:2,explication:"DTU 68.3 (VMC) et arrêté du 24 mars 1982 : débits réglementaires selon le nombre de pièces principales. Cuisine : 45-90 m³/h (SF-A fixe). Salle d'eau : 15-30 m³/h. WC : 15 m³/h. Entrées d'air dans pièces de vie (séjour, chambres). Principe : tirage de l'air des pièces sèches vers les pièces humides.",tags:["VMC","Débit d'air","DTU 68.3","Réglementation ventilation"]},
  {id:"fed_av3",prompt:"L'efficacité thermique d'un échangeur à flux croisés d'une VMC double flux est typiquement de :",choices:["20-30% (faible performance)","75-95% selon la qualité de l'échangeur (récupérateur à plaques ou rotatif)","50% uniquement (standard réglementaire)","100% (récupération totale de la chaleur)"],answer:1,diff:2,explication:"VMC double flux : échangeur à contre-courant ou flux croisés (ou rotatif enthalpique). Récupération 75-95% de la chaleur de l'air extrait. Exemple : T_ext = 0°C, T_int = 20°C, rendement 80% → T_air neuf préchauffé = 16°C. BBC et RE 2020 imposent une récupération ≥ 75% pour le tertiaire.",tags:["VMC double flux","Échangeur","Récupération chaleur","Rendement"]},
  {id:"fed_av4",prompt:"Une Centrale de Traitement d'Air (CTA) en tertiaire assure :",choices:["Uniquement la ventilation mécanique","Le traitement hygrothermique complet de l'air (filtration, chauffage/refroidissement, humidification/déshumidification, récupération d'énergie)","Uniquement la filtration de l'air","La distribution d'eau glacée dans les ventilo-convecteurs"],answer:1,diff:1,explication:"CTA (Unité de Traitement d'Air = UTA) : filtration (G4/F7/H13), chauffage (batterie eau chaude/résistance), refroidissement (batterie eau glacée/DX), humidification (vapeur, adiabatique), récupération chaleur (roue ou plaques), by-pass. Régulation des débits via volets motorisés et variateurs (VFD sur moto-ventilateurs).",tags:["CTA","UTA","Traitement d'air","Tertiaire"]},
  {id:"fed_av5",prompt:"Les pertes de charge singulières (accessoires, coudes, réductions) dans un réseau aéraulique sont exprimées en :",choices:["Pascals directement par la loi de Darcy","ΔPs = ξ × ρv²/2 (Pa), où ξ est le coefficient de perte de charge singulière (adimensionnel)","Watts par mètre de conduit","En m³/h divisé par la section"],answer:1,diff:3,explication:"Pertes de charge dans les conduits : régulières ΔPr = f × L/D × ρv²/2 (Darcy-Weisbach) ; singulières ΔPs = ξ × ρv²/2. ξ dépend du type d'accessoire (coude 90° : ξ ≈ 0.5-1.0). La pression dynamique Pdyn = ρv²/2 (Pa). Vitesse max recommandée : 6-8 m/s (galerie principale), 3-4 m/s (terminaux).",tags:["Aéraulique","Pertes de charge","Singulières","Conduits"]},
  {id:"fed_av6",prompt:"La vitesse recommandée dans un conduit de ventilation tertiaire (galerie principale) ne doit pas dépasser :",choices:["2 m/s (pour éviter le bruit)","6-8 m/s en galerie principale (compromis vitesse/pression sonore/perte de charge)","20 m/s (vitesse industrielle)","0.5 m/s (tirage naturel uniquement)"],answer:1,diff:2,explication:"Recommandations aérauliques : galeries principales 6-8 m/s, distributions secondaires 4-6 m/s, bouches de soufflage/extraction 2-4 m/s (confort). Au-delà de 8 m/s : pertes de charge quadratiques excessives et bruit aéraulique (Lw ↑). Dimensionnement selon abaque de Carrier ou calcul Darcy-Weisbach.",tags:["Aéraulique","Vitesse","Conduits","Bruit"]},
  {id:"fed_av7",prompt:"Un filtre G4 dans une CTA correspond à :",choices:["Un filtre haute efficacité HEPA","Un filtre grossier (efficacité ISO ePM10 > 50%) retenant les grosses particules (pollen, insectes)","Un filtre absolu (efficacité > 99.97%)","Un filtre à charbon actif pour les odeurs"],answer:1,diff:2,explication:"Classification EN ISO 16890 (remplace EN 779) : ePM10 > 50% = G4 (grossier, anciennement EU4). ePM2.5 > 50% = M5/F6 (médium). ePM1 > 50% = F7/F8 (fin). HEPA H13 : > 99.95% (salle propre, bloc opératoire). CTA standard : pré-filtre G4 + filtre M5/F7. Air filtration = qualité de l'air intérieur (QAI).",tags:["Filtre","CTA","G4","EN ISO 16890"]},
  {id:"fed_av8",prompt:"Le taux de renouvellement d'air (TRA) recommandé dans un bureau occupé est de :",choices:["0.1 vol/h (très faible, air stagnant)","25-36 m³/h/personne selon la norme NF EN 13779 (équivalent 1-2 vol/h selon la surface)","100 m³/h/personne","1 vol/h uniquement pour les locaux humides"],answer:1,diff:2,explication:"NF EN 13779 (ventilation bâtiments non résidentiels) : qualité d'air IDA 2 (bonne) = 36 m³/h/pers, IDA 3 (moyenne) = 25 m³/h/pers. Taux CO₂ en occupation : IDA2 < 800 ppm, IDA3 < 1000 ppm. Le RSDT (rapport de soufflage) et le brassage influencent l'efficacité de la ventilation.",tags:["Taux renouvellement","Bureau","NF EN 13779","QAI"]},
  {id:"fed_av9",prompt:"La ventilation nocturne (free cooling nocturne) en été permet de :",choices:["Réduire la consommation de chauffage en hiver","Évacuer les calories stockées dans l'inertie thermique du bâtiment en faisant circuler l'air frais nocturne → recharge le bâtiment en fraîcheur pour le lendemain","Augmenter le débit VMC pendant la nuit pour la qualité de l'air","Éviter la condensation sur les murs en hiver"],answer:1,diff:2,explication:"Free cooling : en été, lorsque T_ext nocturne < T_int, on augmente massivement le débit d'air (2-5 vol/h) pour refroidir l'inertie thermique du bâtiment (dalle, murs). Le bâtiment 'recharge' en fraîcheur → confort diurne amélioré sans climatisation. Nécessite une inertie forte et un pilotage GTB intelligent.",tags:["Free cooling","Ventilation nocturne","Inertie","Confort été"]},
  {id:"fed_av10",prompt:"Le débit extrait par un extracteur de cuisine à hotte doit être :",choices:["Égal au débit d'air soufflé dans la pièce","Suffisant pour capter les graisses et odeurs (150-400 m³/h), avec un filtre anti-graisse et rejet à l'extérieur ou recyclage à charbon actif","Inférieur au débit de ventilation de la pièce","Uniquement en fonctionnement permanent"],answer:1,diff:1,explication:"Hotte de cuisine : débit 150-400 m³/h selon largeur. Filtre anti-graisse (métal lavable). Rejet direct extérieur : le plus efficace (pas de recyclage de l'humidité). Hotte recyclage (filtre charbon actif) : moins efficace en humidité, utilisée si rejet impossible. La hotte n'est pas substituable à la VMC (différents systèmes).",tags:["Hotte","Cuisine","Extraction","Graisse"]},
  {id:"fed_av11",prompt:"Un caisson de ventilation double-ouïe à variation de débit (VFD intégré) est sélectionné pour :",choices:["Uniquement les installations résidentielles simples","Adapter le débit d'air aux besoins réels (occupation, CO₂, HR) → économies d'énergie (P ∝ N³) et meilleur confort","Maximiser le débit constant en toutes circonstances","Minimiser le coût d'installation sans critère de performance"],answer:1,diff:2,explication:"Caisson VMC avec VFD : variation continue du débit selon la demande (occupation, qualité de l'air, heure). Économies par rapport à débit constant : jusqu'à 70% sur la consommation du ventilateur (loi cubique). Régulation via capteurs CO₂ (mesure indirecte de l'occupation) ou hygrostats. Idéal en ERP tertiaire.",tags:["Caisson ventilation","VFD","Variation de débit","Économie d'énergie"]},
  {id:"fed_av12",prompt:"L'essai de débit d'une installation aéraulique (mesure du débit aux bouches) utilise :",choices:["Un wattmètre de puissance","Un anémomètre à fil chaud, un anémomètre à hélice ou un caisson de mesure de débit (Capture Hood) directement positionné sur la bouche de soufflage ou d'extraction","Un tachymètre rotatif","Un thermomètre infrarouge"],answer:1,diff:2,explication:"Équilibrage aéraulique : mesure des débits aux bouches avec caisson (capture hood = mesure directe du débit en m³/h) ou anémomètre à fil chaud/hélice × section du conduit. Comparaison avec débits réglementaires (arrêté 1982/DTU 68.3). Ajustement par registres d'équilibrage. Procès-verbal de réception de l'installation.",tags:["Mesure de débit","Capture Hood","Équilibrage aéraulique","VMC"]},
];

// ─── BANQUE QB_FED_HYDRAULIQUE ───
export const QB_FED_HYDRAULIQUE = [
  {id:"fed_hy1",prompt:"Une pompe centrifuge est sélectionnée en fonction de :",choices:["Uniquement sa puissance nominale","Son point de fonctionnement = intersection entre sa courbe caractéristique (HMT / débit) et la courbe de réseau (pertes de charge / débit)","Sa couleur et ses dimensions","Son fabricant uniquement"],answer:1,diff:2,explication:"Sélection pompe : courbe caractéristique pompe (HMT en fonction de Q) + courbe de réseau (ΔP ∝ Q² pour un réseau à vanne fixe). Le point d'intersection = point de fonctionnement. Si la pompe fonctionne loin de son point nominal BEP (Best Efficiency Point) → rendement faible + surchauffe.",tags:["Pompe centrifuge","Courbe caractéristique","Point de fonctionnement","Hydraulique"]},
  {id:"fed_hy2",prompt:"La HMT (Hauteur Manométrique Totale) d'une pompe comprend :",choices:["Uniquement la hauteur géométrique à vaincre","La somme de la hauteur géométrique (ou pression statique), des pertes de charge régulières et singulières, et de la différence de pression dynamique entre aspiration et refoulement","Le débit multiplié par la pression","La puissance absorbée par le moteur"],answer:1,diff:2,explication:"HMT = Hgéom + ΔP_charge_totale + ΔP_dynamique. Pour un circuit fermé (chauffage en boucle) : HMT = uniquement les pertes de charge du circuit (pas de hauteur statique → pression compensée). Pour circuit ouvert (eau à un réservoir surélevé) : HMT inclut la hauteur géométrique.",tags:["HMT","Pompe","Pertes de charge","Circuit hydraulique"]},
  {id:"fed_hy3",prompt:"Un vase d'expansion (à membrane) dans un circuit de chauffage est dimensionné pour :",choices:["Stocker l'eau chaude sanitaire","Absorber la dilatation de l'eau lors du chauffage (l'eau se dilate de ≈ 4.3% entre 10°C et 90°C) sans dépasser la pression de tarage de la soupape de sécurité","Réguler la pression de l'eau de refroidissement uniquement","Créer une séparation hydraulique entre deux circuits"],answer:1,diff:2,explication:"Dilatation de l'eau : 10°C → 90°C ≈ +4.3% de volume. Sans vase d'expansion : pression monte → soupape de sécurité s'ouvre. Vase à membrane : la pression du gaz (azote) au-dessus de la membrane absorbe la dilatation. Pression de gonflage = pression statique du circuit. Volume vase calculé selon la formule EN 12828.",tags:["Vase d'expansion","Dilatation","Circuit chauffage","Pression"]},
  {id:"fed_hy4",prompt:"Un plancher chauffant hydraulique (PCH) fonctionne en basse température car :",choices:["Les tubes sont trop fins pour les hautes pressions","La surface radiante importante (toute la surface du sol) permet un delta T faible (30-45°C) pour la même puissance qu'un radiateur haute température","Le béton de la dalle ne supporte pas les hautes températures","Les régulateurs imposent 30°C maximum"],answer:1,diff:1,explication:"Plancher chauffant (PCH) : tubes PER ou multicouche noyés dans la chape. Surface émettrice = toute la surface du sol → puissance surfacique faible → T° eau basse (départ 35-45°C, retour 28-35°C). Idéal pour PAC (COP élevé à faible T°). Inertie forte → régulation anticipée. Pas compatible radiateurs haute température sans mélange.",tags:["Plancher chauffant","Basse température","PAC","Inertie"],},
  {id:"fed_hy5",prompt:"Un déséquilibre hydraulique dans un réseau de chauffage entraîne :",choices:["Uniquement une surconsommation d'énergie mineure","Des radiateurs trop chauds sur les circuits courts et trop froids sur les circuits longs → inconfort et surconsommation","Une pression uniforme dans tous les émetteurs","Un meilleur rendement des pompes"],answer:1,diff:2,explication:"Déséquilibre hydraulique : les courts-circuits (résistances faibles) captent trop de débit au détriment des circuits longs. Solution : équilibrage par vannes régulatrices de débit (STAD, STAF), robinets d'équilibrage sur chaque départ, ou pompes à débit variable avec régulation de pression différentielle. Équilibrage = prérequis énergétique.",tags:["Équilibrage hydraulique","Réseau chauffage","Débit","Radiateurs"]},
  {id:"fed_hy6",prompt:"La séparation hydraulique par un échangeur à plaques entre un circuit primaire (PAC/chaudière) et un circuit secondaire (distribution) permet :",choices:["D'augmenter la pression du circuit secondaire","D'isoler hydrauliquement les deux circuits (pression, débit, qualité d'eau différents) tout en transférant l'énergie thermique","De supprimer le besoin de pompe dans le circuit secondaire","D'éviter l'utilisation d'un vase d'expansion"],answer:1,diff:2,explication:"Échangeur de chaleur à plaques (ECP) : séparation physique des circuits (pas de mélange d'eau). Transfert thermique efficace (surface d'échange importante par volume réduit). Utilisé quand les pressions/qualités d'eau sont différentes (circuit PAC glycolé ↔ circuit chauffage eau), ou pour protéger les équipements (sous-station de chauffage urbain).",tags:["Échangeur à plaques","Séparation hydraulique","Circuit primaire/secondaire","ECP"]},
  {id:"fed_hy7",prompt:"L'eau chaude sanitaire (ECS) en réseau collectif doit être maintenue à :",choices:["40°C (confort sans risque de brûlure)","≥ 60°C en production et ≥ 50°C en tout point du réseau pour prévenir la légionellose (Legionella pneumophila)","30°C pour économiser l'énergie","55°C en production et 45°C en distribution uniquement en été"],answer:1,diff:2,explication:"Réglementation ECS collective (arrêté du 30/11/2005) : T° production ≥ 60°C (stérilisation Legionella), T° distribution ≥ 50°C en tout point. Legionella prolifère entre 25-45°C et meurt à ≥ 55°C (rapide à 60°C). Mitigeur thermostatique anti-brûlure ≤ 50°C en sortie au point de puisage. Relevé thermique mensuel obligatoire.",tags:["ECS","Légionellose","Legionella","Réglementation","Température"]},
  {id:"fed_hy8",prompt:"Le dimensionnement d'un réseau de distribution d'eau froide utilise la méthode des Unités de Charge (UC) selon :",choices:["L'arrêté du 24 mars 1982","La norme NF EN 806 / DTU 60.11 : chaque appareil a des UC selon son débit de pointe → calcul du débit simultané (simultanéité)","La RE 2020 uniquement","La loi de Poiseuille directement sans coefficient de simultanéité"],answer:1,diff:2,explication:"DTU 60.11 / NF EN 806-3 : méthode des UC (Unités de Charge) pour tenir compte de la diversité d'usage (les appareils ne fonctionnent pas tous en même temps). UC attribués par type d'appareil. Débit simultané Q = f(ΣUC). Vitesse max dans les canalisations : 0.5-1 m/s (distribution), 2-3 m/s (colonnes montantes). Pertes de charge < 30 Pa/m.",tags:["DTU 60.11","Unités de charge","Simultanéité","EF/ECS"]},
  {id:"fed_hy9",prompt:"Une vanne 3 voies mélangeuse dans un circuit de chauffage est utilisée pour :",choices:["Couper complètement le débit dans le circuit","Mélanger l'eau chaude primaire avec l'eau de retour secondaire refroidie pour obtenir une T° de départ modulée (régulation de la courbe de chauffe)","Mesurer le débit dans la canalisation","Compenser la pression différentielle du réseau"],answer:1,diff:2,explication:"Vanne 3 voies mélangeuse (M) : mélange eau chaude (C) + eau de retour (R) → eau de départ (D) à température régulée. Actionneur motorisé piloté par régulateur selon T_ext (courbe de chauffe) ou T_retour. Vanne 3 voies déviante (D) : dérive le débit vers deux circuits. La courbe de chauffe = loi d'eau (T_départ = f(T_ext)).",tags:["Vanne 3 voies","Régulation","Courbe de chauffe","Circuit chauffage"]},
  {id:"fed_hy10",prompt:"Le robinet thermostatique (robinet de radiateur) régule :",choices:["Le débit global de la pompe","La température locale dans la pièce en modulant le débit d'eau dans ce radiateur (valve thermostatique + tête thermostatique avec capteur de cire)","La pression du réseau général","Le débit de retour dans le collecteur principal"],answer:1,diff:1,explication:"Robinet thermostatique : corps de vanne (préréglable pour équilibrage) + tête thermostatique (capteur cire dilatant → ferme la vanne si T° pièce atteint la consigne). Régulation pièce par pièce sans électricité (mécanique). Préréglage = équilibrage. Remplacement par robinet programmable (électronique) pour économies supplémentaires.",tags:["Robinet thermostatique","Radiateur","Régulation","Équilibrage"]},
  {id:"fed_hy11",prompt:"Le rendement global d'un réseau de distribution de chaleur (pertes en réseau) est caractérisé par :",choices:["Le ratio puissance fournie aux émetteurs / puissance produite en chaudière (pertes linéiques des canalisations non isolées)","Le facteur de puissance électrique de la pompe","La pression différentielle entre départ et retour","Le débit de la pompe en m³/h uniquement"],answer:1,diff:2,explication:"Pertes de réseau : les canalisations de distribution perdent de la chaleur vers l'extérieur si elles ne sont pas isolées (ou si elles traversent des locaux non chauffés). Pertes réseau : ΦR = U_canalisation × L × (T_eau - T_ext). DTU 45.11 / réglementation RT2012 imposent des épaisseurs d'isolation minimales selon le diamètre et le type de réseau.",tags:["Réseau chauffage","Pertes en réseau","Isolation canalisations","DTU 45.11"]},
  {id:"fed_hy12",prompt:"Le coefficient de performance (COP) d'un système de chauffage urbain (réseau de chaleur) est qualifié par :",choices:["Uniquement la T° de l'eau primaire en sous-station","Le contenu CO₂ et énergies primaires du mix énergétique du réseau (biomasse, géothermie, récupération → facteur EnR&R)","La pression de service du réseau primaire","La distance entre la chaufferie et les abonnés"],answer:1,diff:3,explication:"Réseaux de chaleur urbains (RCU) : alimentation en eau chaude haute pression (70-120°C) depuis des chaufferies centrales (bois-énergie, géothermie, récupération chaleur fatale, cogénération). Facteur EnR&R (Énergie Renouvelable et de Récupération) ≥ 50% → éligibilité aux aides (Fonds Chaleur ADEME) et coefficient d'énergie primaire favorable (1.0).",tags:["Réseau de chaleur","EnR&R","Géothermie","Cogénération"]},
];

// ─── BANQUE QB_FED_FROID_CLIM ───
export const QB_FED_FROID_CLIM = [
  {id:"fed_fc1",prompt:"Le diagramme de Mollier (enthalpie/pression) du cycle frigorifique permet de lire :",choices:["La vitesse du compresseur en tr/min","Les enthalpies à chaque point du cycle (h1, h2, h3, h4) → puissances frigorifique et calorifique, travail du compresseur, COP"],answer:1,diff:2,explication:"Diagramme h-log(P) (Mollier) : abscisse = enthalpie massique h (kJ/kg), ordonnée = pression (bar). Points clés : 1 (sortie évaporateur), 2 (sortie compresseur), 3 (sortie condenseur), 4 (sortie détendeur). Puissance frig = ṁ × (h1-h4), puissance cal = ṁ × (h2-h3), W_compresseur = ṁ × (h2-h1). COP = (h1-h4)/(h2-h1).",tags:["Mollier","Diagramme","Cycle frigorifique","Enthalpie"]},
  {id:"fed_fc2",prompt:"La surchauffe à l'aspiration du compresseur (gaz chauds) est volontairement maintenue pour :",choices:["Augmenter le COP en refroidissant le gaz","Éviter que des gouttelettes de liquide n'entrent dans le compresseur (coup de liquide → destruction)","Réduire la pression d'aspiration","Augmenter le débit massique du fluide"],answer:1,diff:2,explication:"Surchauffe (5-10°C) : le fluide frigorigène en sortie d'évaporateur est légèrement en phase gazeuse surchauffée → garantit l'absence de liquide à l'aspiration du compresseur. Le liquide est incompressible → coup de liquide = destruction instantanée du compresseur. Sous-refroidissement (5-10°C) au condenseur améliore le COP.",tags:["Surchauffe","Compresseur","Coup de liquide","Cycle frigorifique"]},
  {id:"fed_fc3",prompt:"L'EER (Energy Efficiency Ratio) d'une unité de climatisation est défini par :",choices:["EER = P_chaud / P_élec (comme le COP en chauffe)","EER = P_froid / P_élec (puissance frigorifique utile / puissance électrique consommée en mode refroidissement)","EER = T_évaporateur / T_condenseur","EER = Débit air / Puissance électrique"],answer:1,diff:1,explication:"EER = Energy Efficiency Ratio (mode refroidissement). EER de 3 : pour 1 kW électrique, 3 kW de puissance frigorifique. SEER = EER saisonnier (conditions réelles sur la saison de refroidissement). Réglementation ErP : SEER minimum imposé selon la puissance de l'unité. PAC réversible : COP en chauffe > EER (condensation à T_int plus élevée).",tags:["EER","SEER","Climatisation","Performance"]},
  {id:"fed_fc4",prompt:"La réglementation F-gas (UE 517/2014, révisée 2024) impose aux techniciens travaillant sur des équipements contenant des HFC de :",choices:["Uniquement enregistrer les interventions","Posséder une attestation de capacité (catégorie I à IV selon la charge en GWP) délivrée par un organisme agréé (DEKRA, Bureau Veritas, etc.)","Utiliser uniquement du R290 (propane)","Acheter leurs fluides uniquement auprès du fabricant de l'équipement"],answer:1,diff:2,explication:"Attestation de capacité F-gas : catégorie I (toutes interventions, y.c. récupération), II (installation sans récupération), III (contrôle étanchéité sans récupération), IV (récupération seule). Attestation délivrée après examen (organisme accrédité). Registres de l'installation obligatoires (interventions, charges). Récupération des fluides obligatoire en fin de vie.",tags:["F-gas","Attestation de capacité","HFC","Réglementation"]},
  {id:"fed_fc5",prompt:"Le contrôle périodique d'étanchéité d'une installation frigorifique (charge > 5 t éq. CO₂) doit être réalisé :",choices:["Tous les 5 ans uniquement","Tous les 12 mois (charge 5-50 t éq. CO₂) ou tous les 6 mois (> 50 t éq. CO₂) par un technicien certifié F-gas"],answer:1,diff:2,explication:"Règlement F-gas UE 517/2014 : seuils de contrôle basés sur la charge en tonnes éq. CO₂ (masse (kg) × PRG). < 5 t éq. CO₂ : pas de contrôle périodique obligatoire. 5-50 t : contrôle annuel. > 50 t : contrôle semestriel. > 500 t : + détecteur de fuite automatique. Registre d'installation obligatoire.",tags:["Contrôle étanchéité","F-gas","Charges","Registre"]},
  {id:"fed_fc6",prompt:"Le fluide frigorigène R290 (propane) est dit 'naturel' car :",choices:["Il est produit industriellement sans pétrole","Son PRG = 3 (quasi nul, pas d'impact sur le réchauffement climatique) et c'est un hydrocarbure naturel — mais il est hautement inflammable (A3)"],answer:1,diff:2,explication:"Fluides naturels : R290 (propane, PRG=3, A3 inflammable), R600a (isobutane, PRG=3, A3), R744 (CO₂, PRG=1, A1), R717 (ammoniac NH₃, PRG=0, B2L toxique-inflammable). Alternatives aux HFC (R32 PRG=675, R134a PRG=1430). Tendance réglementaire : transition vers fluides bas-PRG. Charge réduite (< 3 kg R290 recommandé pour sécurité).",tags:["R290","Propane","Fluide naturel","PRG","Inflammable"]},
  {id:"fed_fc7",prompt:"Un système DRV (Débit de Réfrigérant Variable, ou VRF) se distingue d'un système split classique par :",choices:["L'utilisation d'un seul fluide frigorigène spécifique","La gestion centralisée de plusieurs unités intérieures (jusqu'à 64) par une seule unité extérieure, avec variation du débit de frigorigène selon la charge de chaque pièce"],answer:1,diff:2,explication:"DRV/VRF (Variable Refrigerant Flow) : une unité extérieure + réseau de frigorène (R410A ou R32) + multiples unités intérieures. Chaque unité intérieure module sa puissance indépendamment. Détendeurs électroniques individuels. Possibilité de récupération de chaleur (certaines pièces en chauffe, d'autres en froid simultanément). Usage tertiaire (bureaux, hôtels, commerces).",tags:["DRV","VRF","Climatisation","Tertiaire"]},
  {id:"fed_fc8",prompt:"La tour aéroréfrigérante (TAR) dans un système de refroidissement tertiaire sert à :",choices:["Produire de l'eau glacée directement","Dissiper la chaleur du condenseur par évaporation d'une partie de l'eau (condensation humide), avec un meilleur rendement qu'un condenseur à air"],answer:1,diff:2,explication:"Tour aéroréfrigérante (cooling tower) : eau de condensation circulant dans le condenseur du chiller → pompée vers la tour → pulvérisée sur des garnissages → évaporation partielle → dissipation de chaleur. T° eau froide ≈ 27-32°C (contre 35-45°C pour condenseur à air). Meilleur COP du chiller. Risque légionellose → entretien strict (arrêté du 14/12/2013).",tags:["Tour aéroréfrigérante","TAR","Condenseur","Légionellose"]},
  {id:"fed_fc9",prompt:"Le TEWI (Total Equivalent Warming Impact) d'une installation frigorifique prend en compte :",choices:["Uniquement les fuites de fluide frigorigène","Les émissions directes (fuites du fluide frigorigène × PRG) ET indirectes (CO₂ lié à la consommation électrique sur la durée de vie)"],answer:1,diff:3,explication:"TEWI = impact climatique total = effet direct (fuites fluide × PRG × kg fuite × années) + effet indirect (consommation électrique × facteur CO₂ du réseau × durée de vie). Un fluide à faible PRG (R290) mais consommant plus d'électricité peut avoir un TEWI similaire à un fluide plus efficace à PRG plus élevé. Raisonnement global.",tags:["TEWI","Impact climatique","PRG","Efficacité"]},
  {id:"fed_fc10",prompt:"La réversibilité d'une PAC ou d'un climatiseur (mode chauffe/froid) est assurée par :",choices:["Deux compresseurs distincts","Un inverseur de cycle (vanne 4 voies) qui inverse la circulation du frigorigène → l'évaporateur devient condenseur et inversement"],answer:1,diff:2,explication:"Vanne 4 voies (reversing valve) : commute entre mode chauffe (condenseur côté intérieur = chaleur fournie) et mode froid (évaporateur côté intérieur = fraîcheur fournie). L'unité extérieure alterne entre condenseur (mode froid) et évaporateur (mode chaud). Actionnée par solénoïde. Standard sur toutes les PAC air/air réversibles.",tags:["Réversibilité","Vanne 4 voies","PAC","Mode chauffe/froid"]},
  {id:"fed_fc11",prompt:"Un système de free cooling adiabatique (vs refroidissement mécanique) en data center peut économiser :",choices:["5-10% de l'énergie de refroidissement","60-80% de l'énergie de refroidissement lors des périodes où T_ext < T_eau_froide_requise"],answer:1,diff:3,explication:"Free cooling (économiseur) : lorsque T_ext < T° souhaitée de l'eau froide (< 12°C environ), on utilise directement l'air extérieur pour refroidir sans compresseur. Économiseur à circuit direct ou indirect (échangeur). Data centers en Europe du Nord : 80-90% du temps en free cooling. PUE (Power Usage Effectiveness) = énergie totale / énergie IT.",tags:["Free cooling","Data center","Économie d'énergie","Adiabatique"]},
  {id:"fed_fc12",prompt:"La température de claquage (température de dewpoint ou point de rosée) dans un local climé permet de :",choices:["Régler la température de consigne du thermostat","Calculer la T° à laquelle l'air se sature (HR = 100%) → risque de condensation sur les surfaces froides (batterie froide, gaines, façades non isolées)"],answer:1,diff:2,explication:"Point de rosée (Td) : T° à partir de laquelle l'air se condense (en dessous → condensation). Exemple : air à 25°C / HR 60% → Td ≈ 17°C. Si surface < 17°C → condensation. Importance en CTA (température batterie froide > Td pour éviter condensation excessive) et isolation des gaines froides en milieu humide.",tags:["Point de rosée","Condensation","HR","Psychrométrie"]},
];

// ─── BANQUE QB_FED_ENR ───
export const QB_FED_ENR = [
  {id:"fed_enr1",prompt:"Le rendement d'un capteur solaire plan (CSP) en eau chaude sanitaire solaire est typiquement de :",choices:["5-10% (comme un panneau PV)","40-70% selon les conditions (température, ensoleillement) — bien supérieur au PV en production thermique","95-100% (quasi total)","25-30% uniquement"],answer:1,diff:2,explication:"Capteur solaire plan (thermique) : rendement η = 0 - a1×(T*) - a2×G×(T*)² (courbe EN ISO 9806). T* = (T_moy - T_amb)/G. Typiquement 50-70% à faible ΔT (eau froide + fort ensoleillement). Capteurs à tubes sous vide (CPC) : η > 65% même à faible ensoleillement. CESI (Chauffe-Eau Solaire Individuel) : taux de couverture 50-70%.",tags:["Solaire thermique","CESI","Rendement capteur","CPC"]},
  {id:"fed_enr2",prompt:"Pour un panneau solaire photovoltaïque (PV) standard silicium cristallin, le rendement est approximativement de :",choices:["5% (inefficace)","18-22% (silicium monocristallin), soit 150-200 Wc/m²","50% (très haute efficacité)","35% (cellules bifaciales uniquement)"],answer:1,diff:1,explication:"Silicium monocristallin : η ≈ 18-22%, Wc ≈ 200-220 Wc/m². Polycristallin : η ≈ 15-18%. Amorphe (thin film) : 7-12%. Haute efficacité HJT/TOPCon : 22-24%. Rendement chuté avec T° : -0.4%/°C au-delà de 25°C (NOCT). Performance simulée via logiciels (PVsyst, HelioScope).",tags:["Photovoltaïque","Rendement","Silicium","PV"]},
  {id:"fed_enr3",prompt:"L'onduleur (inverter) dans une installation PV a pour rôle :",choices:["Stocker l'énergie solaire en journée","Convertir le courant continu (DC) produit par les panneaux en courant alternatif (AC) synchronisé avec le réseau (50 Hz, 230 V ou 400 V)","Mesurer uniquement la puissance des panneaux","Réguler la charge des batteries uniquement"],answer:1,diff:1,explication:"Onduleur PV : DC → AC (MPPT = Maximum Power Point Tracking pour optimiser la puissance extraite des panneaux). Onduleur central (un seul), onduleurs de chaîne (string inverters), microonduleurs (un par panneau). Efficacité > 97%. Connecté au réseau ou avec batterie (hybride). En cas de coupure réseau → îlotage interdit (sécurité ENEDIS).",tags:["Onduleur","PV","MPPT","DC/AC"]},
  {id:"fed_enr4",prompt:"La géothermie très basse énergie (sondes verticales, PAC eau/eau) exploite la stabilité thermique du sol à :",choices:["0°C en profondeur (réseau de froid naturel)","10-15°C toute l'année à partir de 15-20 m de profondeur, quelle que soit la saison","30°C en été et 5°C en hiver","La T° varie de la même façon qu'en surface"],answer:1,diff:1,explication:"Géothermie très basse énergie (< 30°C) : sondes verticales (50-200 m) ou capteurs horizontaux (0.8-1.2 m de profondeur). Sol ≈ 12-15°C toute l'année → source froide stable pour PAC (COP de 4-5 vs 2-3 pour PAC air/air). Sonde géothermique : tube en U ou coaxial avec fluide caloporteur (eau glycolée). Forage soumis à déclaration ou autorisation selon profondeur.",tags:["Géothermie","Sonde géothermique","Stabilité thermique","PAC eau/eau"]},
  {id:"fed_enr5",prompt:"Le contrat d'autoconsommation collective PV (REACo) permet à des producteurs et consommateurs locaux de :",choices:["Revendre toute leur production à EDF OA","Partager l'énergie solaire produite entre plusieurs consommateurs d'un même périmètre géographique via le réseau de distribution (virtualisation des échanges)","Créer un réseau privé indépendant d'ENEDIS","Obtenir des subventions automatiques de l'ADEME"],answer:1,diff:3,explication:"Autoconsommation collective (loi transition énergétique 2017) : producteurs + consommateurs proches (même poste HTB → BT, rayon max depuis 2023 = variable selon décret). Répartition de la production selon des clés définies dans l'opération. Économies sur la facture, valorisation de la production locale. Gestion via opérateur de l'opération (OOA).",tags:["Autoconsommation collective","PV","REACo","Réseau de distribution"]},
  {id:"fed_enr6",prompt:"Un chauffe-eau thermodynamique (CET) utilise :",choices:["Uniquement une résistance électrique (comme un chauffe-eau classique)","Une PAC air/air intégrée pour produire l'ECS : extrait la chaleur de l'air ambiant ou de l'air extérieur pour chauffer l'eau (COP ≈ 3)","L'énergie solaire par des panneaux thermiques sur le toit","La géothermie via des capteurs enterrés"],answer:1,diff:1,explication:"CET (Chauffe-Eau Thermodynamique) : petite PAC intégrée dans le ballon d'ECS. Évaporateur prélève chaleur de l'air (ambiant ou extrait/extérieur). COP ≈ 2.5-3.5. Consomme 3× moins qu'un chauffe-eau électrique à résistance. Éligible au crédit d'impôt et aux aides ANAH. Nuisance sonore possible si installation en espace de vie.",tags:["CET","Chauffe-eau thermodynamique","PAC","ECS"]},
  {id:"fed_enr7",prompt:"Le Fonds Chaleur de l'ADEME finance des projets d'énergies renouvelables thermiques (biomasse, géothermie, solaire thermique) à destination des :",choices:["Particuliers uniquement pour leur résidence principale","Collectivités, entreprises et bailleurs sociaux pour des projets > 100 MWh/an","Tout le monde sans condition de taille","Exclusivement les réseaux de chaleur en zone rurale"],answer:1,diff:2,explication:"Fonds Chaleur ADEME : depuis 2009, subventionne les projets ENR thermiques dans le tertiaire, l'industrie, l'agriculture et les réseaux de chaleur. Objectif : développer la chaleur renouvelable (biomasse, géothermie, solaire thermique, PAC de grande puissance). Budget ~600 M€/an. Critère clé : coût de la chaleur produite vs énergie fossile de référence.",tags:["Fonds Chaleur","ADEME","ENR thermique","Subvention"]},
  {id:"fed_enr8",prompt:"La puissance crête (Wc) d'un panneau PV est mesurée dans les conditions standard (STC) :",choices:["Ensoleillement = 500 W/m², T° cellule = 20°C, masse d'air AM 1.0","Ensoleillement = 1000 W/m², T° cellule = 25°C, spectre AM 1.5","Ensoleillement = 1200 W/m², T° ambiante = 30°C","En plein soleil estival en France"],answer:1,diff:2,explication:"STC (Standard Test Conditions) : G = 1000 W/m², T_cellule = 25°C, spectre solaire AM 1.5 (masse d'air correspondant à un angle de 48.2°). Conditions normalisées pour comparaison entre fabricants. En conditions NOCT (45°C, 800 W/m²) la puissance est ≈ 10% inférieure. En usage réel (pertes câbles, salissures, ombrage, T° haute) → facteur de performance PR (Performance Ratio) ≈ 75-85%.",tags:["STC","Wc","Conditions standard","PV"]},
  {id:"fed_enr9",prompt:"La biomasse énergie (bois, pellets, résidus agricoles) est considérée comme énergie renouvelable car :",choices:["Elle ne produit pas de CO₂ lors de la combustion","Le CO₂ émis lors de la combustion est reabsorbé par la croissance des forêts sur le long terme (bilan carbone quasi neutre si gestion durable)","Elle est inépuisable comme le soleil","Sa combustion ne produit ni suies ni particules fines"],answer:1,diff:1,explication:"Biomasse énergie = cycle carbone court : la plante absorbe CO₂ pendant sa croissance → libéré lors de la combustion → réabsorbé par nouvelles plantations. Bilan CO₂ quasi nul si gestion forestière durable. Attention : émissions de particules fines (PM2.5, PM10) → chaudières à haute efficacité + filtres recommandés. Énergie primaire : coefficient 0.6 en RE 2020.",tags:["Biomasse","Bois-énergie","Carbone renouvelable","Forêt"]},
  {id:"fed_enr10",prompt:"La production éolienne varie avec la vitesse du vent selon :",choices:["Puissance ∝ v (linéaire)","Puissance ∝ v³ (cubique) : doubler la vitesse du vent octuple la puissance disponible","Puissance ∝ v² (quadratique)","Puissance constante quelle que soit la vitesse du vent"],answer:1,diff:2,explication:"Puissance éolienne : P = ½ × ρ × A × Cp × v³. Cp = coefficient de Betz (max théorique = 0.593). A = surface du rotor. v = vitesse du vent. La dépendance en v³ explique pourquoi l'implantation est cruciale (vent de 10 m/s → 8× plus d'énergie qu'à 5 m/s). Vitesse de démarrage ≈ 3-4 m/s, puissance nominale ≈ 12-14 m/s, coupure ≈ 25 m/s.",tags:["Éolien","Loi cubique","Betz","Puissance"]},
  {id:"fed_enr11",prompt:"Le certificat de qualification RGE (Reconnu Garant de l'Environnement) est obligatoire pour :",choices:["Tout artisan qui pose des fenêtres","Les artisans et entreprises dont les clients souhaitent bénéficier des aides fiscales (MaPrimeRénov', CEE) pour des travaux d'économies d'énergie ou d'installations EnR"],answer:1,diff:1,explication:"RGE : certification qualité pour accéder aux aides de l'État liées à la rénovation énergétique (MaPrimeRénov', éco-PTZ, CEE). Qualification par organisme accrédité (Qualibat, Qualifelec, QualiPAC, Qualit'EnR). Valable 4 ans, avec audit sur chantier. Obligatoire pour l'entreprise qui réalise les travaux (pas le donneur d'ordre).",tags:["RGE","Certification","MaPrimeRénov","Aides fiscales"]},
  {id:"fed_enr12",prompt:"L'indice de productivité d'un parc solaire PV (kWh/kWc/an) moyen en France métropolitaine est de :",choices:["200-300 kWh/kWc/an (très faible rayonnement)","900-1400 kWh/kWc/an selon la localisation (Sud : 1300-1400 ; Nord : 900-1000)","2000-2500 kWh/kWc/an (comme les tropiques)","400-500 kWh/kWc/an (France entière uniforme)"],answer:1,diff:2,explication:"Productivité PV (index de performance) : dépend de l'ensoleillement, de l'orientation (sud optimal), de l'inclinaison (30-35° pour maximiser en France), des pertes (température, ombrage, câbles). Marseille ≈ 1300-1400 kWh/kWc/an, Paris ≈ 1000, Rennes ≈ 950. Logiciel PVsyst ou HelioScope calcule la production annuelle estimée.",tags:["Productivité PV","kWh/kWc","Ensoleillement","France"]},
];

// ─── BANQUE QB_FED_REGLEMENTATION ───
export const QB_FED_REGLEMENTATION = [
  {id:"fed_reg1",prompt:"La RE 2020 succède à la RT 2012 et s'applique aux permis de construire déposés depuis :",choices:["Janvier 2018","Janvier 2022 pour les maisons individuelles et logements collectifs (tertiaire neuf en cours de déploiement progressif)","Juillet 2025 uniquement","Janvier 2015"],answer:1,diff:1,explication:"RE 2020 (Réglementation Environnementale 2020) : applicable aux logements neufs depuis le 1er janvier 2022 (maisons individuelles et immeubles collectifs), puis progressivement au tertiaire. Elle renforce la RT 2012 en ajoutant un troisième pilier : l'impact carbone (analyse de cycle de vie ACV du bâtiment). Révision des seuils prévue en 2025 et 2028.",tags:["RE 2020","RT 2012","Application","Bâtiment neuf"]},
  {id:"fed_reg2",prompt:"Le label BBC Effinergie Rénovation (Bâtiment Basse Consommation) exige une consommation d'énergie primaire inférieure à :",choices:["100 kWh/m²/an en rénovation","80 kWh/m²/an × coefficient climatique (Cep ≤ 80 kWh/m²/an × modulation géographique et altitude)","50 kWh/m²/an (standard BEPOS)","150 kWh/m²/an (critère minimal)"],answer:1,diff:2,explication:"BBC Rénovation (Effinergie) : Cep ≤ 80 kWh/m²/an × coefficient Ccoef (module selon la zone climatique, de 1.0 à 1.3 selon altitude/région) + perméabilité à l'air testée. Plus exigeant que la RT 2012 (100 kWh/m²/an pour le neuf). Condition obligatoire pour certaines aides (éco-PTZ, MaPrimeRénov' Rénovation Globale).",tags:["BBC Effinergie","Rénovation","80 kWh","Cep"]},
  {id:"fed_reg3",prompt:"L'arrêté du 3 mai 2007 (installations d'eau chaude sanitaire collective) impose une surveillance pour prévenir :",choices:["Les problèmes de pression dans les réseaux","Le risque légionellose dans les réseaux d'ECS collectifs (T° maintenance, purges, nettoyage, analyses bactériologiques)","Les pertes thermiques des canalisations","La corrosion des tuyaux en cuivre"],answer:1,diff:2,explication:"Arrêté du 3 mai 2007 (révisé) : applicable aux ERP (établissements recevant du public) avec réseau ECS collectif. Impose : T° production ≥ 60°C, T° distribution ≥ 50°C en tous points, purges régulières des points bas, maintenance, analyses bactériologiques si risque. Plan de maîtrise du risque légionellose (carnet sanitaire).",tags:["ECS collective","Légionellose","Arrêté 2007","Réglementation"]},
  {id:"fed_reg4",prompt:"Les Certificats d'Économies d'Énergie (CEE) obligent :",choices:["Les ménages à financer eux-mêmes les travaux de rénovation","Les fournisseurs d'énergie (obligés) à financer des économies d'énergie auprès des particuliers et entreprises (financement des travaux via 'coups de pouce')","Les constructeurs de bâtiments neufs à installer des ENR","L'État à verser des subventions directes aux artisans RGE"],answer:1,diff:2,explication:"CEE (système obligatoire depuis 2006) : les fournisseurs d'énergie (EDF, Engie, TotalEnergies...) ont des obligations de réduction de la consommation chez leurs clients. Ils financent des travaux éligibles (isolation, PAC, chaudière biomasse, éclairage LED...) en échange de certificats. Coups de pouce : bonifications pour les opérations prioritaires (isolation, chauffage). Les CEE peuvent aussi être revendus.",tags:["CEE","Certificats d'économies d'énergie","Obligés","Rénovation"]},
  {id:"fed_reg5",prompt:"La réglementation acoustique des bâtiments neufs (arrêté du 30 juin 1999, modifié 2013) impose un isolement DnT,A entre deux logements de :",choices:["25 dB minimum","≥ 53 dB entre logements (bruits aériens) dans les bâtiments d'habitation collectifs","60 dB minimum (standard hôtelier)","40 dB uniquement pour les murs séparatifs en briques"],answer:1,diff:2,explication:"Réglementation acoustique (NF S 31-130) : DnT,A ≥ 53 dB entre logements (bruits aériens). Niveau de bruit de choc Ln,AT ≤ 58 dB. Bruits des équipements : ≤ 35 dB(A) en séjour. NRA (Nouvelle Réglementation Acoustique) 2000 pour les logements neufs. Label Qualitel acoustique pour dépasser les minima réglementaires.",tags:["Acoustique","DnT,A","NRA","Logement collectif"]},
  {id:"fed_reg6",prompt:"Le DTU (Document Technique Unifié) est :",choices:["Un décret gouvernemental ayant force de loi","Un document normatif de référence (norme NF) définissant les règles de l'art pour chaque corps de métier du bâtiment (plomberie, isolation, électricité...)","Un label de performance énergétique","Un document d'inspection de chantier obligatoire"],answer:1,diff:1,explication:"DTU : normes de référence pour la mise en œuvre des ouvrages dans le BTP. Exemples : DTU 60.1 (plomberie sanitaire), DTU 68.3 (VMC), DTU 45.11 (isolation des réseaux de chaleur/froid). Deviennent des normes NF (NF DTU xxx). En cas de litige, le respect du DTU est une preuve du respect des règles de l'art. Les DTU sont publiés par l'AFNOR.",tags:["DTU","Normes","Règles de l'art","BTP"]},
  {id:"fed_reg7",prompt:"Le contrôle des installations électriques par le CONSUEL est obligatoire avant :",choices:["Chaque entretien annuel","La mise en service d'une installation neuve ou rénovée (attestation de conformité permettant la mise en service par ENEDIS)","La vente d'un bien immobilier","Tous les 10 ans dans les habitations"],answer:1,diff:2,explication:"CONSUEL (COmité National pour la Sécurité des USagers de l'ELectricité) : organisme agréé par l'État qui contrôle la conformité des installations électriques neuves (et rénovations avec modification du tableau). L'attestation de conformité CONSUEL est indispensable pour qu'ENEDIS raccorde l'installation. Contrôle NF C 15-100.",tags:["CONSUEL","Conformité électrique","ENEDIS","NF C 15-100"]},
  {id:"fed_reg8",prompt:"La norme NF EN 12831 définit la méthode de calcul de :",choices:["La consommation d'eau chaude sanitaire","Les déperditions thermiques des bâtiments (puissance de chauffage de base) selon la méthode européenne harmonisée","Le coefficient U des fenêtres","La résistance au feu des structures"],answer:1,diff:2,explication:"NF EN 12831 (méthode de calcul des déperditions thermiques de base) : remplace les anciennes méthodes nationales (G, K). Calcule la puissance de chauffage de base (W ou kW) nécessaire pour maintenir la T° de consigne à la T° extérieure de base (T_ext de base selon la zone climatique). Base du dimensionnement de l'installation de chauffage.",tags:["NF EN 12831","Déperditions","Puissance chauffage","Calcul thermique"]},
  {id:"fed_reg9",prompt:"Le classement REI des éléments de structure (résistance au feu) signifie :",choices:["Rendement, Efficacité, Isolation (performances thermiques)","R (Résistance mécanique) + E (Étanchéité aux flammes) + I (Isolation thermique) exprimés en minutes (REI 60, REI 120)","Règle, Équipement, Installation","Rayonnement, Émissivité, Isolation"],answer:1,diff:2,explication:"Classement feu (EN 13501-2) : R = stabilité mécanique (ne s'effondre pas), E = étanchéité aux flammes/gaz (pas de propagation), I = isolation thermique (face non exposée reste froide). Exprimés en minutes : REI 30, REI 60, REI 90, REI 120. Planchers : REI 60 standard. Logements collectifs : murs séparatifs REI 60 minimum.",tags:["REI","Résistance au feu","Incendie","Structure"]},
  {id:"fed_reg10",prompt:"La garantie décennale d'un installateur couvre :",choices:["Uniquement les dommages causés par des tempêtes ou inondations","Les dommages compromettant la solidité de l'ouvrage ou le rendant impropre à sa destination, pendant 10 ans après la réception","Les défauts d'entretien du client","Les pannes d'équipements dues à un mauvais usage"],answer:1,diff:1,explication:"Garantie décennale (art. 1792 Code civil) : responsabilité de l'entrepreneur pendant 10 ans pour tout dommage (vice caché, malfaçon) compromettant la solidité ou l'utilisation de l'ouvrage. Assurance dommage-ouvrage (DO) obligatoire pour le maître d'ouvrage. Assurance RCD (Responsabilité Civile Décennale) obligatoire pour tous les constructeurs. Garantie de parfait achèvement : 1 an.",tags:["Garantie décennale","Assurance","Responsabilité","Construction"]},
  {id:"fed_reg11",prompt:"La loi Elan (2018) introduit notamment l'obligation d'accessibilité universelle dans les bâtiments :",choices:["Pour 100% des logements neufs en collectif","Pour 20% des logements neufs en collectif (logements adaptables), avec obligation de réaliser les travaux d'adaptation sur demande du locataire/propriétaire en situation de handicap","Pour tous les logements individuels uniquement","Pour les bâtiments tertiaires de plus de 5000 m²"],answer:1,diff:3,explication:"Loi ELAN (Évolution du Logement, de l'Aménagement et du Numérique, 2018) : dans les immeubles collectifs neufs, 100% des logements doivent être évolutifs (adaptables) et 20% accessibles d'emblée (normes PMR complètes). Elle simplifie aussi les normes de stationnement, de recours contre permis de construire, et introduit le bail mobilité.",tags:["Loi Elan","Accessibilité PMR","Logement collectif","Handicap"]},
  {id:"fed_reg12",prompt:"Le Schéma Directeur de la Transition Énergétique (SDTE) et le Plan Climat-Air-Énergie Territorial (PCAET) sont élaborés par :",choices:["Les bureaux d'études thermiques","Les établissements publics de coopération intercommunale (EPCI) de plus de 20 000 habitants → stratégie locale de réduction des émissions de GES et de développement des ENR","L'ADEME uniquement au niveau national","Les syndicats d'énergie départementaux"],answer:1,diff:3,explication:"PCAET : document de planification locale obligatoire pour les EPCI > 20 000 habitants. Contenu : diagnostic énergie-climat, objectifs (réduction GES, ENR, maîtrise énergie), programme d'actions. Remplace le SRCAE et le PCET. Révisé tous les 6 ans. L'ADEME accompagne l'élaboration. Outil de mise en œuvre de l'Accord de Paris à l'échelle locale.",tags:["PCAET","EPCI","Transition énergétique","Collectivités"]},
];

// ─── BANQUE E5 : INTERVENTION SUR LES SYSTÈMES ───
export const QB_FED_E5_BILAN = [
  {id:"fed_e5_1",prompt:"L\'épreuve E5 dure combien de temps et quel est son coefficient ?",choices:["2h, coeff 3","3h, coeff 4","4h, coeff 5 — épreuve ponctuelle notée sur 20","6h, coeff 6"],answer:2,diff:1,explication:"E5 = 4h, coeff 5, sur 20, épreuve ponctuelle. Structure fixe : (1) Prise en charge ~45 min, (2) Mesures ~1h30, (3) Kistock RF ~45 min, (4) Analyse ~1h. Jury présent pendant toute l\'épreuve et vous interroge.",tags:["E5","Structure épreuve","Coefficient","BTS FED"]},
  {id:"fed_e5_2",prompt:"C6 (Outils numériques) représente quelle part de la note en E5 ?",choices:["20%","30%","40% — c\'est la compétence la plus importante","50%"],answer:2,diff:1,explication:"C6 = 40%, C7 = 30%, C8 = 30%. C6 est la plus pondérée : maîtriser le Kistock RF (ou la tablette CozytouchC pour condensation Atlantic) est PRIORITAIRE. Si C6 est raté, la note maximale possible tombe à 12/20 même avec C7 et C8 parfaits.",tags:["E5","C6","Pondération","Kistock RF"]},
  {id:"fed_e5_3",prompt:"La compétence C7-3 en E5 est évaluée sur :",choices:["La vitesse d\'exécution","Le fait que la démarche suit un protocole logique et adapté","La maîtrise du Kistock RF","Le calcul du rendement"],answer:1,diff:1,explication:"C7-3 = \'Respecter les procédures\'. Critère : la démarche suit un protocole. C7-4 = conduire essais/sécurité. C7-5 = choisir/utiliser appareils. C7-6 = interpréter résultats et écarts. Chaque sous-compétence a son propre critère — les mémoriser permet de savoir exactement ce que le jury évalue.",tags:["E5","C7","C7-3","Protocole"]},
  {id:"fed_e5_4",prompt:"C8-3 \'Analyser les résultats\' est le cœur du sujet E5. Que doit-on faire exactement ?",choices:["Juste noter les valeurs mesurées dans un tableau","Identifier les écarts entre valeurs constructeur et valeurs mesurées ET les interpréter (expliquer pourquoi)","Refaire les calculs 2 fois pour vérifier","Proposer un nouveau système"],answer:1,diff:1,explication:"C8-3 = identifier + interpréter. Toujours : (1) calculer la valeur mesurée, (2) relever la valeur constructeur dans la doc, (3) calculer l\'écart en %, (4) expliquer pourquoi (vieillissement, encrassement, conditions différentes, imprécision mesure). Constater sans expliquer = points perdus.",tags:["E5","C8-3","Valeurs constructeur","Analyse"]},
  {id:"fed_e5_5",prompt:"Quelles installations ont été rencontrées en E5 session 2025-2026 ?",choices:["Uniquement des chaudières gaz","CTA/PAC York, chaudières fioul et gaz, PAC air/eau Atlantic, chaudière granulés Froling, chaudière condensation Atlantic","Uniquement des PAC","Uniquement des CTA"],answer:1,diff:1,explication:"5 familles de systèmes tombés en 2025-2026 : CTA/PAC York (bilan batterie chaude, bilan PAC), Chaudière fioul basse T° (bilan générateur, émetteurs, échangeurs sanitaires), Chaudière gaz Condensinox (bilan générateur, échangeurs), PAC air/eau Atlantic Alféa R410A (COP chaud/froid), Chaudière granulés Froling (biomasse). La structure en 3 parties est identique pour tous.",tags:["E5","Sujets tombés","Systèmes","2026"]},
  {id:"fed_e5_6",prompt:"En E5, que doit contenir OBLIGATOIREMENT la partie \'Prise en charge\' ?",choices:["Uniquement le schéma de principe","Schéma de principe complété + nomenclature + procédure d\'intervention + choix appareils justifiés + identification capteurs GTC","Uniquement la procédure de sécurité","Uniquement les calculs prévisionnels"],answer:1,diff:2,explication:"La partie 1 (~45 min) exige : (1) Compléter le schéma de principe avec légende et codes couleurs par réseau, (2) Nomenclature (repère, désignation, fonction), (3) Procédure d\'intervention avec appareils justifiés, (4) Mesures de sécurité, (5) Identification capteurs/automate GTC (entrées/sorties). Tout manquant = points perdus en C8-1 et C7-3.",tags:["E5","Prise en charge","Schéma de principe","Nomenclature","Méthodologie"]},
  {id:"fed_e5_7",prompt:"La grille d\'évaluation E5 utilise 4 niveaux de notation. Le niveau 2 correspond à :",choices:["Non réalisé","Insuffisant","Satisfaisant — il suffit de viser le niveau 2 sur tous les indicateurs pour une très bonne note","Maîtrisé"],answer:2,diff:1,explication:"Niveaux : 0 (non réalisé), 1 (insuffisant), 2 (satisfaisant), 3 (maîtrisé). Viser le niveau 2 sur TOUS les indicateurs est suffisant pour une très bonne note. Stratégie : ne pas chercher la perfection sur un indicateur en sacrifiant les autres — la cohérence et l\'exhaustivité priment.",tags:["E5","Grille notation","Niveaux","Stratégie"]},
  {id:"fed_e5_8",prompt:"Comment le jury interroge-t-il pendant l\'E5 ?",choices:["Il attend la fin de l\'épreuve pour poser des questions","Les membres du jury passent vous interroger tout au long des 4 heures sur votre démarche, vos choix et vos calculs","Il n\'y a pas de questions orales en E5","Il y a un exposé de 10 min à la fin"],answer:1,diff:1,explication:"E5 = épreuve à la fois pratique ET orale. Le jury circule et interroge pendant toute l\'épreuve. Ne jamais répondre \'je ne sais pas\' sans explication. Une réponse incomplète mais argumentée vaut mieux que le silence. Prendre l\'initiative de présenter ce que vous faites sans attendre d\'être interrogé.",tags:["E5","Oral","Jury","Communication"]},
  {id:"fed_e5_9",prompt:"Quelle est la séquence correcte pour la mise en service en E5 ?",choices:["Lancer les mesures immédiatement après la mise en route","Mettre en fonctionnement via GTC → attendre la stabilisation (10-15 min minimum) → relever les mesures","Relever d\'abord à froid puis à chaud","Commencer par les calculs avant les mesures"],answer:1,diff:1,explication:"Ordre obligatoire : (1) Mettre en fonctionnement via GTC (avec l\'enseignant), (2) Observer les températures sur la GTC jusqu\'à stabilisation (régime permanent), (3) Seulement alors commencer les relevés. Relever avant stabilisation = erreur fatale = valeurs incorrectes = calculs faux = mauvaise note C7 et C8.",tags:["E5","Mise en service","Stabilisation","GTC","Méthodologie"]},
  {id:"fed_e5_10",prompt:"Comment doit se terminer CHAQUE partie du compte rendu E5 ?",choices:["Par la signature du candidat","Par une synthèse courte : l\'installation est-elle conforme ? Quelles améliorations proposer ? (points faciles à gagner sur C8)","Par la liste des appareils utilisés","Par la date et l\'heure"],answer:1,diff:1,explication:"Règle de base : chaque partie se clôt par une CONCLUSION. Questions à répondre systématiquement : (1) L\'installation est-elle conforme aux données constructeur ? (2) Quelles améliorations concrètes proposer dans le cadre d\'une rénovation ? Ce sont des points faciles à gagner sur C8-4 (concevoir une action corrective) — ne jamais les négliger.",tags:["E5","Conclusion","C8-4","Action corrective"]},
  {id:"fed_e5_11",prompt:"La formule de la puissance échangée par l\'eau est Φ = ṁ × Cp × ΔT. Pour Cp_eau, quelle valeur utiliser ?",choices:["1005 J/(kg·K)","2100 J/(kg·K)","4186 J/(kg·K) — chaleur massique de l\'eau liquide","4000 J/(kg·K)"],answer:2,diff:1,explication:"Cp_eau = 4186 J/(kg·K) = 4,186 kJ/(kg·K). C\'est une constante fondamentale à mémoriser. Pour l\'air : Cp_air ≈ 1005 J/(kg·K). Pour la vapeur d\'eau : Cp ≈ 2100 J/(kg·K). Ne pas les confondre en E5. Application : Φ(W) = ṁ(kg/s) × 4186 × ΔT(K).",tags:["E5","Cp eau","Formule","Bilan thermique"]},
  {id:"fed_e5_12",prompt:"Un débit de 1 800 L/h est mesuré. Quelle est la conversion correcte en kg/s pour le calcul de puissance (eau) ?",choices:["1 800 kg/s","0,5 kg/s (1800 / 3600 = 0,5 kg/s puisque ρ_eau ≈ 1 kg/L)","1,8 kg/s","18 kg/s"],answer:1,diff:2,explication:"Conversion : 1 800 L/h ÷ 3 600 s/h = 0,5 L/s = 0,5 kg/s (car ρ_eau ≈ 1 kg/L ≈ 1 kg/dm³). Application : Φ = 0,5 × 4186 × ΔT. Si ΔT = 10 K → Φ = 0,5 × 4186 × 10 = 20 930 W ≈ 21 kW. Erreur classique : oublier de diviser par 3600.",tags:["E5","Conversion","Débit","L/h vers kg/s","Calcul"]},
  {id:"fed_e5_13",prompt:"La formule du COP d\'une PAC est COP = Φ_utile / P_absorbée. Si Φ_utile = 9 kW et P_élec = 3 kW, que vaut le COP ?",choices:["0,33","3 (COP = 9/3 = 3 — pour 1 kWh électrique, 3 kWh thermiques fournis)","27","6"],answer:1,diff:1,explication:"COP = 9/3 = 3. Interprétation : 1 kW électrique → 3 kW thermiques. Les 2 kW \'supplémentaires\' proviennent de l\'air extérieur (source froide). Puissance prélevée sur la source froide = Φ_utile - P_élec = 9 - 3 = 6 kW. Pour comparer au constructeur, relever le COP nominal dans la fiche technique à la température d\'essai correspondante.",tags:["E5","COP","PAC","Calcul","Bilan thermique"]},
  {id:"fed_e5_14",prompt:"Le rendement PCI d\'une chaudière est η = Φ_utile / Φ_absorbée. Φ_absorbée se calcule par :",choices:["ṁ_eau × Cp × ΔT","qm_combustible (kg/s) × PCI (J/kg)","P_électrique du brûleur","Φ_utile / COP"],answer:1,diff:2,explication:"Φ_absorbée = qm_combustible × PCI. Exemple fioul (FOD) : qm = 3,213 kg/h = 0,000892 kg/s, PCI_FOD = 41 992 kJ/kg = 41 992 000 J/kg → Φ_abs = 0,000892 × 41 992 000 = 37 457 W ≈ 37,5 kW. Φ_utile = ṁ_eau × Cp × ΔT_eau. η = Φ_utile / 37,5 kW.",tags:["E5","Rendement PCI","Chaudière","Fioul","Calcul"]},
  {id:"fed_e5_15",prompt:"Quelle est la formule de l\'efficacité d\'un échangeur thermique ?",choices:["ε = Φ_utile × ΔT_max","ε = ΔT_réel / ΔT_max (ΔT_max = T_chaud_entrée − T_froid_entrée)","ε = Φ_utile / Φ_total","ε = ΔT_départ / ΔT_retour"],answer:1,diff:2,explication:"ε = ΔT_réel / ΔT_max. ΔT_max = T_chaud_entrée − T_froid_entrée (écart maximal théorique possible). ΔT_réel = variation effective mesurée du fluide le moins puissant. Application bilan échangeur sanitaire : calculer ε pour échangeur à plaque et multitubulaire, puis comparer au rendement constructeur (C8-3).",tags:["E5","Échangeur","Efficacité","Formule","Échangeur sanitaire"]},
  {id:"fed_e5_16",prompt:"La formule de Siegert pour les pertes par les fumées est :",choices:["qA = T_fumées × CO₂ / T_air","qA = (T_fumées − T_air) × (A₁/CO₂ + B) — A₁ et B dépendent du combustible","qA = CO₂% × O₂% / T_fumées","qA = (T_fumées + T_air) / CO₂"],answer:1,diff:3,explication:"Siegert : qA(%) = (T_fumées − T_air) × (A₁/CO₂% + B). Pour gaz naturel : A₁ ≈ 0,68, B ≈ 0,009. Pour fioul : A₁ ≈ 0,56, B ≈ 0,007. qA donne les pertes fumées en %. η_chaudière ≈ 100% - qA - pertes rayonnement. Méthode indirecte sans mesure directe du débit de combustible.",tags:["E5","Siegert","Pertes fumées","Combustion","Formule"]},
  {id:"fed_e5_17",prompt:"La formule de puissance échangée par l\'AIR dans une CTA est :",choices:["Φ = ṁ × 4186 × ΔT","Φ = q × ρ × Cp_air × ΔT (q en m³/s, ρ_air ≈ 1,2 kg/m³, Cp_air ≈ 1005 J/kg·K)","Φ = Q × ΔP","Φ = v × S × ΔT"],answer:1,diff:2,explication:"Puissance air : Φ(W) = q(m³/s) × 1,2(kg/m³) × 1005(J/kg·K) × ΔT(K). Le produit ρ × Cp_air ≈ 1206 J/(m³·K). Débit volumique air q = v(m/s) × S(m²) section de gaine. Application batterie chaude CTA : mesurer T_air_entrée et T_air_sortie, débit avec anémomètre → calculer Φ_air et comparer à Φ_eau (C8-3).",tags:["E5","CTA","Puissance air","Formule","Batterie chaude"]},
  {id:"fed_e5_18",prompt:"Le débit volumique d\'air dans une gaine se calcule par :",choices:["Q = ΔP / résistance aéraulique","Q = v × S (v = vitesse mesurée en m/s, S = section de gaine en m²)","Q = ṁ / ρ × temps","Q = Φ / (ρ × Cp × ΔT)"],answer:1,diff:1,explication:"Q(m³/s) = v(m/s) × S(m²). v mesurée avec anémomètre (hélice pour sections importantes, fil chaud pour faibles vitesses). S calculée à partir des dimensions de la gaine (section rectangulaire S = L × l, circulaire S = π × D²/4). Appliquer ensuite Φ = q × ρ × Cp × ΔT pour la puissance batterie côté air.",tags:["E5","CTA","Débit air","Anémomètre","Section de gaine"]},
  {id:"fed_e5_19",prompt:"Pour un débit de fioul de 3,213 kg/h et un PCI_FOD = 41 992 kJ/kg, la puissance absorbée par la chaudière est :",choices:["37,5 W","3 750 W","37 457 W ≈ 37,5 kW","375 kW"],answer:2,diff:2,explication:"qm = 3,213 kg/h = 3,213/3600 = 0,000892 kg/s. Φ_abs = 0,000892 × 41 992 000 J/kg = 37 457 W ≈ 37,5 kW. Ce calcul correspond au sujet Régulation ECBT 2026 : gicleur 1 Usgal/h → 3,78 L/h × 0,85 (densité) = 3,213 kg/h. Comparer ensuite à la puissance nominale constructeur de la chaudière.",tags:["E5","Fioul","Puissance absorbée","FOD","Calcul"]},
  {id:"fed_e5_20",prompt:"Pour obtenir une puissance de 30 kW avec ΔT = 10°C côté eau, quel débit massique faut-il ?",choices:["3 kg/s","0,717 kg/s (Φ = ṁ × Cp × ΔT → ṁ = 30 000 / (4186 × 10) = 0,717 kg/s = 2 580 L/h)","7,17 kg/s","71,7 kg/s"],answer:1,diff:2,explication:"ṁ = Φ / (Cp × ΔT) = 30 000 / (4186 × 10) = 0,717 kg/s = 717 L/h × 3,6 = 2 580 L/h. C\'est le type de calcul demandé en TP2 2026 : \'indiquer le réglage de la vanne TA pour 30 kW avec ΔT = 10°C\'. Une fois le débit calculé, on lit l\'abaque TA pour régler la vanne.",tags:["E5","Calcul","Débit massique","Vanne TA","CTA","Puissance"]},
  {id:"fed_e5_21",prompt:"Les données de référence températures extérieures à mémoriser pour E5 sont :",choices:["Hiver -10°C (HR 80%), Été 30°C (HR 50%)","Hiver -4°C (HR 90%), Été 35°C (HR 40%), T_int hiver 20°C, T_int été 26°C","Hiver 0°C, Été 35°C","Hiver -5°C, Été 40°C"],answer:1,diff:2,explication:"Données de référence E5 (Cep_ref = 58,4 kWhep/m²/an) : T_ext_hiver = -4°C (HR 90%), T_ext_été = 35°C (HR 40%), T_int_hiver = 20°C, T_int_été = 26°C. Attention : la T° ext de base pour le dimensionnement d\'une installation spécifique peut différer (ex : -5°C dans le sujet Régulation ECBT 2026).",tags:["E5","Données de référence","Température de base","Psychrométrie"]},
  {id:"fed_e5_22",prompt:"La conversion d\'un débit en L/h vers m³/h est :",choices:["Diviser par 100","Diviser par 1 000","Diviser par 1 000 (1 L = 0,001 m³ = 1 dm³)","Multiplier par 1 000"],answer:2,diff:1,explication:"1 L = 0,001 m³ = 1 dm³. Donc 1 000 L/h = 1 m³/h. Erreur fréquente en E5 : utiliser L/h directement dans Φ = ṁ × Cp × ΔT sans convertir. La conversion complète : L/h → kg/s = diviser par 3 600 (car ρ_eau = 1 kg/L). Exemple : 720 L/h = 720/3600 = 0,2 kg/s.",tags:["E5","Conversions","Unités","Débit","Erreur fréquente"]},
  {id:"fed_e5_23",prompt:"Comment calculer la puissance thermique à partir des mesures côté eau d\'un échangeur ?",choices:["Φ = ΔT / Cp","Φ = ṁ × Cp × ΔT (avec ṁ en kg/s mesuré par débitmètre, ΔT = T_entrée − T_sortie)","Φ = ṁ² × Cp","Φ = ṁ × ΔT uniquement"],answer:1,diff:1,explication:"Φ = ṁ × Cp × ΔT. Mesures nécessaires : débit Q (débitmètre PCE-HAWA30 → convertir en kg/s), température entrée et sortie (thermomètre de contact ou TESTO 922). ΔT = T_entrée_eau_chaude − T_sortie_eau_chaude. Même formule côté eau froide (vérification bilan énergétique de l\'échangeur).",tags:["E5","Échangeur","Bilan thermique","Calcul","Mesures"]},
  {id:"fed_e5_24",prompt:"Si l\'on mesure Φ_utile_eau = 32 kW et Φ_absorbée_chaudière = 37,5 kW, le rendement est :",choices:["85,3% (32/37,5 × 100 = 85,3%)","117%","37,5%","32%"],answer:0,diff:2,explication:"η = Φ_utile / Φ_absorbée × 100 = 32/37,5 × 100 = 85,3%. C\'est un rendement typique d\'une chaudière fioul basse température standard. Une chaudière condensation atteint η > 100% (PCI) car elle récupère la chaleur latente de condensation des fumées. Interpréter : l\'écart vs constructeur (ex: 88%) = 2,7 points → expliquer causes.",tags:["E5","Rendement","Chaudière","Calcul","C8-3"]},
  {id:"fed_e5_25",prompt:"Quelle est la valeur du produit ρ_air × Cp_air utile pour les calculs CTA ?",choices:["4186 J/(m³·K)","1206 J/(m³·K) (ρ_air ≈ 1,2 kg/m³ × Cp_air ≈ 1005 J/kg·K = 1206 J/m³·K)","2500 J/(m³·K)","760 J/(m³·K)"],answer:1,diff:2,explication:"ρ_air × Cp_air ≈ 1,2 × 1005 = 1206 J/(m³·K). Donc Φ(W) = q(m³/s) × 1206 × ΔT(K). Permet de calculer rapidement la puissance batterie côté air sans passer par le débit massique. Exemple : q = 0,5 m³/s, ΔT = 20 K → Φ = 0,5 × 1206 × 20 = 12 060 W = 12,1 kW.",tags:["E5","CTA","Air","Puissance","Calcul rapide"]},
  {id:"fed_e5_26",prompt:"Le PCI du Fioul Domestique (FOD) est :",choices:["10,2 kWh/m³N","11,89 kWh/kg (PCI_FOD ≈ 41 992 kJ/kg)","44 780 kJ/kg (c\'est le PCS)","25,4 kWh/m³N"],answer:1,diff:2,explication:"FOD : PCS = 44 780 kJ/kg ≈ 12,44 kWh/kg, PCI = 41 992 kJ/kg ≈ 11,66 kWh/kg. La différence PCS-PCI correspond à la chaleur latente de vaporisation de l\'eau contenue dans les fumées (≈ 6% pour le fioul). Les chaudières condensation récupèrent cette énergie, d\'où η PCI > 100%.",tags:["E5","Fioul","FOD","PCI","PCS","Combustibles"]},
  {id:"fed_e5_27",prompt:"Le PCI du gaz naturel type LACQ est :",choices:["10,2 kWh/m³N (= 36 720 kJ/m³N) — valeur standard à mémoriser","41 992 kJ/kg","44 780 kJ/kg","25,4 kWh/m³N"],answer:0,diff:2,explication:"Gaz naturel type LACQ : PCI = 10,2 kWh/m³N, PCS = 11,3 kWh/m³N. Rapport PCS/PCI = 0,90 (10% de différence). CO₂ max = 11,8% (stœchiométrie). Air théorique = 9,7 m³/m³N. Pour le propane commercial : PCI = 25,4 kWh/m³N. Pour le butane : PCI = 32,9 kWh/m³N.",tags:["E5","Gaz naturel","PCI","Combustibles","LACQ"]},
  {id:"fed_e5_28",prompt:"Le CO₂ maximum lors de la combustion stœchiométrique du fioul domestique est :",choices:["11,8%","15,25% — valeur caractéristique du FOD (à retenir)","21%","28,3%"],answer:1,diff:2,explication:"CO₂ max FOD = 15,25% (combustion stœchiométrique, sans excès d\'air). En pratique avec excès d\'air : CO₂ mesuré < CO₂ max. Pour gaz naturel LACQ : CO₂ max = 11,8%. Propane : 21,6%. Butane : 28,3%. Plus l\'excès d\'air est élevé, plus CO₂ diminue et O₂ augmente dans les fumées.",tags:["E5","CO2","Combustion","Fioul","Analyse combustion"]},
  {id:"fed_e5_29",prompt:"L\'indice de Bacharach mesure dans l\'analyse de combustion d\'une chaudière fioul :",choices:["La température des fumées","Le taux d\'imbrûlés (suies) dans les fumées — spécifique au fioul (0 = propre, 9 = encrassé)","La teneur en O₂","La pression du brûleur"],answer:1,diff:2,explication:"Indice de Bacharach = 0 (propre) à 9 (très encrassé, suies). Mesuré avec une pompe d\'aspiration et un filtre. Valeur acceptable ≤ 1 pour un brûleur bien réglé. Si > 2 : risque d\'encrassement du générateur, pertes thermiques augmentées, émissions de particules. Uniquement pour le fioul (pas utilisé pour le gaz).",tags:["E5","Bacharach","Fioul","Imbrûlés","Analyse combustion"]},
  {id:"fed_e5_30",prompt:"Le CO (monoxyde de carbone) dans les fumées est dangereux car :",choices:["Il corrode les canalisations","Il se fixe sur l\'hémoglobine 200 fois plus que l\'O₂, provoquant l\'hypoxie cérébrale — inodore et incolore → mortel","Il augmente le rendement de la chaudière","Il est inflammable uniquement"],answer:1,diff:1,explication:"CO : gaz inodore, incolore, mortel par asphyxie. Affinité avec l\'hémoglobine × 200 > O₂ → carboxyhémoglobine → hypoxie. Seuils : 35 ppm (exposition 8h), 200 ppm (malaise en 2-3h), 1600 ppm (mort en 2h). Détecteur CO obligatoire en présence de chaudière. CO > 100 ppm dans les fumées = combustion imparfaite.",tags:["E5","CO","Sécurité","Combustion","Danger"]},
  {id:"fed_e5_31",prompt:"La formule du débit de fioul au gicleur selon le sujet Régulation ECBT 2026 est :",choices:["Débit = Calibre × Pression","Débit [L/h] = Calibre [Usgal/h] × 3,78 × (Pression [bar] / 7)^0,5","Débit = Calibre × 3,78 uniquement","Débit = Calibre [L/h] × densité"],answer:1,diff:3,explication:"Débit fioul [L/h] = Calibre [Usgal/h] × 3,78 × (P[bar] / 7)^0,5. Pour gicleur 1 Usgal/h à 7 bar : débit = 1 × 3,78 × (7/7)^0,5 = 1 × 3,78 × 1 = 3,78 L/h. À 10 bar : 3,78 × (10/7)^0,5 = 3,78 × 1,195 = 4,51 L/h. 3,78 est le facteur de conversion Usgal → litres.",tags:["E5","Gicleur","Fioul","Débit","Calcul","Brûleur"]},
  {id:"fed_e5_32",prompt:"Pour un gicleur de calibre 1 Usgal/h à 7 bar avec une densité fioul de 0,85, le débit massique en kg/h est :",choices:["3,78 kg/h","3,21 kg/h (3,78 L/h × 0,85 kg/L = 3,213 kg/h)","4,45 kg/h","0,85 kg/h"],answer:1,diff:2,explication:"Débit volumique = 3,78 L/h (calculé avec formule gicleur). Débit massique = 3,78 × 0,85 = 3,213 kg/h. Conversion en kg/s : 3,213 / 3600 = 0,000892 kg/s. Puissance absorbée = 0,000892 × 41 992 000 = 37 457 W ≈ 37,5 kW. C\'est le calcul de référence du sujet Régulation ECBT 2026.",tags:["E5","Gicleur","Fioul","Débit massique","Calcul"]},
  {id:"fed_e5_33",prompt:"Quelle est la différence entre PCS et PCI d\'un combustible ?",choices:["PCS est toujours inférieur au PCI","PCS > PCI. La différence correspond à la chaleur latente de vaporisation de l\'eau dans les fumées. Les chaudières à condensation récupèrent cette énergie","PCS = PCI pour le gaz naturel","Il n\'y a pas de différence pratique"],answer:1,diff:2,explication:"PCS (Pouvoir Calorifique Supérieur) > PCI (Inférieur). La différence = chaleur latente de l\'eau de combustion (condensation de H₂O). Pour FOD : PCS-PCI ≈ 2 788 kJ/kg (≈ 6%). Pour gaz naturel : PCS-PCI ≈ 1 100 kJ/m³N (≈ 10%). Chaudière condensation : récupère cette chaleur → η PCI peut dépasser 100% (normal et correct).",tags:["E5","PCS","PCI","Condensation","Combustibles"]},
  {id:"fed_e5_34",prompt:"En analyse de combustion, un taux d\'O₂ élevé (ex: 8%) dans les fumées signifie :",choices:["Combustion incomplète dangereuse","Excès d\'air important → augmentation des pertes par les fumées → baisse du rendement chaudière","Combustion parfaite stœchiométrique","Présence de CO dangereux"],answer:1,diff:2,explication:"O₂ élevé dans fumées = trop d\'air injecté (excès d\'air important). Conséquences : (1) fumées plus abondantes et chaudes → pertes Siegert augmentent, (2) rendement chaudière baisse, (3) risque de condensation acide si T_fumées trop basse avec excès d\'air. Réglage optimal : O₂ ≈ 3-4% gaz, 4-5% fioul (selon constructeur).",tags:["E5","O2","Excès d\'air","Combustion","Rendement"]},
  {id:"fed_e5_35",prompt:"La composition du FOD (Fioul Domestique) selon les annales 2026 est :",choices:["100% méthane (CH4)","C≈84,3%, H≈12,4%, O≈2%, S≈0,5%, N≈0,8% — mélange d\'hydrocarbures","75% propane, 25% butane","50% méthane, 50% éthane"],answer:1,diff:3,explication:"FOD : C 84,3%, H 12,4%, O 2%, S 0,5%, N 0,8%. PCS = 44 780 kJ/kg, PCI = 41 992 kJ/kg. La teneur en soufre (0,5%) génère SO₂ dans les fumées → risques de corrosion acide si T_fumées < point de rosée acide (~140°C pour fioul). Le soufre est une des raisons pour lesquelles la condensation pour chaudière fioul est plus délicate que pour le gaz.",tags:["E5","FOD","Composition","Combustibles","Soufre"]},
  {id:"fed_e5_36",prompt:"L\'analyseur de combustion doit être placé :",choices:["En amont du brûleur","Dans la boîte à feu de la chaudière","Dans le conduit de fumées après la chaudière, dans la zone des gaz de combustion","Au niveau du gicleur"],answer:2,diff:1,explication:"Sonde de l\'analyseur = dans le conduit de fumées, zone de gaz chauds issus de la combustion. Mesure O₂, CO₂, CO, T_fumées. T_air (température du local) saisie séparément. La sonde doit être dans le flux de fumées sans aspirer d\'air parasite (risque de faux résultat). Durée de mesure : attendre la stabilisation des valeurs affichées.",tags:["E5","Analyseur combustion","Positionnement","Mesure","Technique"]},
  {id:"fed_e5_37",prompt:"Pour une chaudière gaz, quel est le signe d\'une combustion incomplète ?",choices:["CO₂ trop élevé","CO (monoxyde de carbone) détecté > 100 ppm dans les fumées — risque intoxication","O₂ trop faible uniquement","Température de fumées trop haute uniquement"],answer:1,diff:1,explication:"Combustion incomplète : CO présent dans fumées (manque d\'O₂ ou mauvais mélange air/gaz). Seuil d\'alerte : CO > 100 ppm → risque d\'intoxication. CO > 300 ppm → arrêt impératif et ventilation. Causes : gicleur encrassé, défaut d\'amenée d\'air, brûleur mal réglé. A signaler immédiatement au jury et proposer action corrective (C8-4).",tags:["E5","CO","Combustion incomplète","Sécurité","Gaz"]},
  {id:"fed_e5_38",prompt:"Le PCI du gaz naturel LACQ en kJ/m³N est :",choices:["41 992 kJ/m³N","36 720 kJ/m³N (10,2 kWh/m³N × 3 600 kJ/kWh = 36 720 kJ/m³N)","44 780 kJ/m³N","10 200 kJ/m³N"],answer:1,diff:2,explication:"PCI_GN = 10,2 kWh/m³N × 3600 kJ/kWh = 36 720 kJ/m³N. Conversion : 1 kWh = 3600 kJ. Utile pour calculer : Φ_abs = q_gaz (m³N/s) × 36 720 000 J/m³N. Volume molaire normal (m³N) = à 0°C et 1 atm. À utiliser dans les calculs de puissance absorbée chaudière gaz.",tags:["E5","Gaz naturel","PCI","Conversion","Kj/m³N"]},
  {id:"fed_e5_39",prompt:"Un brûleur fioul avec une pression de pulvérisation de 28 bar (au lieu de 7 bar) aura un débit :",choices:["4 fois plus important (×4)","2 fois plus important (×2) car débit ∝ √Pression : √(28/7) = √4 = 2","Identique à 7 bar","8 fois plus important"],answer:1,diff:3,explication:"Formule gicleur : débit ∝ √(P/7). √(28/7) = √4 = 2. Donc le débit double quand la pression quadruple. Pour gicleur 1 Usgal/h : 3,78 L/h à 7 bar → 7,56 L/h à 28 bar. La pression de pulvérisation influe sur l\'atomisation du fioul (fines gouttelettes) et donc la qualité de combustion.",tags:["E5","Gicleur","Pression","Débit","Calcul"]},
  {id:"fed_e5_40",prompt:"Lors d\'un bilan combustion, à quoi correspond l\'excès d\'air (λ) ?",choices:["Rapport PCS/PCI du combustible","Rapport entre l\'air réel injecté et l\'air théorique stœchiométrique (λ = 1 → stœchiométrie, λ > 1 → excès d\'air)","Le taux de CO₂ mesuré","La température des fumées"],answer:1,diff:2,explication:"λ (lambda) = air réel / air théorique. λ = 1 : combustion stœchiométrique (idéal théorique). λ > 1 : excès d\'air (pertes fumées ↑ mais sécurité CO). λ < 1 : manque d\'air → CO dangereux. En pratique : λ ≈ 1,1 à 1,3 pour les chaudières. Plus λ élevé → plus O₂ dans fumées, moins CO₂ mesuré.",tags:["E5","Excès d\'air","Lambda","Combustion","Stœchiométrie"]},
  {id:"fed_e5_41",prompt:"Dans le sujet TP2 2026 (CTA plateforme 014), quelle est la mission principale ?",choices:["Faire le bilan d\'une chaudière fioul","Déterminer la puissance de la batterie chaude de la CTA en mesurant le débit et les températures ECBT","Régler les volets d\'air neuf","Paramétrer le Kistock RF uniquement"],answer:1,diff:1,explication:"TP2 2026 : vérifier le fonctionnement de la CTA (plateforme 014), déterminer la puissance de la batterie chaude. Méthode : mesurer débit ECBT (débitmètre TA), mesurer T° entrée/sortie ECBT (TESTO 922 ou thermomètres GESA), calculer Φ = ṁ × Cp × ΔT, comparer aux données constructeur (C8-3). La V3V doit être à 100% d\'ouverture pour les mesures nominales.",tags:["E5","TP2","CTA","Batterie chaude","ECBT"]},
  {id:"fed_e5_42",prompt:"ECBT signifie dans le contexte E5 :",choices:["Eau Chaude Basse Tension","Eau Chaude Basse Température — réseau de distribution d\'eau chaude (35-90°C selon installation)","Équipement de Climatisation Basse Température","Échangeur de Chaleur Basse Technicité"],answer:1,diff:1,explication:"ECBT = Eau Chaude Basse Température. Réseau hydraulique distribuant l\'eau chaude du générateur (chaudière, PAC) vers les émetteurs (radiateurs, planchers chauffants, batteries CTA). Régime typique : 60/40°C (T_départ/T_retour), 70/50°C, 80/60°C. Les nouvelles installations PAC utilisent 35-45°C pour optimiser le COP.",tags:["E5","ECBT","Vocabulaire","Réseau hydraulique"]},
  {id:"fed_e5_43",prompt:"La vanne V3V (3 voies) montée sur une batterie chaude de CTA sert à :",choices:["Couper l\'alimentation électrique de la batterie","Réguler la puissance de la batterie en mélangeant eau chaude et eau de retour (régulation proportionnelle de T°)","Mesurer le débit d\'eau","Purger le circuit"],answer:1,diff:2,explication:"V3V mélangeuse : 3 voies = arrivée eau chaude (A), retour eau de retour (B), départ vers batterie (AB). En modulant l\'ouverture A/B, on règle la T° départ batterie. Pour mesure nominale en E5 : V3V à 100% position A (eau chaude maximale) → puissance batterie maximale. Régulation GTC : actionneur motorisé 0-10V ou TOR sur la V3V.",tags:["E5","V3V","Vanne 3 voies","CTA","Batterie","Régulation"]},
  {id:"fed_e5_44",prompt:"Le TESTO 922 est un appareil de mesure utilisé en E5 TP2. Il mesure :",choices:["Uniquement la vitesse d\'air","La température de 2 sondes simultanément (thermomètre différentiel 2 canaux, thermocouple type K, plage -50 à +1000°C)","La combustion (O2, CO2, CO)","Le débit volumique d\'eau"],answer:1,diff:2,explication:"TESTO 922 : thermomètre 2 canaux, thermocouple type K, plage -50 à +1000°C, précision ±(0,5°C + 0,3%). Avantages : mesure simultanée T_entrée et T_sortie, affichage de la différentielle ΔT directement, impression cyclique des valeurs. Idéal pour bilan échangeur ou batterie. Sonde radio optionnelle. Autonomie batterie 200h sans rétro-éclairage.",tags:["E5","TESTO 922","Appareils de mesure","Thermomètre","TP2"]},
  {id:"fed_e5_45",prompt:"Les thermomètres fixes GESA présents dans les installations E5 sont :",choices:["Des capteurs électroniques PT100","Des thermomètres à dilatation de liquide (alcool ou mercure) en verre, montés en fixe sur les tuyauteries — précision ±1°C à ±2°C selon la plage","Des pyromètres infrarouges","Des thermocouples type J uniquement"],answer:1,diff:2,explication:"GESA : thermomètres mécaniques à dilatation de liquide (alcool bleu ou rouge pour T<200°C, mercure pour T>200°C). Plages : -60/0/+60 à -60/0/+600°C. Précision : ±1 division (selon plage). Montage : droite, 90° ou 135°. En E5 TP2 : estimer l\'incertitude sur les mesures de T° fixes (écart type ≈ ±2°C sur plage standard). À considérer dans l\'analyse d\'incertitude de Φ.",tags:["E5","GESA","Thermomètre fixe","Incertitude","TP2"]},
  {id:"fed_e5_46",prompt:"Pour corriger la mesure de débit de la vanne TA avec un fluide autre que l\'eau à 20°C, il faut :",choices:["Multiplier par la masse volumique","Diviser le débit affiché par √(masse volumique en t/m³)","Multiplier par la viscosité","Aucune correction n\'est nécessaire"],answer:1,diff:3,explication:"Correction vanne TA : débit_réel = débit_CBI / √(γ) avec γ = masse volumique en t/m³. Exemple : eau glycolée 30% à 20°C, γ ≈ 1,04 t/m³ → débit_réel = débit_CBI / √1,04 = débit_CBI / 1,02 (correction de 2%). La viscosité augmente aux basses températures → risque d\'écoulement laminaire → erreur de mesure plus importante sur petits diamètres.",tags:["E5","Vanne TA","Correction débit","Eau glycolée","Métrologie"]},
  {id:"fed_e5_47",prompt:"L\'abaque de la vanne TA permet de déterminer :",choices:["La pression de service maximale","La position de réglage (nombre de tours) en fonction du débit et de la perte de charge souhaitée (Kv)","La température maximale du fluide","Le type de raccordement"],answer:1,diff:2,explication:"Abaque TA (nomogramme) : 3 échelles (débit en m³/h ou L/s, Kv, perte de charge en kPa). Une droite relie les 3 échelles. Kv = 0,01 × q/√ΔP (q en L/h, ΔP en kPa) ou Kv = 36 × q/√ΔP (q en L/s). Lire position de réglage (nombre de tours) sur l\'échelle correspondant au DN de la vanne. Application E5 : régler la vanne pour obtenir le débit nominal.",tags:["E5","Vanne TA","Abaque","Kv","Débit","Réglage"]},
  {id:"fed_e5_48",prompt:"Dans une CTA, la batterie froide produit de l\'eau glacée à :",choices:["0°C/4°C","7°C/12°C (eau glacée standard pour le tertiaire — produite par groupe frigorifique ou chiller)","15°C/20°C","25°C/30°C"],answer:1,diff:1,explication:"Eau glacée standard tertiaire : 7°C départ / 12°C retour (ΔT = 5K). Certains bâtiments utilisent 6/12°C ou 14/18°C (free cooling). La CTA refroidit et déshumidifie l\'air en le faisant passer sur la batterie froide (T° batterie < T° de rosée de l\'air → condensation de l\'humidité). Drains obligatoires sous batterie froide.",tags:["E5","CTA","Batterie froide","Eau glacée","7/12°C"]},
  {id:"fed_e5_49",prompt:"Lors du bilan d\'une CTA, pourquoi faut-il effectuer les mesures à la fois côté eau ET côté air ?",choices:["Pour doubler la précision uniquement","Pour vérifier l\'équilibre énergétique (Φ_eau ≈ Φ_air) — un écart important révèle une fuite ou une erreur de mesure (C8-3)","Les mesures côté air sont optionnelles","Pour calculer la pression de service"],answer:1,diff:2,explication:"Bilan batterie : Φ_eau = ṁ_eau × Cp_eau × ΔT_eau et Φ_air = q_air × ρ_air × Cp_air × ΔT_air. Si Φ_eau ≈ Φ_air (écart < 10%) → mesures cohérentes. Si écart important → erreur de mesure ou déperditions. Ce double calcul démontre la maîtrise de C8-1 (procédure logique) et C7-6 (interprétation des résultats).",tags:["E5","CTA","Bilan double","Équilibre","C8-1","Méthodo"]},
  {id:"fed_e5_50",prompt:"Pour le diagramme de l\'air humide en E5 (sujet CTA), quels paramètres doit-on mesurer et reporter ?",choices:["Uniquement la température sèche","Température sèche (T_s) ET humidité relative (HR) ou température humide — pour les points extérieur, soufflage et reprise","Uniquement la pression","Débit d\'air uniquement"],answer:1,diff:2,explication:"Diagramme de l\'air humide (psychrométrique) : T_sèche en abscisse, teneur en eau (g/kg) en ordonnée. Reporter les points : air extérieur (T_ext, HR_ext), air soufflé (T_soufflage, HR_soufflage), air repris (T_reprise, HR_reprise). Lire : enthalpie (kJ/kg), teneur eau, T° rosée, énergie échangée. Mesures : thermo-hygromètre (T + HR) aux 3 positions.",tags:["E5","Diagramme air humide","CTA","Psychrométrie","Mesures"]},
  {id:"fed_e5_51",prompt:"Pourquoi la V3V doit-elle être à 100% d\'ouverture côté eau chaude pour la mesure de puissance nominale ?",choices:["Pour économiser l\'énergie","Pour avoir le débit et la température maximum → puissance maximale → comparaison valide avec la puissance nominale constructeur (C8-2)","Pour réduire les pertes de charge","Pour éviter les bulles d\'air"],answer:1,diff:2,explication:"Puissance nominale constructeur = mesurée à 100% d\'ouverture (conditions nominales). Si V3V partiellement ouverte → T° entrée batterie plus basse, puissance réduite → comparaison invalide. En E5 TP2 2026 : \'la batterie chaude alimentée à 100% d\'ouverture de la V3V\'. Ce détail démontre la compréhension de C8-2 (paramètres pertinents).",tags:["E5","V3V","Mesure nominale","CTA","C8-2"]},
  {id:"fed_e5_52",prompt:"La Centrale de Traitement d\'Air (CTA) contient dans son caisson, dans l\'ordre d\'entrée de l\'air neuf :",choices:["Batterie → Filtre → Ventilateur → Batterie","Filtration → Batterie froide ou chaude → Ventilateur de soufflage (ordre standard)","Ventilateur → Filtre → Batterie","Batterie → Ventilateur → Filtre"],answer:1,diff:2,explication:"Ordre standard CTA soufflage : (1) Filtre (G4 puis F7), (2) Batterie chaude (préchauffage hiver) ou froide (refroidissement été), (3) Humidificateur (si besoin), (4) Ventilateur de soufflage. Pour double flux : échangeur récupérateur avant filtration. En E5 TP2 schéma CTA : repérer chaque composant et le légender (nomenclature C7-3).",tags:["E5","CTA","Composants","Filtre","Batterie","Ventilateur"]},
  {id:"fed_e5_53",prompt:"Quel instrument utiliser pour mesurer la vitesse d\'air dans une gaine de CTA (section importante, grande gaine) ?",choices:["Thermomètre laser","Anémomètre à hélice — adapté aux vitesses 0,5-20 m/s dans les grandes sections","Anémomètre à fil chaud uniquement","Débitmètre PCE-HAWA30"],answer:1,diff:1,explication:"Anémomètre à hélice : vitesse 0,5-20 m/s, idéal grandes sections de gaines. Anémomètre à fil chaud : faibles vitesses (< 1 m/s), grande précision, petites sections ou turbulences. Pour CTA classique (vitesse 4-8 m/s en galerie principale) → hélice. Mesure en plusieurs points de la section (méthode des surfaces égales) pour éviter les effets de bord.",tags:["E5","Anémomètre","CTA","Vitesse air","Appareils de mesure","C7-5"]},
  {id:"fed_e5_54",prompt:"L\'IAQ-CALC 7515 est utilisé en E5 pour :",choices:["Mesurer le débit d\'eau","Mesurer la qualité de l\'air intérieur (CO₂ en ppm, T°, HR) — sujet CTA, contrôle qualité air pièce desservie","Analyser la combustion","Enregistrer les données sans fil"],answer:1,diff:2,explication:"IAQ-CALC 7515 (Indoor Air Quality calculator) : mesure CO₂ (ppm), T° (°C), HR (%). Seuils CO₂ : < 800 ppm (IDA2, très bonne qualité), < 1000 ppm (IDA3, bonne qualité), > 1500 ppm (mauvaise qualité). Utilisé pour valider le débit d\'air neuf de la CTA (C8-3 : comparer à la réglementation DTU 68.3 / NF EN 13779).",tags:["E5","IAQ-CALC","Qualité air","CO2","CTA","C6"]},
  {id:"fed_e5_55",prompt:"Lors du bilan d\'une batterie chaude (TP2), l\'erreur possible sur la mesure de puissance due aux thermomètres GESA (±2°C) est :",choices:["Négligeable dans tous les cas","Significative si ΔT_mesuré est faible (ex: ΔT=10°C → incertitude ±40% sur ΔT si erreur totale ±4°C)","Toujours inférieure à 1%","Ne concerne pas les calculs de puissance"],answer:1,diff:3,explication:"Incertitude GESA ±2°C. Si T_entrée = 70±2°C et T_sortie = 60±2°C → ΔT = 10°C avec incertitude maximale ±4°C → incertitude relative ±40%. Puissance Φ = ṁ × Cp × ΔT → même incertitude sur Φ. En E5 TP2 : \'indiquer l\'erreur possible sur les mesures de température → incertitude sur la puissance calculée\'. Recommandation : utiliser TESTO 922 (±0,5°C) pour réduire l\'incertitude.",tags:["E5","Incertitude","GESA","Métrologie","TP2","Erreur de mesure"]},
  {id:"fed_e5_56",prompt:"Le régulateur Siemens RMH760B utilisé dans le sujet Régulation ECBT 2026 pilote :",choices:["Uniquement la VMC","La marche du brûleur + la régulation de puissance du réseau de radiateurs via loi d\'eau glissante","Uniquement l\'ECS","Uniquement le Kistock RF"],answer:1,diff:2,explication:"RMH760B : régulateur de chauffage Siemens. Fonctions : pilotage brûleur (marche/arrêt), loi d\'eau glissante (T_départ réseau en fonction de T_ext), programme horaire (confort/réduit), protection anti-gel, protection chaudière. Paramétrage via logiciel ACS ou touches frontales. Communication : LPB (Local Process Bus) pour extension modules.",tags:["E5","RMH760B","Siemens","Régulation","GTC","Chauffage"]},
  {id:"fed_e5_57",prompt:"Le schéma de régulation H3-2 du RMH760B correspond à :",choices:["Régulation ECS uniquement","Circuit chaudière + 1 circuit chauffage avec vanne mélangeuse (schéma standard pour radiateurs avec V3V)","Régulation de 3 circuits indépendants","Régulation solaire uniquement"],answer:1,diff:3,explication:"H3-2 : schéma hydraulique type avec générateur (chaudière) + 1 circuit secondaire régulé par vanne mélangeuse 3 voies. Le régulateur pilote : (1) le brûleur selon la T° chaudière, (2) la V3V selon la loi d\'eau (T_départ réseau fonction T_ext). Sonde extérieure locale obligatoire pour la loi d\'eau glissante.",tags:["E5","H3-2","RMH760B","Schéma hydraulique","V3V"]},
  {id:"fed_e5_58",prompt:"La \'droite de chauffe\' (loi d\'eau glissante) relie :",choices:["T_départ réseau et T_retour réseau","T_départ réseau (en ordonnée) et T_extérieure (en abscisse) — plus il fait froid dehors, plus T_départ est élevée","T_chaudière et débit pompe","T_intérieure consigne et T_extérieure"],answer:1,diff:2,explication:"Droite de chauffe : T_départ_réseau = f(T_ext). Exemple régime 60/40 : à T_ext = -5°C → T_départ = 60°C, à T_ext = +15°C → T_départ ≈ 30°C (limite coupure chauffe). La pente (ex: 1,5) définit la sensibilité. Paramétré dans RMH760B. En E5 : tracer cette droite + graphe TOR du pilote chaudière avec les préréglages Siemens.",tags:["E5","Droite de chauffe","Loi d\'eau","RMH760B","Régulation","Courbe de chauffe"]},
  {id:"fed_e5_59",prompt:"Pour le sujet Régulation ECBT 2026, le régime fluide caloporteur est 60/40. Que signifie-t-il ?",choices:["60°C en été, 40°C en hiver","T_départ = 60°C et T_retour = 40°C — ΔT réseau = 20°C","Débit 60 L/h avec 40% de glycol","60 bar de pression, 40°C minimum"],answer:1,diff:1,explication:"Régime 60/40 : T_départ = 60°C, T_retour = 40°C, ΔT = 20°C. Ces valeurs correspondent aux conditions nominales de dimensionnement (T_ext de base = -5°C dans ce sujet). À T_ext > T_ext_base : T_départ diminue selon la droite de chauffe. Pour radiateurs standard : 60/40 typique. Pour planchers chauffants : 35/28 ou 40/35 (mieux pour PAC).",tags:["E5","Régime 60/40","Loi d\'eau","Chauffage","Paramétrage"]},
  {id:"fed_e5_60",prompt:"Dans le sujet Régulation ECBT 2026, la saison de chauffe va du 12/10 au 28/03. Cela signifie pour le RMH760B :",choices:["Le régulateur est éteint en dehors de ces dates","Le programme de chauffe (mode confort/réduit) est actif uniquement du 12 octobre au 28 mars — paramétré dans l\'horloge du régulateur","La chaudière s\'arrête automatiquement ces jours-là","Aucune signification pour la régulation"],answer:1,diff:2,explication:"Le RMH760B intègre une horloge hebdomadaire et annuelle. Paramétrer : (1) Période de chauffe : 12/10 au 28/03, (2) Programme journalier : confort 7h-17h (T = 21°C), réduit reste (T = 18°C = 21-3°C d\'abaissement), (3) Anti-gel : 9°C en permanence même hors saison. La sonde extérieure détecte automatiquement les besoins selon T_ext.",tags:["E5","Saison de chauffe","RMH760B","Programmation","Horloge"]},
  {id:"fed_e5_61",prompt:"L\'abaissement de nuit de 3°C dans le sujet Régulation ECBT 2026 signifie :",choices:["La chaudière s\'arrête la nuit","La consigne de T° intérieure passe de 21°C à 18°C (21-3) en mode réduit — économie d\'énergie nocturne","La T° extérieure est réduite de 3°C","La loi d\'eau est décalée de 3°C"],answer:1,diff:1,explication:"Abaissement nuit (mode réduit) : T_consigne passe de 21°C (confort) à 18°C (= 21-3°C). Le régulateur recalcule la T_départ réseau pour maintenir 18°C intérieur selon la loi d\'eau. Économie estimée : 5-8% par °C d\'abaissement × heures réduites. Paramétrage RMH760B : réglage de l\'abaissement en °C dans les paramètres horaire.",tags:["E5","Abaissement nuit","Économie énergie","RMH760B","Consigne"]},
  {id:"fed_e5_62",prompt:"La consigne anti-gel de 9°C dans le sujet Régulation ECBT 2026 est active :",choices:["Uniquement en saison de chauffe","En permanence, y compris hors saison de chauffe — protège le bâtiment du gel même en été si vague de froid","Uniquement si T_ext < 0°C","Uniquement la nuit"],answer:1,diff:2,explication:"Anti-gel = protection permanente (toute l\'année, 24h/24). Si T_ext tombe sous un seuil bas (typiquement -5 à 0°C selon réglage), le régulateur déclenche automatiquement la chauffe pour maintenir T_int ≥ 9°C, même en intersaison. Paramétré dans RMH760B indépendamment du programme horaire. Essentiel pour éviter le gel des canalisations.",tags:["E5","Anti-gel","RMH760B","Protection","Hors saison"]},
  {id:"fed_e5_63",prompt:"Le LPB (Local Process Bus) du régulateur RMH760B est :",choices:["Un port USB pour connexion PC","Un bus de communication propriétaire Siemens permettant de cascader plusieurs régulateurs et modules (ex: RMZ781)","Une interface KNX standard","Une liaison série RS232"],answer:1,diff:3,explication:"LPB (Local Process Bus) = bus propriétaire Siemens. Permet : connexion du module d\'extension RMZ781, cascade de régulateurs (générateur esclave), communication entre régulateurs de différentes zones. Dans le sujet 2026 : ordinateur avec passerelle KNX et LPB + logiciel ACS pour le paramétrage et la supervision (C6).",tags:["E5","LPB","RMH760B","Bus","Siemens","Communication"]},
  {id:"fed_e5_64",prompt:"Pour vérifier le bon fonctionnement de la régulation à T_ext = -5°C (sujet Régulation ECBT 2026), qu\'observe-t-on sur la GTC ?",choices:["La chaudière doit être à l\'arrêt","T_départ réseau = 60°C (régime nominal), brûleur actif, pompe circulateur active, V3V en position correspondante","T_départ = 30°C uniquement","La V3V doit être fermée"],answer:1,diff:2,explication:"À T_ext = -5°C (T_ext de base) : T_départ_réseau = 60°C (régime nominal 60/40), chaudière en marche (consigne 70°C), pompe circulateur active, V3V mélangeuse en position maximale eau chaude. À T_ext = 5°C : T_départ réduit (≈ 50°C selon pente). À T_ext = 15°C : T_départ très réduit ou arrêt si T_ext > T° limite de coupure (souvent 15-18°C).",tags:["E5","Régulation","GTC","Synoptique","Vérification","RMH760B"]},
  {id:"fed_e5_65",prompt:"Lors de l\'exploitation des résultats (partie 3 du sujet Régulation ECBT 2026), que faut-il calculer pour C8-3 ?",choices:["Uniquement la T° de départ réseau","Puissance absorbée (fioul) + Puissance restituée (eau) + Rendement — puis comparer à la puissance constructeur","La résistance des capteurs","Le débit gicleur uniquement"],answer:1,diff:1,explication:"Calculs obligatoires C8-3 : P_abs = qm_fioul × PCI_FOD, P_utile = ṁ_eau × Cp × ΔT, η = P_utile/P_abs × 100%. Puis comparer : η_mesuré vs η_constructeur, P_nominale constructeur vs P_calculée. Interpréter les écarts : vieillissement brûleur, encrassement échangeur, conditions d\'essai différentes. Proposer au moins 2 améliorations concrètes (C8-4).",tags:["E5","C8-3","Régulation ECBT","Rendement","Calculs","Exploitation"]},
  {id:"fed_e5_66",prompt:"Le logiciel ACS utilisé avec le RMH760B permet :",choices:["Uniquement de visualiser les températures","De paramétrer le régulateur, visualiser le synoptique GTC, modifier les consignes et lire les historiques (compétence C6 = 40% de la note)","De calculer automatiquement la puissance chaudière","De mesurer la combustion"],answer:1,diff:2,explication:"ACS (Automation & Control System) Siemens : logiciel de paramétrage et supervision pour régulateurs RMH/RVL. Fonctions : saisie de tous les paramètres (programme horaire, pentes, consignes), synoptique animé (visualisation en temps réel), historiques, alarmes. En E5 : c\'est l\'outil numérique C6 (40% note). Maîtriser la navigation dans les menus = points assurés.",tags:["E5","ACS","C6","RMH760B","Siemens","Logiciel"]},
  {id:"fed_e5_67",prompt:"Un signal 4-20 mA entrant dans un automate GTC correspond à :",choices:["Un signal TOR (Tout Ou Rien)","Un signal analogique continu (4 mA = 0% = minimum mesure, 20 mA = 100% = maximum mesure) — typique des capteurs de T°, pression, débit","Un signal bus KNX","Un signal 0-10V uniquement"],answer:1,diff:2,explication:"4-20 mA = signal analogique industriel normalisé. 4 mA = valeur minimale (0%), 20 mA = valeur maximale (100%). Avantage : détection des pannes câble (0 mA ≠ mesure normale). Exemples capteurs : sonde T° 4-20 mA (0-100°C → 4-20 mA), débitmètre, pression différentielle. En E5 : identifier nature signal de chaque capteur sur le schéma électrique.",tags:["E5","4-20 mA","Signal analogique","Automate","GTC","Capteurs"]},
  {id:"fed_e5_68",prompt:"Le Kistock RF se configure dans quel ordre pour E5 ?",choices:["Enregistrement → Paramétrage → Intégration modules","(1) Intégrer les modules RF dans le réseau, (2) Paramétrer chaque voie (grandeur, unité, plage), (3) Lancer l\'enregistrement, (4) Exporter les données","Exporter → Paramétrer → Lancer","Il n\'y a pas d\'ordre particulier"],answer:1,diff:2,explication:"Séquence Kistock RF : (1) Intégration des modules dans le réseau RF (recherche automatique + validation), (2) Paramétrage des voies de mesure (T°, HR, unités, intervalles d\'enregistrement), (3) Test du réseau (vérifier réception des modules), (4) Lancement de l\'enregistrement, (5) En fin d\'épreuve : arrêt et export des données sur PC. Chaque étape correspond à un indicateur C6.",tags:["E5","Kistock RF","C6","Configuration","Procédure"]},
  {id:"fed_e5_69",prompt:"Pourquoi la tablette CozytouchC remplace le Kistock RF dans le sujet chaudière condensation Atlantic ?",choices:["Parce que le Kistock RF ne fonctionne pas avec le gaz","Parce que la chaudière Atlantic est pilotée via sa propre interface numérique (tablette connectée CozytouchC) — c\'est l\'outil numérique C6 spécifique à ce sujet","Parce que la tablette est moins chère","Parce que le Kistock RF mesure uniquement la combustion"],answer:1,diff:2,explication:"CozytouchC = tablette de pilotage connectée Atlantic pour chaudières condensation (Condensinox). Fonctions : paramétrage de la chaudière (courbe de chauffe, consignes, programmes), visualisation des données (T° départ, retour, fumées, compteur gaz), diagnostics. En E5 sujet condensation : c\'est l\'outil C6. Vérifier rendement ≥ 94% et conformité RT existant (Arrêté 3 mai 2007).",tags:["E5","CozytouchC","Atlantic","C6","Condensation","Tablette"]},
  {id:"fed_e5_70",prompt:"L\'Arrêté du 3 mai 2007 concerne en E5 :",choices:["La sécurité électrique des installations","La performance des équipements de chauffage en bâtiments existants (RT existant) — vérification du rendement à pleine charge et en intermittence","La réglementation des frigorigènes HFC","La norme KNX"],answer:1,diff:2,explication:"Arrêté du 3 mai 2007 (RT existant) : réglementation thermique pour les bâtiments existants. Exige notamment : rendement chaudière ≥ 90% (basse T°) ou ≥ 94% (condensation) en conditions d\'essai normalisées. En E5 sujet CTA : conformité Arrêté 3 mai 2007 pour les installations de traitement d\'air. En E5 sujet condensation Atlantic : vérification rendement ≥ 94%.",tags:["E5","Arrêté 3 mai 2007","RT existant","Rendement","Réglementation","Conformité"]},
  {id:"fed_e5_71",prompt:"Le débitmètre PCE-HAWA30 mesure :",choices:["La vitesse d\'air","Le débit volumique d\'eau dans les circuits hydrauliques — indispensable pour calculer Φ = ṁ × Cp × ΔT","La teneur en CO₂","La puissance électrique"],answer:1,diff:1,explication:"PCE-HAWA30 : débitmètre hydraulique ultrasonique ou à insertion. Mesure le débit d\'eau en L/h ou m³/h dans les circuits de chauffage, ECS, échangeurs. À positionner sur une portion de tuyau droite (respect des distances amont/aval = 10D amont, 5D aval). Nécessaire pour calculer Φ = ṁ × Cp × ΔT. En E5 : justifier son choix (grandeur, plage, procédure).",tags:["E5","PCE-HAWA30","Débitmètre","Appareils de mesure","C7-5"]},
  {id:"fed_e5_72",prompt:"Le thermomètre laser (pyromètre infrarouge) utilisé en E5 mesure :",choices:["La T° de l\'air ambiant uniquement","La T° de surface sans contact (rayonnement IR) — utile pour canalisations, corps de chaudière, surfaces difficilement accessibles","La T° des fumées dans le conduit","L\'humidité relative"],answer:1,diff:1,explication:"Pyromètre IR : mesure T° de surface par rayonnement. Avantage : sans contact, lecture instantanée. Limites : émissivité variable (surfaces métalliques brillantes → ε faible → erreur importante). Régler ε selon le matériau (acier oxydé ε ≈ 0,8, cuivre brillant ε ≈ 0,1). En E5 : utiliser pour repérer rapidement les canalisations chaudes, corps de chaudière, détection fuites.",tags:["E5","Thermomètre laser","Infrarouge","Appareils de mesure","Surface"]},
  {id:"fed_e5_73",prompt:"La pince ampèremétrique en E5 permet de mesurer :",choices:["Uniquement la tension","L\'intensité (A), la tension (V) et la puissance électrique (W) — pour mesurer P_élec absorbée par le compresseur PAC ou moteur pompe","Le CO dans les fumées","La pression de condensation"],answer:1,diff:1,explication:"Pince ampèremétrique clamp : mesure le courant par induction (sans couper le circuit). Avec mesure de tension simultanée → puissance active P = U × I × cos φ (mono). Triphasé : P = √3 × U × I × cos φ. En E5 sujet PAC : mesurer P_élec compresseur → calculer COP = Φ_utile / P_élec. En sujet chaudière : mesurer P_élec pompe circulateur.",tags:["E5","Pince ampèremétrique","Puissance électrique","PAC","C7-5"]},
  {id:"fed_e5_74",prompt:"Le thermo-hygromètre est INDISPENSABLE pour le sujet :",choices:["Chaudière fioul uniquement","CTA (mesure T° et HR de l\'air extérieur, soufflage et reprise — report sur diagramme de l\'air humide)","Régulation ECBT uniquement","Bilan échangeur sanitaire uniquement"],answer:1,diff:1,explication:"Thermo-hygromètre : mesure T° (°C) + Humidité Relative (%) en même temps. Indispensable pour : sujet CTA (points sur diagramme air humide), ambiance locale. En bilan CTA : mesurer les 3 points (air extérieur, soufflage, reprise) → report sur diagramme psychrométrique → calcul enthalpies → puissance traitement d\'air. Pour sujet chaudière : optionnel.",tags:["E5","Thermo-hygromètre","CTA","Humidité","Diagramme air humide"]},
  {id:"fed_e5_75",prompt:"Le thermomètre à contact est préféré au thermomètre laser pour :",choices:["Mesurer les surfaces brillantes à distance","Mesurer précisément les T° de surface métalliques (canalisations départ/retour, échangeurs) — meilleure précision que le laser sur les métaux","Mesurer les fumées de combustion","Mesurer l\'air ambiant"],answer:1,diff:2,explication:"Thermomètre à contact (sonde de contact plate ou à aiguille) : précision ±0,3-0,5°C sur surfaces. Avantage sur laser : pas de problème d\'émissivité. Inconvénient : temps de stabilisation (10-30s). Utilisation E5 : T° départ/retour eau chaude sur tuyauteries. Placer la sonde en bon contact (pâte thermique si surface irrégulière) et isoler du rayonnement ambiant.",tags:["E5","Thermomètre à contact","Appareils de mesure","Surface","C7-5"]},
  {id:"fed_e5_76",prompt:"En E5, pour quelle raison TOUJOURS justifier le choix de chaque appareil de mesure devant le jury ?",choices:["C\'est optionnel et décoratif","Parce que C7-5 évalue \'les matériels utilisés sont adaptés et utilisés correctement\' — justification = points directs","Pour impressionner le jury uniquement","C\'est une obligation administrative"],answer:1,diff:1,explication:"C7-5 = \'Choisir et utiliser des appareils de mesure\'. Le jury attend : (1) grandeur à mesurer, (2) plage de mesure adaptée à la gamme attendue, (3) précision/incertitude acceptable, (4) procédure d\'utilisation (comment le brancher, où le positionner, quelle précaution). Savoir justifier 5 appareils = maîtrise totale de C7-5.",tags:["E5","C7-5","Justification appareils","Jury","Métrologie"]},
  {id:"fed_e5_77",prompt:"Pour mesurer le débit d\'air dans une bouche de ventilation (faible section, faible vitesse), quel instrument choisir ?",choices:["Anémomètre à hélice (inadapté aux faibles vitesses)","Anémomètre à fil chaud — mesures précises faibles vitesses, faible turbulence, petites sections","Débitmètre PCE-HAWA30","Thermo-hygromètre"],answer:1,diff:2,explication:"Anémomètre à fil chaud : principe de mesure par convection autour d\'un fil chauffé (résistance variable selon la vitesse). Plage 0,1-20 m/s, très précis pour v < 1 m/s. Pour bouches (petite section, v ≈ 0,5-3 m/s) → fil chaud préféré. Pour grandes gaines (v > 3 m/s, grande section) → hélice ou sonde Pitot. En E5 sujet CTA TP3/TP4 : réglage volets et débits bouches.",tags:["E5","Anémomètre fil chaud","Bouche de ventilation","CTA","C7-5"]},
  {id:"fed_e5_78",prompt:"Pourquoi ne jamais monter une vanne TA immédiatement en aval d\'une pompe ?",choices:["Pour des raisons esthétiques","Les turbulences en aval de la pompe perturbent le profil d\'écoulement → mesure de débit incorrecte (erreur jusqu\'à ±10%)","La pompe la détériorerait","Pour faciliter l\'entretien"],answer:1,diff:2,explication:"Vanne TA (de réglage + mesure) : nécessite un écoulement établi (laminaire/turbulent selon Re, mais profil stable). Aval pompe = turbulences → profil non établi → mesure faussée. Règle d\'installation : minimum 5D en amont et 2D en aval de perturbations (coudes, pompes, vannes). Le non-respect génère des erreurs de mesure et invalide les calculs de puissance (C8-3).",tags:["E5","Vanne TA","Installation","Turbulences","Métrologie"]},
  {id:"fed_e5_79",prompt:"La pince ampèremétrique donne I = 8,5 A sous U = 230 V avec cos φ = 0,85 pour un circulateur. La puissance absorbée est :",choices:["1 955 W","1 661 W (P = U × I × cos φ = 230 × 8,5 × 0,85 = 1 661 W ≈ 1,66 kW)","8,5 W","230 W"],answer:1,diff:2,explication:"P = U × I × cos φ = 230 × 8,5 × 0,85 = 1 661 W ≈ 1,66 kW. La puissance apparente S = U × I = 230 × 8,5 = 1 955 VA. La puissance réactive Q = √(S²-P²) = √(1955²-1661²) ≈ 1 028 VAR. En E5 sujet PAC : P_élec compresseur mesurée → COP = Φ_utile / P_élec_compresseur (sans la pompe).",tags:["E5","Calcul","Puissance électrique","Cos phi","Pince ampèremétrique"]},
  {id:"fed_e5_80",prompt:"L\'analyseur de combustion doit être étalonné :",choices:["Jamais, il est précis en permanence","Régulièrement selon les préconisations du fabricant (certificat d\'étalonnage) — en E5, vérifier la date d\'étalonnage et la remise à zéro avant usage","Uniquement si CO détecté","Après chaque utilisation uniquement"],answer:1,diff:2,explication:"Analyseur combustion : etalonnage annuel recommandé (COFRAC ou fabricant). Avant usage : remettre à zéro (purge à l\'air propre), vérifier date d\'étalonnage, vérifier électrochimie CO (durée de vie cellule ≈ 2 ans). En E5 : mentionner ces vérifications dans la procédure (C7-3 = suivre un protocole). Un appareil hors étalonnage → résultats non fiables → mauvaise note C8.",tags:["E5","Analyseur combustion","Étalonnage","Métrologie","C7-3"]},
  {id:"fed_e5_81",prompt:"Dans la grille d\'analyse des risques E5, la cotation \'Priorité 1\' correspond à :",choices:["Risque très faible","Dommage très grave (4) × Probabilité très probable (4) = risque maximal nécessitant une action corrective immédiate","Risque négligeable","Uniquement les risques électriques"],answer:1,diff:2,explication:"Cotation risque E5 : Gravité 1-4 (1=faible, 4=très grave/décès) × Probabilité 1-4 (1=très improbable, 4=très probable). Priorité 1 = zone rouge (Gravité 3-4 + Probabilité 3-4). Priorité 2 = zone orange. Priorité 3 = zone verte. En E5 : identifier les dangers (électricité, brûlure, chute, fuite frigorigène), évaluer, puis proposer les mesures de prévention adaptées.",tags:["E5","Analyse des risques","Priorité","Cotation","Sécurité"]},
  {id:"fed_e5_82",prompt:"Les EPI obligatoires à mentionner lors d\'une intervention sur une chaudière en E5 sont :",choices:["Uniquement les gants","Gants isolants, lunettes de protection, chaussures de sécurité (antistatiques si nécessaire) — les examinateurs y sont très attentifs (C7-4)","Uniquement le casque","EPI non nécessaires si installation < 10 kW"],answer:1,diff:1,explication:"EPI obligatoires en E5 (C7-4) : gants isolants (risque électrique/brûlure), lunettes (projections liquides, fumées), chaussures de sécurité (risque de chute d\'objets). Selon l\'intervention ajouter : casque (hauteur), combinaison ignifugée (brûleur), protection auditive (ventilateur). Le jury évalue systématiquement la mention des EPI → ne JAMAIS l\'omettre.",tags:["E5","EPI","Sécurité","C7-4","Chaudière"]},
  {id:"fed_e5_83",prompt:"La consignation électrique (LOTO) avant intervention sur une installation en E5 consiste à :",choices:["Éteindre la lumière du local","Identifier, consigner (verrouiller en position OFF) et cadenasser l\'alimentation électrique, puis vérifier l\'absence de tension avant toute intervention","Uniquement signaler par une pancarte","Mettre en marche dégradée"],answer:1,diff:1,explication:"LOTO (Lock Out, Tag Out) : (1) Identifier les sources d\'énergie (électrique, hydraulique, pneumatique), (2) Les neutraliser (disjoncteur OFF, vanne fermée), (3) Cadenasser et étiqueter \'Ne pas manœuvrer\', (4) Vérifier l\'absence de tension (VAT avec voltmètre), (5) Mettre à la terre si nécessaire. En E5 : mentionner dans la procédure de sécurité. Omettre = perte de points C7-4.",tags:["E5","Consignation","LOTO","Sécurité","C7-4","Électrique"]},
  {id:"fed_e5_84",prompt:"Quel est le risque principal lors d\'une intervention sur une installation frigorifique PAC (sujet PAC E5) ?",choices:["Risque de surcharge pondérale","Fuite frigorigène (R410A) — gaz sous haute pression, risque d\'asphyxie, risque de brûlure cryogénique sur peau, attestation de capacité obligatoire pour les intervenants","Risque de chute uniquement","Risque sonore uniquement"],answer:1,diff:2,explication:"PAC R410A : pression HP ≈ 25-30 bar, pression BP ≈ 8-15 bar. Risques : brûlure cryogénique (détente → froid intense), asphyxie (gaz plus lourd que l\'air), inflammation (non inflammable mais risque sur autres gaz). Attestation de capacité catégorie I obligatoire pour manipuler le fluide (F-gas). En E5 : ne pas ouvrir le circuit frigorifique → uniquement mesures externes (HP/BP, T° aspiration/refoulement).",tags:["E5","PAC","Frigorigène","R410A","Sécurité","F-gas"]},
  {id:"fed_e5_85",prompt:"Lors d\'une détection de CO dans le local chaudière pendant l\'E5, quelle est la procédure correcte ?",choices:["Continuer les mesures en ouvrant juste une fenêtre","Arrêter immédiatement la chaudière, évacuer le local, ventiler, prévenir le jury — ne jamais rester dans un local avec CO détecté","Attendre que le CO se dissipe naturellement","Signaler uniquement à la fin de l\'épreuve"],answer:1,diff:1,explication:"CO = urgence. Procédure : (1) Arrêt immédiat chaudière/brûleur, (2) Évacuation rapide du local, (3) Ventilation maximum (ouvrir portes/fenêtres), (4) Alerter le jury immédiatement, (5) Ne pas ré-entrer avant mesures CO < 10 ppm. En E5 : cette situation peut arriver (défaut brûleur, problème tirage fumées). Montrer que vous connaissez la procédure = points sur C7-4 sécurité.",tags:["E5","CO","Urgence","Sécurité","Procédure","C7-4"]},

  // ─── PAC (sujets E5 CFA — sujet eau/eau et air/air) ───
  {id:"fed_e5_86",prompt:"Dans un sujet E5 PAC eau/eau, la formule pour calculer la puissance thermique côté eau est :",choices:["P = m × Cp × ΔT (débit massique en kg/s)","P = qv × 1,163 × ΔT (qv en m³/h, ΔT en °C) — formule directement utilisable sur le sujet","P = U × I × cos φ","P = COP × Pélec"],answer:1,diff:1,explication:"Formule donnée dans le sujet PAC E5 : P = qv × 1,163 × ΔT. qv = débit volumique (m³/h), 1,163 = facteur de conversion de l\'eau (ρ × Cp en kWh/m³°C = 1000 × 4186/3 600 000 ≈ 1,163), ΔT = écart température entrée/sortie (°C). Exemple : qv = 1,2 m³/h, ΔT = 5°C → P = 1,2 × 1,163 × 5 = 6,98 kW.",tags:["E5","PAC","Puissance thermique","Calcul","Sujet CFA"]},
  {id:"fed_e5_87",prompt:"Le SCOP (Seasonal Coefficient Of Performance) d\'une PAC se calcule par :",choices:["SCOP = Pélec / Putile","SCOP = Putile / Pélec — formule donnée dans le sujet E5","SCOP = ΔT / Pélec","SCOP = qv × 1,163 / Pélec"],answer:1,diff:1,explication:"SCOP = Putile / Pélec (formule donnée dans le sujet CFA 2025). C\'est le COP saisonnier moyen calculé sur une saison de chauffe complète (conditions réelles, pas juste à +7°C/+20°C). En E5 : mesurer Putile (côté eau via P = qv × 1,163 × ΔT) et Pélec (pince ampèremétrique côté compresseur), puis calculer SCOP. Comparer aux données constructeur.",tags:["E5","PAC","SCOP","COP","Calcul"]},
  {id:"fed_e5_88",prompt:"Dans le sujet E5 PAC eau/eau CFA 2025, pourquoi faut-il couper le surpresseur AVANT d\'arrêter le système ?",choices:["Pour économiser de l\'énergie","Car la PAC doit toujours s\'arrêter en premier (si le surpresseur s\'arrête après la PAC, la pression chute brutalement → risque de cavitation ou défaut haute pression)","Pour permettre la mesure des températures","Car le surpresseur démarre automatiquement"],answer:1,diff:2,explication:"La consigne \'Couper le surpresseur avant d\'arrêter le système\' figure explicitement dans le sujet E5 CFA PAC eau/eau. Un surpresseur (pompe de mise en pression) maintient la pression du circuit. Si la PAC s\'arrête en premier, le débit peut continuer avec une pression anormale → risques : bruit, vibrations, défaut sécurité. En pratique : respecter TOUJOURS les ordres d\'arrêt indiqués dans la procédure du jury.",tags:["E5","PAC","Surpresseur","Sécurité","Procédure"]},
  {id:"fed_e5_89",prompt:"En sujet PAC E5, le cahier des charges impose une consigne de température = température ambiante + 3°C avec une T° extérieure de 5°C. Cela correspond à quel mode de fonctionnement ?",choices:["Mode rafraîchissement automatique","Mode chauffage en marche forcée jour — la PAC doit maintenir Tambiante + 3°C = Tconsigne","Mode veille nuit","Mode dégivrage"],answer:1,diff:2,explication:"Cahier des charges sujet PAC CFA : Text = 5°C, Tconsigne = Tambiante + 3°C, mode chauffage, marche forcée jour. Cela signifie que la PAC ne s\'arrête pas même si Tambiante > Tconsigne (marche forcée = on force le fonctionnement continu pour pouvoir faire les mesures). L\'émission se fait par ventilo-convecteur (fan coil). En E5 : paramétrer ce mode avant les mesures (C6 = 40%).",tags:["E5","PAC","Cahier des charges","Marche forcée","Paramétrage"]},
  {id:"fed_e5_90",prompt:"L\'émetteur de chaleur utilisé avec la PAC eau/eau dans le sujet E5 CFA est :",choices:["Un plancher chauffant","Un radiateur en fonte","Un ventilo-convecteur (fan coil) — émet chaleur ET froid selon le mode","Un aérotherme industriel"],answer:2,diff:1,explication:"Le cahier des charges précise : \'Emission chaleur/froid par ventilo-convecteur\'. Le ventilo-convecteur (ou fan coil) est un échangeur eau/air avec un ventilateur. Il peut être utilisé en chaud (PAC mode chauffage) ou en froid (PAC mode climatisation réversible). Avantage : réponse rapide, compatible PAC réversible, adapté aux petits locaux.",tags:["E5","PAC","Ventilo-convecteur","Fan coil","Émetteurs"]},
  {id:"fed_e5_91",prompt:"Pour vérifier les performances d\'une PAC eau/eau en E5, quels paramètres faut-il mesurer côté source froide (eau de nappe) ?",choices:["Uniquement la température entrée","Débit volumique (qv) ET températures entrée/sortie côté source froide — pour calculer la puissance absorbée sur la source","Uniquement la pression","Uniquement la conductivité de l\'eau"],answer:1,diff:2,explication:"Bilan PAC eau/eau : 2 circuits eau. Côté source froide (eau de nappe, sol, rivière) : mesurer qv + ΔT → Φfroid = qv × 1,163 × ΔT. Côté condenseur (eau chauffage) : mesurer qv + ΔT → Φchaud = qv × 1,163 × ΔT. COP = Φchaud / Pélec. Vérification bilan : Φchaud = Φfroid + Pélec (premier principe). En E5 C8-2 : choisir ces 5 grandeurs (2 débits + 4 températures + 1 puissance élec).",tags:["E5","PAC","Mesures","Source froide","Bilan thermique"]},
  {id:"fed_e5_92",prompt:"La vanne 4 voies d\'une PAC réversible air/air ou air/eau permet de :",choices:["Régler le débit de frigorigène","Inverser le sens de circulation du frigorigène pour passer du mode chauffe au mode froid (l\'évaporateur devient condenseur et vice-versa)","Régler la pression haute","Dégivrer l\'évaporateur uniquement"],answer:1,diff:2,explication:"Vanne 4 voies (ou inverseur de cycle) : organe clé des PAC réversibles. En mode chauffe : frigorigène circule dans un sens (condenseur côté intérieur). En mode froid : bobine de la vanne alimentée → inversión → évaporateur côté intérieur. En sujet E5 PAC air/air CFA : identifier la position de la vanne 4 voies sur le schéma de principe et expliquer le cycle.",tags:["E5","PAC","Vanne 4 voies","Réversibilité","Cycle frigorifique"]},
  {id:"fed_e5_93",prompt:"Dans un sujet E5 PAC, le diagramme enthalpique (h-log P) permet de :",choices:["Mesurer la consommation électrique","Visualiser le cycle frigorifique réel (points 1 à 4), lire les enthalpies, calculer le COP théorique et identifier la surchauffe/sous-refroidissement","Régler le détendeur thermostatique","Paramétrer le régulateur"],answer:1,diff:3,explication:"Diagramme h-log P (Mollier frigorigène) : axe X = enthalpie (kJ/kg), axe Y = pression (bar). Points : 1 = aspiration compresseur (vapeur surchauffée), 2 = refoulement compresseur (après compression), 3 = sortie condenseur (liquide sous-refroidi), 4 = sortie détendeur (mélange liquide-vapeur). COP théorique = (h1-h4)/(h2-h1). Surchauffe = T1 - Tsat(P1). En E5 : souvent demandé en partie analyse (C8).",tags:["E5","PAC","Diagramme enthalpique","Mollier","COP théorique"]},
  {id:"fed_e5_94",prompt:"La pression HP (haute pression) mesurée sur une PAC R410A en mode chauffe à une température de condensation de 40°C est environ :",choices:["6 bar","10 bar","25 bar — pression de saturation du R410A à 40°C ≈ 24,3 bar","40 bar"],answer:2,diff:3,explication:"R410A : pression de saturation à 40°C ≈ 24,3 bar (table de saturation R410A). À 45°C ≈ 27,7 bar. À 50°C ≈ 31,4 bar. BP : à 0°C ≈ 7,9 bar, à -5°C ≈ 6,6 bar. En E5 : utiliser la table de saturation du frigorigène (fournie dans le dossier technique) pour vérifier si HP/BP mesurées correspondent aux températures d\'évaporation/condensation attendues.",tags:["E5","PAC","R410A","Pression HP","Saturation"]},
  {id:"fed_e5_95",prompt:"Pour mesurer la puissance électrique absorbée par le compresseur en E5, on utilise :",choices:["Un voltmètre seul","Une pince ampèremétrique (pour I) + multimètre (pour U) + cos φ donné → P = U × I × cos φ","Un thermomètre","Un manomètre"],answer:1,diff:1,explication:"Puissance élec compresseur : P = U × I × cos φ. U mesuré au multimètre (≈ 230 V monophasé ou 400 V triphasé). I mesuré à la pince ampèremétrique (autour du câble phase). cos φ donné dans le sujet (ex: 0,9). Pour triphasé : P = √3 × U × I × cos φ. En E5 CFA PAC : cos φ = 0,9 donné. Ne pas confondre S (VA) = U × I et P (W) = S × cos φ.",tags:["E5","PAC","Pince ampèremétrique","Puissance électrique","Mesure"]},
  {id:"fed_e5_96",prompt:"Lors du paramétrage d\'une PAC en E5, la notice d\'utilisation destinée à l\'utilisateur doit expliquer :",choices:["Uniquement comment allumer/éteindre","Les différents modes (chauffe, froid, auto), comment régler la consigne, les voyants d\'alarme et les actions à faire en cas de défaut — expliquée oralement au jury (C6)","Le schéma frigorifique complet","Le câblage électrique détaillé"],answer:1,diff:1,explication:"C6 (40% de la note E5) inclut : \'L\'utilisation des différents modes est clairement expliquée (Q4)\'. La notice doit être rédigée EN TERMES SIMPLES pour l\'utilisateur non technicien. Couvrir : comment régler la température, passer en mode chauffe/froid, comprendre les voyants (vert = OK, rouge = défaut), que faire en cas de panne (appeler un technicien). Elle est ensuite expliquée oralement au jury.",tags:["E5","PAC","Notice utilisateur","C6","Modes"]},
  {id:"fed_e5_97",prompt:"En sujet E5 PAC, les \'valeurs attendues\' (C7-1) avant de faire les mesures sont :",choices:["Des valeurs inventées pour remplir le tableau","Les données constructeur (COP nominal, puissance thermique nominale, HP/BP à Text donnée) lues dans la fiche technique — à comparer aux mesures","Les valeurs imposées par le jury","Les valeurs de l\'année précédente"],answer:1,diff:2,explication:"C7-1 (10% de la note C7) : \'Les valeurs attendues sont correctement définies, les grandeurs à prendre en compte permettent l\'analyse du système (Q1)\'. Avant toute mesure : lire la fiche technique constructeur de la PAC → relever COP nominal, puissance calorifique nominale, température de fonctionnement admissible, pression HP/BP nominales. Ces valeurs deviennent le référentiel de comparaison pour C8-3.",tags:["E5","PAC","Valeurs constructeur","C7-1","Fiche technique"]},
  {id:"fed_e5_98",prompt:"La surchauffe à l\'aspiration du compresseur dans un cycle PAC réel doit être :",choices:["Nulle (vapeur saturante pure)","Positive et typiquement de 5 à 10°C — elle garantit que le frigorigène est entièrement vaporisé avant le compresseur (pas de gouttes liquides)","Aussi élevée que possible (20-30°C)","Négative (frigorigène liquide en aspiration)"],answer:1,diff:3,explication:"Surchauffe = T_aspiration - T_saturation(BP). Elle doit être positive (5-10°C typique) pour garantir que le frigorigène est 100% vapeur avant d\'entrer dans le compresseur. Aspiration liquide → risque de coup de liquide → endommagement du compresseur. Surchauffe trop élevée (>15°C) → rendement dégradé, T° refoulement trop haute, risque dégradation huile. En E5 : mesurer T° aspiration + lire BP → calculer surchauffe.",tags:["E5","PAC","Surchauffe","Aspiration","Cycle frigorifique"]},
  {id:"fed_e5_99",prompt:"L\'attestation de capacité (F-gas) est obligatoire pour :",choices:["Lire les pressions sur le manifold en externe","Ouvrir le circuit frigorifique, récupérer ou recharger le frigorigène — interdite sans cette attestation (R410A, R32, R744)","Mesurer la température d\'air","Brancher l\'alimentation électrique de la PAC"],answer:1,diff:2,explication:"Attestation de capacité (règlement F-gas 517/2014) : catégorie I pour circuits > 5 t CO₂eq (R410A > 1,5 kg). Nécessaire pour : récupération, charge, réparation circuit frigorifique. En E5 : le candidat n\'intervient PAS sur le circuit (pas de récupération/charge). Il fait des mesures externes : températures (sondes), pressions (raccords service par le jury), performances. Mentionner en C7-2 (réglementation) = points.",tags:["E5","PAC","F-gas","Attestation de capacité","R410A","Réglementation"]},
  {id:"fed_e5_100",prompt:"Dans un tableau de mesures PAC E5, les grandeurs à relever pour calculer le COP sont :",choices:["Uniquement HP et BP","Débit qv + ΔT côté condenseur (→ Φutile) + tension U + intensité I + cos φ (→ Pélec) → COP = Φutile/Pélec","Uniquement les températures ambiantes","Uniquement la T° extérieure"],answer:1,diff:2,explication:"Tableau de mesures PAC E5 complet : (1) qv eau condenseur (m³/h) par débitmètre, (2) T° entrée eau condenseur (°C), (3) T° sortie eau condenseur (°C), (4) ΔT = T_sortie - T_entrée, (5) Φutile = qv × 1,163 × ΔT (kW), (6) U (V), (7) I (A) pince amperémétrique, (8) cos φ = 0,9, (9) Pélec = U × I × cos φ (kW), (10) COP = Φutile / Pélec. Comparer COP mesuré à COP constructeur (C8-3).",tags:["E5","PAC","Tableau de mesures","COP","Protocole"]},
  {id:"fed_e5_101",prompt:"Un écart de +0,5 COP entre valeur mesurée et valeur constructeur s\'interprète comme :",choices:["Un défaut grave de la PAC","Performances légèrement supérieures aux spécifications constructeur — peut être dû aux conditions réelles (Text favorable, régime stabilisé) — à analyser et à noter dans le compte rendu","Une erreur de mesure automatique","Le signe que la PAC est surdimensionnée"],answer:1,diff:2,explication:"En E5 C8-3 (30% de C8) : analyser les écarts. COP_mesuré > COP_constructeur : performances réelles meilleures (températures de fonctionnement favorables, PAC rodée). COP_mesuré < COP_constructeur : dégradation possible (encrassement, manque de frigorigène, températures source défavorables). Mentionner la précision des appareils (±5% typique) avant de conclure. Toujours commenter : écart acceptable ?, cause probable ?, action corrective ?",tags:["E5","PAC","Analyse des résultats","COP","C8-3"]},
  {id:"fed_e5_102",prompt:"Le dégivrage automatique d\'une PAC air/air en hiver se déclenche quand :",choices:["La température intérieure est trop haute","L\'évaporateur extérieur se couvre de givre (T° < 0°C + humidité) — détecté par sonde de température ou par pression BP trop basse → cycle inverse temporaire pour fondre le givre","L\'utilisateur appuie sur un bouton","Le compresseur surchauffe"],answer:1,diff:2,explication:"Dégivrage PAC air/air : quand Text < 5°C et humidité élevée, l\'évaporateur extérieur givrait. Détection : sonde T° sur évaporateur < seuil (ex : -4°C) ou temporisation cyclique. Action : inversion cycle brève (vanne 4 voies) → condenseur extérieur fond le givre → reprise du mode chauffe. Pendant le dégivrage (2-5 min) : la PAC souffle air froid côté intérieur = normal. En E5 : si sujet air/air, mentionner ce mode en notice utilisateur.",tags:["E5","PAC","Dégivrage","Air/air","Vanne 4 voies"]},
  {id:"fed_e5_103",prompt:"Comparer le COP calculé à partir des mesures avec les données constructeur constitue quelle compétence en E5 ?",choices:["C6 — Outils numériques","C7-6 (Interpréter les résultats) ET C8-3 (Analyser les résultats) — les deux compétences C7 et C8 sont mobilisées dans l\'analyse finale","C7-2 uniquement","Aucune compétence spécifique"],answer:1,diff:2,explication:"En E5 sujet PAC : C7-6 (20% de C7) = \'Les résultats et les écarts par rapport aux résultats attendus sont analysés et interprétés (Q8)\'. C8-3 (30% de C8) = \'Les écarts entre les valeurs contractuelles et les valeurs mesurées sont identifiés et interprétés (Q9)\'. Ce sont les 2 questions les plus valorisées de la partie analyse. Présenter un tableau comparatif (valeur constructeur / valeur mesurée / écart / interprétation) est la meilleure façon de décrocher ces points.",tags:["E5","PAC","C7-6","C8-3","Analyse","Compétences"]}
];

// ─── BANQUE E5 : CTA & VMC DOUBLE FLUX ───
export const QB_FED_E5_CTA = [
  {id:"fed_cta1",prompt:"La formule de puissance sur l'air dans une CTA est :",choices:["P = qv × 1,163 × ΔT","P = 0,34 × qv × ΔT (qv en m³/h, ΔT en °C)","P = U × I × cos φ","P = m × Cp × ΔT avec Cp = 4186 J/kg·K"],answer:1,diff:1,explication:"Air : P (kW) = 0,34 × qv (m³/h) × ΔT (°C). Le coefficient 0,34 = ρ_air × Cp_air / 3600 ≈ 1,2 × 1005 / 3600 ≈ 0,335 ≈ 0,34. À comparer avec l'eau : 1,163. Exemple : CTA avec qv = 5 000 m³/h, ΔT = 8°C → P = 0,34 × 5000 × 8 = 13 600 W = 13,6 kW.",tags:["E5","CTA","Aéraulique","Formule","Puissance thermique"]},
  {id:"fed_cta2",prompt:"Le débit volumique d'air mesuré à l'anémomètre à hélice dans une bouche se calcule par :",choices:["qv = P / (0,34 × ΔT)","qv = V × S × 3600 (V = vitesse en m/s, S = section en m²)","qv = 18 × nombre d'occupants","qv = ΔP / R_aeraulique"],answer:1,diff:1,explication:"qv (m³/h) = V (m/s) × S (m²) × 3600. V mesurée à l'anémomètre à hélice (ou à fil chaud). S = section de la bouche ou du conduit. En E5 TP3/TP4 : mesurer V en plusieurs points (profil de vitesse), faire la moyenne, multiplier par S × 3600. Vérifier par rapport au débit nominal du plan.",tags:["E5","CTA","Aéraulique","Anémomètre","Débit"]},
  {id:"fed_cta3",prompt:"Le débit d'air neuf réglementaire dans une salle de spectacle est de :",choices:["5 m³/h/occupant","10 m³/h/occupant","18 m³/h/occupant (réglementation sanitaire)","25 m³/h/occupant"],answer:2,diff:2,explication:"18 m³/h/occupant dans une salle de spectacle selon la réglementation sanitaire (arrêté hygiène + RT). La CTA Wesper Airtech 75 de la salle de spectacle de Limours (sujet CCF) traite 3 000 m³/h d'air neuf pour 270 personnes max (270 × 18 / 3600 ≈ 1,35 m³/s). En E5 : citer la référence réglementaire = points C7-2.",tags:["E5","CTA","Réglementation","Débit air neuf","Ventilation"]},
  {id:"fed_cta4",prompt:"L'efficacité d'un échangeur double flux (récupération de chaleur) se calcule par :",choices:["η = P_récupérée / P_soufflage","η = (T_soufflage - T_air extérieur) / (T_reprise - T_air extérieur) × 100%","η = débit soufflage / débit reprise","η = ΔP_soufflage / ΔP_reprise"],answer:1,diff:2,explication:"Efficacité échangeur = (Ts - Text) / (Tr - Text). Ts = T° soufflage après échangeur, Text = T° air extérieur, Tr = T° air reprise. Valeur typique : 70-85% pour un échangeur à plaques croisées. Exemple : Ts = 16°C, Text = 0°C, Tr = 22°C → η = 16/22 = 73%. En E5 CFA CTA : mesurer Ts, Text, Tr et calculer η, comparer au constructeur (C8-3).",tags:["E5","CTA","VMC","Échangeur","Efficacité","Double flux"]},
  {id:"fed_cta5",prompt:"Dans le sujet E5 CFA CTA, les 3 débits à connaître sont :",choices:["Entrée, milieu, sortie","Minimum 275 m³/h, pointe 700 m³/h, sur-ventilation 1 000 m³/h — à paramétrer sur l'objet KNX 'Consigne Débit Confort'","100, 200, 300 m³/h","Soufflage, reprise, recyclage"],answer:1,diff:2,explication:"Cahier des charges sujet E5 CFA CTA : débit minimum = 275 m³/h (fonctionnement continu), débit de pointe = 700 m³/h (fort taux d'occupation), sur-ventilation = 1 000 m³/h (nettoyage, défaut). En C6 (40%) : paramétrer ces 3 seuils dans l'interface GTC/ETS5. L'objet KNX 'Consigne Débit Confort' accepte 275-700 m³/h en entrée directe.",tags:["E5","CTA","Débit","Paramétrage","C6","CFA"]},
  {id:"fed_cta6",prompt:"Le variateur de fréquence SSD Drives série 650 d'un moto-ventilateur CTA nécessite de régler en premier le paramètre :",choices:["P1 (tension d'alimentation)","P6 (fréquence maximale de sortie liée à la vitesse moteur nominale)","P10 (courant de protection)","P100 (rampe d'accélération)"],answer:1,diff:2,explication:"Paramètre P6 = fréquence maximale (ou vitesse max) du variateur SSD 650. C'est le premier réglage à effectuer car il définit la vitesse nominale du moteur. Si P6 est mal réglé, le moteur peut tourner trop vite (risque mécanique) ou trop lentement (débit insuffisant). En E5 : vérifier la plaque moteur (Nn, In, cos φ, Pn) avant de programmer P6. Ensuite régler la rampe d'accélération/décélération.",tags:["E5","CTA","Variateur","SSD 650","Paramétrage","P6"]},
  {id:"fed_cta7",prompt:"La CTA Wesper Airtech 75 Premi@ir PR90 installée à la salle de spectacle de Limours a un débit nominal de soufflage de :",choices:["1 000 m³/h","5 000 m³/h en mode salle de spectacle (8 000 m³/h max constructeur)","2 500 m³/h","10 000 m³/h"],answer:1,diff:3,explication:"CTA Wesper PR90 salle de Limours : débit soufflage constructeur = 8 000 m³/h max, mais en mode salle de spectacle = 5 000 m³/h. Débit reprise = 2 000 m³/h. Débit air neuf = 3 000 m³/h (dont puits canadien). Rejet = 0 à 5 000 m³/h variable. Dimensions : 3,44 × 1,325 m, hauteur 1,94 m. Ces valeurs sont dans le dossier technique du sujet CCF.",tags:["E5","CTA","Wesper","Limours","CCF","Débit"]},
  {id:"fed_cta8",prompt:"Le puits canadien (ou puits provençal) branché sur la CTA de Limours sert à :",choices:["Évacuer les eaux usées","Préchauffer l'air extérieur en hiver (ou le rafraîchir en été) en faisant passer l'air dans un conduit enterré à T° constante du sol (~12-14°C)","Filtrer les particules fines de l'air","Alimenter la chaudière en combustible"],answer:1,diff:2,explication:"Puits canadien : conduit enterré à 1,5-2 m de profondeur (T° sol constante ≈ 12-14°C). En hiver : air extérieur froid (0°C) passe dans le conduit → préchauffé à 10-12°C avant la CTA → économie batterie chaude. En été : air chaud (30°C) → refroidi à 20°C → économie batterie froide. Sujet CCF Limours : puits canadien intégré dans la boîte de mélange BM (débit air neuf + puits).",tags:["E5","CTA","Puits canadien","Préchauffage","Limours","CCF"]},
  {id:"fed_cta9",prompt:"La régulation de débit d'air neuf par capteur CO₂ dans une CTA permet de :",choices:["Mesurer la température de soufflage","Moduler le débit d'air neuf selon la qualité de l'air intérieur (taux CO₂ = indicateur d'occupation) — mode DCV (Demand Controlled Ventilation)","Contrôler l'humidité relative","Détecter les incendies"],answer:1,diff:2,explication:"DCV (ventilation à la demande) : capteur CO₂ mesure la concentration en CO₂ (en ppm) dans la reprise d'air — indicateur indirect du taux d'occupation humaine. Si CO₂ > seuil (ex : 1000 ppm) → ouvrir davantage les volets d'air neuf/recyclé (boîte BM2). Si local vide → réduire débit. Économies d'énergie 30-40% vs débit constant. Régulateur TREND IQ3xcite gère cette logique.",tags:["E5","CTA","CO₂","DCV","Régulation","Qualité air"]},
  {id:"fed_cta10",prompt:"En mode VMC double flux, le débit de base pour un T3 selon le sujet E5 CFA VMC est de :",choices:["50 m³/h","90 m³/h (débit continu de base — confort automatique)","275 m³/h","500 m³/h"],answer:1,diff:2,explication:"Cahier des charges sujet E5 CFA VMC (T3) : débit de base = 90 m³/h (continu), débit de pointe = 105 m³/h (modulation cuisine/salle de bain), sur-ventilation = 300 m³/h. Ces débits sont à paramétrer sur le tableau de commande VMC en C6. Vérification par mesure anémomètre aux bouches d'extraction.",tags:["E5","VMC","Double flux","Débit","CFA","Paramétrage"]},
  {id:"fed_cta11",prompt:"La formule de puissance sur l'air d'une VMC double flux donne pour qv = 300 m³/h et ΔT = 15°C :",choices:["450 W","1 530 W (P = 0,34 × 300 × 15 = 1 530 W = 1,53 kW)","300 W","4 500 W"],answer:1,diff:2,explication:"P = 0,34 × qv × ΔT = 0,34 × 300 × 15 = 1 530 W = 1,53 kW. Vérification dimensionnelle : 0,34 kW/(m³/h·°C) × 300 m³/h × 15°C = 1,53 kW. En E5 : calculer la puissance récupérée par l'échangeur de la VMC pour en déduire l'efficacité réelle (C8-3).",tags:["E5","VMC","Calcul","Puissance air","Formule"]},
  {id:"fed_cta12",prompt:"Lors de la mise en service d'une VMC double flux, dans quel ordre faut-il vérifier les débits ?",choices:["D'abord les bouches de soufflage, puis les bouches d'extraction","D'abord les débits totaux (soufflage + extraction à l'unité centrale), puis les débits aux bouches — équilibrage du plus fort débit au plus faible","Simultanément toutes les bouches","Uniquement les bouches d'extraction"],answer:1,diff:2,explication:"Méthode d'équilibrage séquentiel : (1) Mesurer débit total soufflage et total extraction à l'unité (comparer au nominal). (2) Équilibrer par branche (la plus éloignée d'abord). (3) Ajuster les bouches. (4) Vérification finale de tous les débits. Cette approche évite de régler plusieurs fois. DTU 68.3 impose des débits ± 10% des valeurs de conception. En E5 VMC : cette procédure est évaluée en C7-3 (protocole).",tags:["E5","VMC","Équilibrage aéraulique","Procédure","C7-3","DTU 68.3"]},
  {id:"fed_cta13",prompt:"Le contrôleur TREND IQ3xcite 96/100-240 de la CTA de Limours est :",choices:["Un simple thermostat","Un automate programmable de GTB (Gestion Technique du Bâtiment) qui régule la T° de soufflage, les débits, la qualité d'air et communique avec la supervision","Un variateur de fréquence","Un compteur d'énergie"],answer:1,diff:1,explication:"TREND IQ3xcite : automate de régulation GTB. Programme : régulation T° intérieure avec cascade T° soufflage, gestion boîtes de mélange BM et BM2 (air neuf / recyclé, air neuf / puits canadien), modulation selon CO₂, alarmes. Communication réseau (BACnet ou LON selon version). En E5 CCF Limours : l'étudiant interagit avec ce contrôleur pour paramétrer la CTA.",tags:["E5","CTA","TREND IQ3xcite","GTB","Automate","Limours"]},
  {id:"fed_cta14",prompt:"Lors du réglage des volets d'air neuf en E5 TP3, quel appareil sert à mesurer la vitesse d'air dans les conduits ?",choices:["Thermomètre TESTO 922","Anémomètre à hélice (ou à fil chaud) placé dans la section de mesure du conduit","Manomètre différentiel","Hygromètre"],answer:1,diff:1,explication:"Anémomètre : mesure la vitesse de l'air (m/s). À hélice : convient pour vitesses > 0,3 m/s (bouches, conduits). À fil chaud : mesures fines (< 0,3 m/s, ambiance). En E5 TP3 (Réglage volets air neuf CTA serre) : mesurer V en section connue → qv = V × S × 3600. Comparer au nominal. Ajuster position volet. Re-mesurer. C7-5 : matériel utilisé correctement.",tags:["E5","CTA","Anémomètre","Mesure","Volets","TP3"]},
  {id:"fed_cta15",prompt:"En E5 TP4 (Réglage débits bouches CTA vapeur), comment ajuste-t-on le débit à une bouche de soufflage ?",choices:["En modifiant la fréquence du variateur central","En agissant sur l'obturateur ou le registre intégré à la bouche (rotation de la grille ou vis de réglage) puis en re-mesurant","En coupant l'alimentation électrique de la CTA","En changeant le filtre de la CTA"],answer:1,diff:1,explication:"Réglage d'une bouche de soufflage : agir sur le registre intégré (obturateur à lamelles ou vis centrale). Fermer partiellement pour réduire le débit (si bouche proche de la CTA, pression excédentaire). Ouvrir davantage pour augmenter (bouche éloignée). Méthode : mesure → calcul écart vs nominal → réglage → re-mesure. Kistock RF enregistre les débits mesurés à chaque bouche. En E5 : documenter les réglages dans le compte rendu (C8).",tags:["E5","CTA","Bouches","Équilibrage","TP4","Réglage"]},
  {id:"fed_cta16",prompt:"Quelle réglementation impose les débits minimaux de ventilation dans les ERP (Établissements Recevant du Public) ?",choices:["Uniquement le DTU 68.3 (logements)","L'arrêté du 3 mai 2007 pour les ECS ET l'arrêté du 25 juin 1980 (sécurité ERP) + circulaire sanitaire 9 mai 1985 pour les débits d'air neuf","La NF EN 12831 uniquement","La RE 2020 uniquement"],answer:1,diff:3,explication:"ERP : réglementation ventilation = arrêté sécurité incendie (fumées) + arrêté hygiène. Pour les locaux de travail : Code du travail + arrêté du 8 octobre 1987. DTU 68.3 : logements résidentiels. Valeur clé E5 : 18 m³/h/personne pour salle spectacle, 25-30 m³/h/personne pour bureaux. En E5 C7-2 : citer la réglementation applicable à l'installation évaluée.",tags:["E5","Réglementation","Ventilation","ERP","C7-2"]},
  {id:"fed_cta17",prompt:"Sur le diagramme de l'air humide, la transformation dans la batterie chaude d'une CTA correspond à :",choices:["Une humidification isotherme","Un réchauffement sensible à humidité spécifique constante (droite horizontale vers la droite sur le diagramme, hr diminue à W constant)","Un refroidissement avec condensation","Une transformation adiabatique"],answer:1,diff:3,explication:"Batterie chaude : ajout de chaleur sensible → T° augmente, W (teneur en vapeur) constante → droite horizontale vers la droite sur le diagramme de l'air humide (ou psychrométrique). La hr (humidité relative) diminue car l'air peut contenir plus de vapeur à T° plus haute. En E5 TP2 (bilan batterie chaude) : mesurer T° entrée/sortie de l'air et de l'eau pour calculer puissances et vérifier bilan enthalpique.",tags:["E5","CTA","Diagramme air humide","Batterie chaude","Psychrométrie"]},
  {id:"fed_cta18",prompt:"Le Kistock RF enregistre les mesures de la CTA pendant l'épreuve E5. La durée minimale d'enregistrement recommandée pour avoir un régime stabilisé est :",choices:["30 secondes","Au moins 10-15 minutes après stabilisation des paramètres (T° soufflage stable ± 0,5°C)","5 heures","Une journée complète"],answer:1,diff:2,explication:"Kistock RF : enregistreur de données multi-voies sans fil (sondes débrochables type K ou PT100). En E5 : attendre la stabilisation du régime (T° soufflage stable ≠ en transit) avant de lancer l'enregistrement. Durée recommandée : 10-15 min minimum pour moyenner les fluctuations. Puis exporter les données (logiciel Kimo) → courbe T° vs temps → preuve du régime stabilisé. C6 (40%) : maîtrise du Kistock = note critique.",tags:["E5","Kistock RF","Enregistrement","Régime stabilisé","C6"]},
  {id:"fed_cta19",prompt:"Pour calculer la puissance de la batterie chaude d'une CTA côté eau (P = qv × 1,163 × ΔT), avec qv = 2,5 m³/h et ΔT = 10°C, la puissance est :",choices:["25 kW","29,1 kW (P = 2,5 × 1,163 × 10 = 29,075 ≈ 29,1 kW)","2,9 kW","11,6 kW"],answer:1,diff:1,explication:"P = qv × 1,163 × ΔT = 2,5 × 1,163 × 10 = 29,075 ≈ 29,1 kW. Le débit qv est mesuré avec la vanne TA sur le circuit ECBT alimentant la batterie. ΔT = T_entrée_eau - T_sortie_eau batterie. En E5 TP2 : comparer cette puissance avec la puissance côté air (P_air = 0,34 × qv_air × ΔT_air) → vérification du bilan (écart < 10% acceptable).",tags:["E5","CTA","Batterie chaude","Calcul","Puissance eau"]},
  {id:"fed_cta20",prompt:"L'humidité relative (hr) mesurée par l'hygromètre de la CTA doit être maintenue entre :",choices:["0 et 20% (très sec)","30 et 70% (confort thermique et qualité de l'air — norme ISO 7730)","80 et 100% (très humide)","La hr n'a aucune importance pour le confort"],answer:1,diff:2,explication:"Zone de confort thermique (ISO 7730 / NF EN 15251) : hr entre 30 et 70%, T° entre 20°C et 26°C. En dessous de 30% : irritations muqueuses, poussières. Au-dessus de 70% : risque de condensation sur surfaces froides, développement moisissures, légionelles. La CTA contrôle la hr via la batterie froide (déshumidification) et l'humidificateur (si besoin en hiver).",tags:["E5","CTA","Humidité relative","Confort","ISO 7730"]},
];

// ─── BANQUE E5 : HYDRAULIQUE & ÉQUILIBRAGE ───
export const QB_FED_E5_HYDRAULIQUE = [
  {id:"fed_hyd1",prompt:"La formule de la vanne TA (Kv) pour l'équilibrage hydraulique est :",choices:["Kv = q × √Δp","Kv = 0,01 × q / √Δp (q en l/h, Δp en kPa)","Kv = P / (1,163 × ΔT)","Kv = ΔT / q"],answer:1,diff:2,explication:"Kv vanne TA = 0,01 × q / √Δp (q en l/h, Δp en kPa). Formule constructeur (IMI/TA). Alternative : Kv = 36 × q / √Δp si q en l/s. Le Kv représente le débit en m³/h sous une perte de charge de 1 bar (100 kPa). Lecture sur abaque TA : connaître Kv calculé → positionner le réglage de la vanne. En E5 : calculer Kv pour le débit nominal, puis régler la vanne en conséquence.",tags:["E5","Vanne TA","Kv","Équilibrage","Hydraulique"]},
  {id:"fed_hyd2",prompt:"Pour une puissance P = 70 kW avec ΔT = 15°C dans le réseau ECBT, le débit volumique nécessaire est :",choices:["1,05 m³/h","4,01 m³/h (qv = P / (1,163 × ΔT) = 70 / (1,163 × 15) ≈ 4,01 m³/h)","70 m³/h","10,5 m³/h"],answer:1,diff:2,explication:"qv = P / (1,163 × ΔT) = 70 / (1,163 × 15) = 70 / 17,45 ≈ 4,01 m³/h. C'est la formule inverse de P = qv × 1,163 × ΔT. Application E5 TP1 (bilan chaudière) : pour vérifier que la vanne TA est réglée au bon débit pour atteindre la puissance nominale. Puis calculer Kv pour ce débit et lire la position de réglage sur l'abaque.",tags:["E5","Hydraulique","Calcul","Débit","ECBT","Vanne TA"]},
  {id:"fed_hyd3",prompt:"La correction de débit pour un fluide glycolé (densité γ = 1,05 t/m³) sur une vanne TA est :",choices:["Aucune correction nécessaire","Débit réel = q_CBI / √γ = q_CBI / √1,05 ≈ q_CBI / 1,025 (le débit réel est légèrement inférieur à celui affiché)","Débit réel = q_CBI × γ","Débit réel = q_CBI × 2"],answer:1,diff:3,explication:"La vanne TA est étalonnée pour l'eau pure (γ = 1 t/m³). Pour un fluide glycolé (γ > 1) : Débit réel = q_affiché / √γ. Pour γ = 1,05 : Débit réel = q_CBI / 1,025 ≈ débit affiché × 0,975. Erreur de ~2,5% pour 20% de glycol → souvent négligeable. Pour 40% glycol (γ ≈ 1,08) : erreur ~4%. En E5 : si fluide glycolé identifié dans le dossier, mentionner cette correction (C7-6).",tags:["E5","Vanne TA","Glycol","Correction","Hydraulique"]},
  {id:"fed_hyd4",prompt:"Le circulateur SALMSON SCX 32-80 DN32 du réseau ECBT fonctionne en triphasé 400V. Sa vitesse de rotation sur la vitesse 3 est de :",choices:["1 000 tr/min","2 665 tr/min (vitesses disponibles : 1900/2280/2665 tr/min pour 3 vitesses)","3 000 tr/min","500 tr/min"],answer:1,diff:3,explication:"SALMSON SCX 32-80 : circulateur triphasé 400V/50Hz, 2 pôles. 3 vitesses disponibles : vitesse 1 = 1 900 tr/min, vitesse 2 = 2 280 tr/min, vitesse 3 = 2 665 tr/min. La vitesse 3 correspond à la vitesse maximale (débit/HMT maximaux). En E5 TP1 : pour mesurer le débit nominal, le circulateur doit fonctionner en régime stabilisé à la vitesse spécifiée dans le dossier technique.",tags:["E5","Circulateur","SALMSON","Hydraulique","ECBT"]},
  {id:"fed_hyd5",prompt:"Une vanne TA ne doit jamais être installée immédiatement en aval d'une pompe car :",choices:["La pompe peut la bloquer mécaniquement","Les turbulences en aval de la pompe perturbent le profil d'écoulement → erreur de mesure jusqu'à ±10%","La pression est trop élevée","Elle s'abîme avec le bruit"],answer:1,diff:2,explication:"Règle d'installation vanne TA : distance minimale de 5 diamètres (5D) en amont et 2D en aval de toute perturbation (coude, pompe, vanne d'arrêt). Aval pompe : turbulences → profil de vitesse non établi → mesure de débit incorrecte. Un profil établi = conditions d'écoulement laminaire/turbulent stables nécessaires à la précision de mesure. En E5 : signaler ce point dans le compte rendu d'intervention.",tags:["E5","Vanne TA","Installation","Turbulences","Métrologie"]},
  {id:"fed_hyd6",prompt:"La vanne 3 voies (V3V) en mélange permet de :",choices:["Couper complètement le débit","Mélanger le débit chaud (circuit primaire) et le débit froid (retour) pour obtenir une T° départ régulée — utilisée pour la régulation loi d'eau","Mesurer le débit","Filtrer les impuretés"],answer:1,diff:2,explication:"V3V en mélange : 3 ports (départ chaud C, retour froid B, sortie mélange M). Actionneur modulant (0-10V ou 3 points). Position 100% C = tout chaud, position 0% C = tout retour. La régulation ajuste continuellement la V3V pour maintenir T_départ réseau selon la loi d'eau. En E5 TP2 (bilan batterie chaude) : ouvrir V3V à 100% pour les mesures de puissance nominale.",tags:["E5","Vanne 3 voies","V3V","Régulation","Loi d'eau","ECBT"]},
  {id:"fed_hyd7",prompt:"Le manomètre différentiel (ou débitmètre par différence de pression) mesure un débit en :",choices:["Mesurant directement le volume d'eau","Mesurant la différence de pression (ΔP) aux bornes d'un organe calibré (vanne TA, débitmètre venturi) puis en utilisant la relation q = f(√ΔP)","Mesurant la température de l'eau","Comptant les impulsions d'un turbinage"],answer:1,diff:2,explication:"Vanne TA à mesure différentielle : prises de pression en amont/aval → ΔP = f(q²). Relation : q = Kv × √ΔP. Lecture sur le manomètre différentiel TA (STAD, STAF) : graduation directement en l/h ou m³/h. PCE-HAWA30 est un débitmètre à ultrasons clamp-on alternatif (non invasif). En E5 : utiliser la procédure correcte (robinets de purge, prise de pression, lecture).",tags:["E5","Vanne TA","Manomètre différentiel","Mesure","Débit"]},
  {id:"fed_hyd8",prompt:"Le PCE-HAWA30 est un appareil de mesure de débit :",choices:["Par calorimétrie (T° entrée/sortie)","Par ultrasons à pincement externe (clamp-on) — mesure non invasive sur tuyau en place sans interruption du circuit","Par différence de pression","Par turbinage à hélice interne"],answer:1,diff:2,explication:"PCE-HAWA30 : débitmètre à ultrasons externe. 2 transducteurs collés sur l'extérieur du tuyau → mesure par temps de transit des ultrasons. Avantages : non invasif (pas de purge, pas de fuite), instantané, tous fluides. Inconvénients : précision ± 2-3%, nécessite tuyau plein, connaître matière et diamètre du tuyau. En E5 : alternative rapide à la vanne TA pour vérifier les débits (C7-5).",tags:["E5","PCE-HAWA30","Débitmètre ultrasons","Mesure non invasive","Débit"]},
  {id:"fed_hyd9",prompt:"Pour vérifier qu'une installation ECBT est à l'équilibre hydraulique, on vérifie que :",choices:["La pression en tous points est identique","Le débit mesuré à chaque sous-station correspond au débit nominal (± 5-10%) → tous les émetteurs reçoivent la puissance prévue","La température est uniforme dans tout le réseau","Le circulateur tourne à la vitesse maximale"],answer:1,diff:2,explication:"Équilibrage hydraulique : objectif = que chaque branche/sous-station reçoive le débit pour lequel elle a été dimensionnée. Sans équilibrage : les branches courtes (pression disponible élevée) volent le débit des branches longues → certains radiateurs froids, certains trop chauds. Méthode : vanne TA réglée sur Kv calculé pour chaque branche, mesure débit, ajustement. En E5 TP CHILI : équilibrage réseau ECBT 014.",tags:["E5","Équilibrage","ECBT","Hydraulique","Vanne TA","Débit nominal"]},
  {id:"fed_hyd10",prompt:"Le TESTO 922 (thermomètre différentiel 2 canaux) utilisé en E5 permet de mesurer :",choices:["Uniquement la température ambiante","2 températures simultanées (thermocouple type K, -50°C à +1000°C) ET leur différence ΔT — idéal pour mesurer ΔT sur une batterie ou un échangeur","La pression hydraulique","Le débit d'air"],answer:1,diff:1,explication:"TESTO 922 : 2 entrées thermocouple K. Mesure T°1, T°2 et ΔT = T°1 - T°2. Précision : ±(0,5°C + 0,3% v.m.). Résolution 0,1°C. Idéal pour : ΔT batterie chaude/froide, ΔT échangeur, ΔT chaudière. En E5 TP2 (bilan CTA) et sujets ECBT : brancher canal 1 sur entrée eau froide (retour), canal 2 sur sortie eau chaude (aller) → lire ΔT directement. Vérifier l'étalonnage avant usage.",tags:["E5","TESTO 922","Thermomètre","ΔT","Batterie","Mesure"]},
  {id:"fed_hyd11",prompt:"Lors d'une mesure de débit à la vanne TA avec le manomètre STAD, pourquoi faut-il purger les raccords de mesure avant de lire ?",choices:["Pour économiser l'eau","Pour éliminer les bulles d'air qui fausseraient la mesure de pression différentielle → lecture incorrecte du débit","Pour réchauffer le manomètre","Par obligation réglementaire"],answer:1,diff:2,explication:"Bulles d'air dans les tuyaux de raccordement du manomètre différentiel → variation de ΔP lue → débit affiché faux. Procédure : ouvrir robinets de prise de pression, purger jusqu'à apparition d'eau continue (sans bulles), fermer robinet de by-pass, lire la valeur stabilisée. Cette précaution relève de C7-3 (protocole) et C7-5 (utilisation correcte des appareils).",tags:["E5","Vanne TA","Mesure","Purge","Manomètre","Bulles d'air"]},
  {id:"fed_hyd12",prompt:"Calculer qv pour P = 30 kW, ΔT = 10°C (formule eau) :",choices:["30 m³/h","2,58 m³/h (qv = 30 / (1,163 × 10) ≈ 2,58 m³/h)","0,3 m³/h","103 m³/h"],answer:1,diff:1,explication:"qv = P / (1,163 × ΔT) = 30 / (1,163 × 10) = 30 / 11,63 ≈ 2,58 m³/h. Application directe E5 TP2 : \'Régler la vanne TA pour obtenir P = 30 kW avec ΔT = 10°C\'. → Calculer qv = 2,58 m³/h → Calculer Kv = 0,01 × 2580 / √ΔP → Lire position de réglage sur abaque TA. Valeur à mémoriser : 1,163 kW·h/(m³·°C) est le produit ρ × Cp de l'eau divisé par 3600.",tags:["E5","Calcul","Vanne TA","Débit","Puissance","Hydraulique"]},
];

// ─── BANQUE E5 : RÉGULATION & CHAUDIÈRE ───
export const QB_FED_E5_REGUL = [
  {id:"fed_reg_e5_1",prompt:"La loi d'eau (ou courbe de chauffe) d'un régulateur relie :",choices:["La consommation de gaz à la température extérieure","La température de départ réseau à la température extérieure — T_départ = f(T_ext) pour maintenir le confort","La pression à la température","Le débit à la température"],answer:1,diff:1,explication:"Loi d'eau : courbe programmée dans le régulateur. Quand T_ext diminue → T_départ réseau augmente. Exemple RMH760B : régime 60/40 signifie T_aller = 60°C quand T_ext = T°_base (-5°C), T_aller = 40°C quand T_ext = 20°C. La droite de chauffe est ajustée par la pente (écart max) et la translation (confort). En E5 : tracer cette droite sur graphe et vérifier les 3 points de fonctionnement (-5°C, +5°C, +15°C).",tags:["E5","Régulation","Loi d'eau","Droite de chauffe","RMH760"]},
  {id:"fed_reg_e5_2",prompt:"Pour un régime 60/40 et T°_base = -5°C, la consigne départ réseau à T_ext = +5°C est :",choices:["60°C","52°C environ — interpolation linéaire entre 60°C (-5°C ext) et 40°C (+20°C ext) → à +5°C : 60 - (5+5)/(20+5) × 20 ≈ 52°C","40°C","70°C"],answer:1,diff:3,explication:"Droite de chauffe régime 60/40 : T_départ = 60°C à -5°C, T_départ = 40°C à +20°C. Pente = (60-40)/(-5-20) = 20/25 = -0,8°C/°C extérieur. À T_ext = +5°C : T_départ = 60 + (-0,8) × (-5-5) = 60 + 8 = 52°C. En E5 sujet RMH760B : calculer les 3 consignes pour T_ext = -5°C (60°C), +5°C (52°C), +15°C (44°C) et vérifier sur synoptique GTC.",tags:["E5","Régulation","Loi d'eau","Calcul","RMH760"]},
  {id:"fed_reg_e5_3",prompt:"Le régulateur Siemens RMH760B contrôle l'installation en utilisant quel type de bus de communication ?",choices:["KNX","LPB (Local Process Bus) — protocole Siemens propriétaire pour la communication entre régulateurs","BACnet","Modbus TCP"],answer:1,diff:2,explication:"LPB (Local Process Bus) : protocole Siemens propriétaire, 2 fils (LPB+, LPB-), topologie bus. Permet la communication entre le régulateur RMH760B et les modules d'extension (RMZ781), les sondes intelligentes et les cascades de chaudières. Vitesse 1 200 baud. Différent du KNX (topologie identique mais protocoles incompatibles). En E5 : identifier les bornes LPB dans le schéma de câblage du RMH760B.",tags:["E5","RMH760","LPB","Siemens","Bus","Communication"]},
  {id:"fed_reg_e5_4",prompt:"Le logiciel ACS (Advanced Configuration Software) de Siemens est utilisé pour :",choices:["Dessiner les plans des installations","Paramétrer, mettre en service et diagnostiquer les régulateurs Siemens (RMH760, RVS, RVA...) via une connexion PC","Calculer les déperditions du bâtiment","Dessiner les schémas hydrauliques"],answer:1,diff:2,explication:"ACS700 (ou ACS790) : logiciel PC Siemens pour configuration des régulateurs de la gamme Synco et ancienne gamme. Connexion via interface OCI700 (port USB). Fonctions : lecture/écriture de tous les paramètres, diagnostic des températures et états, sauvegarde/restauration de configurations, historique alarmes. En E5 sujet ECS/régulation : accès logiciel ACS = compétence C6 si demandé dans le sujet.",tags:["E5","RMH760","ACS","Siemens","Paramétrage","Logiciel"]},
  {id:"fed_reg_e5_5",prompt:"Le débit d'un gicleur fioul de calibre 0,75 Usgal/h sous 10 bar de pression de pulvérisation est :",choices:["0,75 l/h","3,04 l/h (Débit = 0,75 × 3,78 × (10/7)^0,5 = 2,835 × 1,195 ≈ 3,39 l/h)","7,56 l/h","1 l/h"],answer:1,diff:3,explication:"Formule : Débit (l/h) = Calibre × 3,78 × (P_pulvérisation / 7)^0,5. Avec calibre = 0,75 Usgal/h et P = 10 bar : Débit = 0,75 × 3,78 × (10/7)^0,5 = 2,835 × 1,195 ≈ 3,39 l/h. Note : sous 7 bar (pression nominale) : Débit = 0,75 × 3,78 × 1 = 2,835 l/h. Le gicleur est l'organe de pulvérisation du fioul dans le brûleur. Son calibre (Usgal/h) détermine la puissance maximale de la chaudière.",tags:["E5","Fioul","Gicleur","Calcul","Combustion","RMH760"]},
  {id:"fed_reg_e5_6",prompt:"La composition du fioul domestique (FOD) est approximativement :",choices:["CH₄ uniquement (méthane comme le gaz)","C 84,3%, H₂ 12,4%, S 0,5%, O₂ 2%, N₂ 0,8% (mélange d'hydrocarbures lourds)","C 50%, H₂ 50%","CO₂ et H₂O uniquement"],answer:1,diff:3,explication:"FOD (fioul domestique = gazole de chauffage) : hydrocarbures à longue chaîne (C10-C25). Composition massique : C ≈ 84-86%, H ≈ 12-14%, S ≈ 0,1-0,5%, impuretés (N, O). Air théorique ≈ 11,24 m³/kg. Pouvoir calorifique inférieur PCI = 41 992 kJ/kg ≈ 11,7 kWh/kg. Masse volumique ≈ 840-850 kg/m³. Le soufre S → SO₂ → pluies acides → réglementations sur teneur en S (< 0,1% depuis 2000).",tags:["E5","Fioul","FOD","Composition","Combustion","PCI"]},
  {id:"fed_reg_e5_7",prompt:"Lors d'une analyse de combustion en E5 (chaudière fioul ou gaz), les 4 mesures clés à relever sont :",choices:["Tension, intensité, cos φ, puissance","CO₂ (ou O₂), CO, T° fumées, indice de Bacharach (pour fioul) — permettant de calculer le rendement PCI via la formule de Siegert","HR, T° ambiante, pression, débit air","pH, conductivité, turbidité, dureté"],answer:1,diff:1,explication:"Analyse combustion chaudière : (1) CO₂% ou O₂% → taux d'excès d'air, (2) CO ppm → qualité de combustion (mauvaise si > 100 ppm), (3) T° fumées (°C) → pertes par les fumées, (4) Indice de Bacharach (fioul) → teneur en suies (0=propre, 9=très encrassé, max admis = 4). Ces 4 valeurs permettent le calcul du rendement via la formule de Siegert : η = 100 - q_A - q_K (pertes fumées sensibles et chimiques).",tags:["E5","Combustion","Analyse fumées","Rendement","Siegert","Chaudière"]},
  {id:"fed_reg_e5_8",prompt:"Le schéma type H3-2 du régulateur RMH760B correspond à :",choices:["Un seul circuit direct sans régulation","Un circuit chaudière + 1 circuit de distribution régulé par vanne 3 voies — type standard réseau radiateurs avec régulation loi d'eau","Une installation tri-énergie","Un circuit solaire avec appoint"],answer:1,diff:3,explication:"RMH760B schémas hydrauliques : H1 = circuit direct chaudière seule. H3 = chaudière + 1 circuit régulé (V3V ou circulateur). H3-2 = chaudière + circuit secondaire régulé par vanne 3 voies + régulation loi d'eau + abaissement nuit. C'est le schéma classique d'une installation résidentielle ou petit tertiaire avec radiateurs. Le composant M11 = actionneur V3V, Y11 = vanne 3 voies, B11 = sonde départ réseau.",tags:["E5","RMH760","Schéma H3-2","Hydraulique","Régulation"]},
  {id:"fed_reg_e5_9",prompt:"L'abaissement de nuit programmé dans le RMH760B (3°C de moins que le jour) signifie :",choices:["Que la chaudière s'arrête complètement la nuit","Que la consigne de confort intérieur passe de 21°C le jour à 18°C la nuit — la droite de chauffe est décalée vers le bas de 3°C","Que le circulateur s'arrête","Que la T° des fumées diminue"],answer:1,diff:2,explication:"Abaissement : dans le sujet RMH760B, la consigne jour = 21°C, abaissement nuit = 3°C → consigne nuit = 18°C. La droite de chauffe est translatée vers le bas de ΔT correspondant → T_départ réseau réduite la nuit. Économie d'énergie 10-15%. Anti-gel actif (consigne 9°C dans le sujet). Programme horaire : confort 7h-17h, réduit reste journée, 7j/7. En E5 : paramétrer correctement le programme horaire dans le RMH760B.",tags:["E5","RMH760","Abaissement","Programme horaire","Économie d'énergie"]},
  {id:"fed_reg_e5_10",prompt:"Lors du contrôle de la chaudière condensation Atlantic (Ponct 2 condensinox), le rendement PCI minimum à vérifier est :",choices:["80%","≥ 94% (exigence chaudière à condensation — justifie le label THPE / avantage fiscal)","70%","100%"],answer:1,diff:2,explication:"Chaudière à condensation : rendement PCI ≥ 100% théoriquement possible car récupération de la chaleur latente de condensation des fumées (H₂O). Rendement PCI réglementaire pour la qualification \'condensation\' : ≥ 94% selon la directive rendement (92/42/CEE). En pratique : 97-107% selon les conditions. En E5 condensinox : mesurer O₂%, CO₂, T° fumées → calculer rendement par Siegert → vérifier que la valeur dépasse 94% pour valider la conformité RT existant (Arrêté 3 mai 2007).",tags:["E5","Condensation","Rendement PCI","Atlantic","Condensinox","Réglementation"]},
  {id:"fed_reg_e5_11",prompt:"La tablette CozytouchC (Atlantic) dans un sujet E5 condensation sert à :",choices:["Mesurer les températures de fumées","Paramétrer et mettre en service la chaudière à condensation Atlantic via une interface tactile Bluetooth/Wi-Fi — remplace l'interface locale du régulateur","Enregistrer les données Kistock RF","Équilibrer le réseau hydraulique"],answer:1,diff:2,explication:"CozytouchC : tablette tactile propriétaire Atlantic pour la mise en service des chaudières condensation Atlantic (remplace l'ancien boîtier de mise en service filaire). Connexion Bluetooth. Fonctions : réglage loi d'eau, paramétrage ECS, diagnostic, lecture capteurs. En E5 : maîtriser la tablette CozytouchC = compétence C6 (40%). Si mal maîtrisée → note maximale limitée à ~12/20.",tags:["E5","CozytouchC","Atlantic","Condensation","C6","Paramétrage"]},
  {id:"fed_reg_e5_12",prompt:"Le saison de chauffe programmée dans le RMH760B (sujet 2026) couvre du 12/10 au 28/03. Cela signifie :",choices:["La chaudière est éteinte en dehors de cette période","La chaudière fonctionne uniquement en mode automatique pendant cette période — en dehors, mode été (ECS uniquement si applicable)","La chaudière fonctionne en mode manuel toute l'année","Le programme horaire ne s'applique que pendant cette période"],answer:0,diff:2,explication:"La saison de chauffe (ou programme annuel) dans le RMH760B définit les dates d'activation du chauffage. Du 12/10 au 28/03 : mode chauffage actif selon la loi d'eau et le programme horaire. Hors saison : mode été (chauffage inactif, ECS possible si raccordée). La chaudière peut toujours être forcée manuellement. En E5 : paramétrer cette plage dans le régulateur = C6.",tags:["E5","RMH760","Saison de chauffe","Programme","Paramétrage"]},
];

// ─── BANQUE E5 : KNX & GTB ETS5 ───
export const QB_FED_E5_KNX = [
  {id:"fed_knx_e5_1",prompt:"Dans la programmation ETS5 pour un sujet KNX E5, la première étape est :",choices:["Câbler les bus KNX","Créer le projet → ajouter les participants (avec leur référence catalogue) → affecter les adresses physiques via le bouton de programmation","Configurer la supervision","Mesurer les tensions du bus"],answer:1,diff:1,explication:"Démarche ETS5 : (1) Créer projet (nommer, choisir médium TP). (2) Ajouter les appareils depuis le catalogue (référence MTN, Schneider, ABB...). (3) Affecter adresses physiques (1.1.1, 1.1.2...) via bouton de programmation sur chaque appareil. (4) Configurer les objets de communication. (5) Créer les adresses de groupe. (6) Lier objets → adresses de groupe. (7) Télécharger dans chaque appareil. C6 = 40% de la note : maîtrise ETS5 essentielle.",tags:["E5","KNX","ETS5","Programmation","C6"]},
  {id:"fed_knx_e5_2",prompt:"L'adresse physique 1.1.5 dans un réseau KNX correspond à :",choices:["Zone 1, ligne 1, appareil 5 — adresse individuelle unique de l'appareil sur le bus (ici l'actionneur de variation dans le sujet EVA Studios)","Une adresse de groupe","Une adresse IP","Une adresse MAC Ethernet"],answer:0,diff:2,explication:"Adresse physique KNX : format X.Y.Z = Zone.Ligne.Appareil. 1.1.5 = Zone 1, Ligne 1, Appareil 5. Dans le sujet E5 KNX EVA Studios : adresse 1.1.5 = actionneur de variation (MTN649350). Chaque appareil a une adresse physique unique pour la configuration ETS5. L'adresse de groupe (ex : 0/1/1) est différente : elle définit la fonction logique (bouton commande une sortie).",tags:["E5","KNX","Adresse physique","ETS5","EVA Studios"]},
  {id:"fed_knx_e5_3",prompt:"Dans le sujet E5 KNX EVA Studios, le scénario 1 doit allumer E1 et E2 à 20% et descendre les volets. Cela nécessite :",choices:["3 adresses de groupe séparées","Un objet 'scénario' (scene) qui envoie simultanément 3 télégrammes préprogrammés (valeur 20% sur E1, valeur 20% sur E2, commande descente VR)","Une reprogrammation matérielle","Un variateur supplémentaire"],answer:1,diff:3,explication:"Scénario KNX : objet de communication de type 'scene' (DPT 18.001). Une touche peut déclencher un scénario qui envoie plusieurs valeurs simultanément (E1=20%, E2=20%, VR=descente). Configuration dans ETS5 : créer le scénario dans l'actionneur correspondant, définir les valeurs cibles, lier l'objet scénario à l'adresse de groupe dédiée. En E5 : les scénarios sont courants dans les sujets KNX hôtels/ERP.",tags:["E5","KNX","Scénario","ETS5","Objet","EVA Studios"]},
  {id:"fed_knx_e5_4",prompt:"La commande générale ON/OFF de l'éclairage dans le sujet EVA Studios utilise :",choices:["Un bouton spécial \'master\'","Une adresse de groupe commune liée à tous les actionneurs d'éclairage → un seul télégramme ON/OFF commande tous les circuits","Un interrupteur physique centralisé","Une commande vocale"],answer:1,diff:2,explication:"Commande générale KNX : créer une adresse de groupe \'maître\' (ex : 0/0/1). Lier cette adresse en écriture à l'objet \'ON/OFF\' de chaque actionneur (E1, E2, E3). Un seul télégramme ON (1) ou OFF (0) commande tous les circuits. Dans le sujet EVA Studios : touche 'All ON/OFF' de la commande 8 touches S1. En E5 : cette logique multi-binding est fondamentale en KNX.",tags:["E5","KNX","Commande générale","Adresse de groupe","ETS5"]},
  {id:"fed_knx_e5_5",prompt:"Dans le sujet KNX EVA Studios, le détecteur de présence ARGUS 360° (1.1.6) gère l'éclairage couloir E4. Pour vérifier ses performances, on mesure :",choices:["La tension bus KNX","Le niveau d'éclairement (lux) en plusieurs points du couloir à l'aide d'un luxmètre, en comparant aux exigences de la norme EN 12464-1","La consommation électrique des luminaires","La T° ambiante"],answer:1,diff:2,explication:"Norme EN 12464-1 (éclairage des lieux de travail intérieurs) : couloirs de circulation → Ēm ≥ 100 lux. Mesure au luxmètre (appareil mesurant l'éclairement en lux sur une surface). En E5 C8 : mesurer en plusieurs points (milieu couloir, extrémités), calculer la valeur moyenne Ēm, comparer à 100 lux. Si inférieur : proposer une action corrective (changer les luminaires, rapprocher, augmenter la puissance). C7-5 : utilisation correcte du luxmètre.",tags:["E5","KNX","Détecteur présence","ARGUS","Éclairage","Luxmètre","EN 12464"]},
  {id:"fed_knx_e5_6",prompt:"La différence entre l'actionneur de commutation (1.1.3) et l'actionneur de variation (1.1.5) dans le sujet KNX est :",choices:["Uniquement leur prix","Commutation = ON/OFF tout ou rien (pour télérupteur E3). Variation = gradation 0-100% (pour E1 et E2 via bus KNX, DPT 5.001 = 1 byte)","Commutation = triphasé, Variation = monophasé","Aucune différence fonctionnelle"],answer:1,diff:2,explication:"Actionneur de commutation : sorties relais ON/OFF → commande éclairage non gradable, télérupteur (E3 dans le sujet). Actionneur de variation (dimmer) : sortie gradation (0-100%) → commande éclairage gradable (E1, E2). Dans ETS5 : l'objet de l'actionneur variation est de type DPT 5.001 (1 octet, 0-255 = 0-100%). La touche 'variation +/-' envoie des télégrammes DPT 3.007 (augmenter/diminuer de X%).",tags:["E5","KNX","Actionneur","Commutation","Variation","ETS5"]},
  {id:"fed_knx_e5_7",prompt:"Lors d'une maintenance KNX en E5 (diagnostic studio 11), la première étape du protocole est :",choices:["Remplacer tous les appareils","Analyser le symptôme → vérifier l'alimentation bus (tension 29-31V DC sur les fils KNX) → vérifier les connexions → identifier l'appareil défaillant via ETS5 (test communication)","Contacter le fabricant","Débrancher tout le bus"],answer:1,diff:2,explication:"Protocole diagnostic KNX : (1) Symptôme (quelle fonction ne marche pas). (2) Vérification alimentation bus (29-31V DC entre les fils KNX vert et rouge). (3) Test communication ETS5 (lecture/écriture de l'appareil suspect). (4) Vérification câblage (court-circuit, mauvaise connexion). (5) Test de fonctionnement des appareils individuellement. (6) Conclusion et action corrective. En E5 B (maintenance) : rédiger ce protocole = points C7-3.",tags:["E5","KNX","Maintenance","Diagnostic","Protocole","ETS5"]},
  {id:"fed_knx_e5_8",prompt:"La passerelle KNX/LPB mentionnée dans le sujet ECS régulation permet de :",choices:["Convertir 230V AC en 24V DC","Faire communiquer le bus KNX (domotique/GTB) avec le bus LPB Siemens (régulation chaudière) — intégration dans la supervision globale du bâtiment","Alimenter les capteurs solaires","Mesurer le débit ECS"],answer:1,diff:3,explication:"Passerelle KNX/LPB : interface de traduction de protocoles. KNX (domotique, éclairage, stores, accès) ↔ LPB Siemens (régulation chaudière, chauffage). Permet à la supervision GTB KNX de lire les valeurs du régulateur de chauffage (T° départ, T° ext, alarmes) et de lui envoyer des consignes (changement de programme, mode forcé). Intégration système complète dans les bâtiments tertiaires modernes.",tags:["E5","KNX","LPB","Passerelle","Intégration","GTB"]},
];

// ─── BANQUE E5 : ECS SOLAIRE ───
export const QB_FED_E5_ECS = [
  {id:"fed_ecs_e5_1",prompt:"Le régulateur SKSC3 Sonnenkraft d'un système ECS solaire dispose de combien d'entrées sondes ?",choices:["2 entrées","8 entrées PT1000 (F1 à F8) + 1 entrée capteur d'ensoleillement CS10","4 entrées","16 entrées"],answer:1,diff:2,explication:"SKSC3 Sonnenkraft : 8 entrées sondes PT1000 (F1-F8) pour mesure températures (capteur, ballon, eau froide, eau mitigée...) + 1 entrée capteur d'ensoleillement CS10 (intensité en W/m²). 3 régulations différentielles configurables. 4 sorties relais dont 3 sorties pompe tachymétrique. Alimentation 230V AC. En E5 CCF ECS : raccorder la sonde PT1000 retour panneau sur F1 = compétence C6.",tags:["E5","ECS solaire","SKSC3","Sonnenkraft","PT1000","Sondes"]},
  {id:"fed_ecs_e5_2",prompt:"Comment distinguer une sonde PT100 d'une sonde PT1000 sans documentation ?",choices:["Par la couleur du câble uniquement","Par mesure à l'ohmmètre : PT100 = 100Ω à 0°C, PT1000 = 1000Ω à 0°C — à température ambiante (~20°C) : PT100 ≈ 107,8Ω, PT1000 ≈ 1078Ω","Par la taille du capteur","Par la tension d'alimentation"],answer:1,diff:2,explication:"Sonde PT : résistance varie linéairement avec T°. PT100 : R₀ = 100Ω à 0°C, α ≈ 0,385 Ω/°C. PT1000 : R₀ = 1000Ω à 0°C, α ≈ 3,85 Ω/°C. À 20°C : PT100 ≈ 107,8Ω, PT1000 ≈ 1078Ω. Mesure avec ohmmètre (câble déconnecté !). En E5 CCF ECS : identifier le type de sonde livré avec l'installation → vérifier compatibilité avec l'entrée SKSC3 (PT1000) → raccorder.",tags:["E5","ECS solaire","PT1000","PT100","Identification","Ohmmètre"]},
  {id:"fed_ecs_e5_3",prompt:"Le fluide caloporteur utilisé dans le circuit solaire thermique du sujet CCF Limours est :",choices:["Eau pure","Eau glycolée à 20% — protection antigel, point de congélation ≈ -8°C","Huile thermique","Frigorigène R410A"],answer:1,diff:1,explication:"Circuit primaire solaire : eau glycolée (propylène glycol ou éthylène glycol) pour protection antigel (T° capteur peut descendre à -10°C ou moins la nuit). Concentration 20% → protection jusqu'à -8°C environ. Concentration 40% → protection jusqu'à -23°C. Le glycol modifie légèrement la capacité thermique et la viscosité (formule correction vanne TA). En E5 : noter la concentration du fluide dans le compte rendu (C7-4).",tags:["E5","ECS solaire","Glycol","Fluide caloporteur","Antigel"]},
  {id:"fed_ecs_e5_4",prompt:"L'entrée F1 du régulateur SKSC3 Sonnenkraft est affectée à :",choices:["L'eau froide du réseau","Le retour panneau solaire (T° la plus froide du circuit primaire = point de comparaison pour la régulation différentielle)","Le ballon ECS","L'ensoleillement"],answer:0,diff:2,explication:"Affectation entrées SKSC3 dans le sujet CCF Limours : F1 = retour panneau, F2 = ballon ECS, F4 = eau chaude, F5 = eau mitigée, F6 = eau froide, F7 = aller panneau, F8 = volumètre V40 (compteur énergie), CS10 = intensité rayonnement solaire. La régulation différentielle compare T_F7 (aller panneau) - T_F2 (ballon) : si ΔT > seuil haut (ex 5°C) → pompe ON. Si ΔT < seuil bas (ex 2°C) → pompe OFF.",tags:["E5","ECS solaire","SKSC3","F1","Régulation différentielle"]},
  {id:"fed_ecs_e5_5",prompt:"La régulation anti-légionellose dans un système ECS solaire impose :",choices:["Une T° de 30°C dans le ballon","Un maintien périodique du ballon à ≥ 60°C (arrêté du 3 mai 2007) avec une purge thermique hebdomadaire pour éliminer les légionelles","Une filtration UV obligatoire","Un traitement chimique quotidien"],answer:1,diff:1,explication:"Légionellose : bactérie Legionella pneumophila se développe à 25-45°C, détruite en quelques minutes à 60°C. Arrêté du 3 mai 2007 (ECS collective) : T° ballon ≥ 60°C en production, T° distribution ≥ 50°C en tous points. Purge thermique (= choc thermique) hebdomadaire recommandée. SKSC3 : fonction limitation T° max ballon + activation résistance appoint pour purge thermique automatique. En E5 : vérifier que la T° F2 (ballon) atteint 60°C en production.",tags:["E5","ECS solaire","Légionellose","Arrêté 2007","60°C","Sécurité"]},
  {id:"fed_ecs_e5_6",prompt:"La sortie A1 du régulateur SKSC3 (pompe tachymétrique) permet de :",choices:["Uniquement mettre la pompe en marche/arrêt","Faire varier la vitesse de la pompe du circuit primaire solaire en modulant le signal tachymétrique → optimisation du transfert d'énergie selon l'ensoleillement","Alimenter le ballon en électricité","Ouvrir une vanne motorisée"],answer:1,diff:2,explication:"Sortie pompe tachymétrique SKSC3 : 1A/250V AC avec signal de contrôle de vitesse (via modulation). Permet de faire varier la vitesse de la pompe solaire en fonction de l'écart ΔT capteur-ballon et de l'intensité solaire (CS10). Plus l'ensoleillement est fort → débit augmente → meilleure extraction de l'énergie. Mode standard (ON/OFF simple) aussi possible (sans tachymétrie).",tags:["E5","ECS solaire","SKSC3","Pompe tachymétrique","Variation vitesse"]},
  {id:"fed_ecs_e5_7",prompt:"Pour vérifier les performances d'un capteur solaire en E5, on calcule son rendement par :",choices:["η = T° panneau / T° ambiante","η = P_récupérée / P_incidente = (qv × 1,163 × ΔT) / (G × A_capteur) — G en W/m², A en m²","η = COP solaire","η = durée ensoleillement / 24h"],answer:1,diff:3,explication:"Rendement capteur solaire : η = Pu / Pi. Pi = G (W/m²) × A_capteur (m²) = puissance incidente. Pu = qv × 1,163 × ΔT = puissance récupérée (côté fluide caloporteur). G mesuré par le capteur CS10 (pyranomètre). En E5 : si G = 700 W/m², A = 2 m², qv = 0,1 m³/h, ΔT = 20°C : Pu = 0,1 × 1,163 × 20 = 2,33 kW. Pi = 700 × 2 = 1 400 W = 1,4 kW. η = 2,33/1,4 = 1,66 → erreur ! Vérifier unités (G en kW/m²).",tags:["E5","ECS solaire","Rendement capteur","Calcul","CS10"]},
];

export const QB_FED_PHOTOVOLTAIQUE2 = [
  {id:"fed_pv2_1",prompt:"La puissance-crête (Wc) d'un panneau photovoltaïque est mesurée dans les conditions standard de test (STC) qui sont :",choices:["1000 W/m², 25°C de température cellule, AM 1,0","1000 W/m², 25°C de température cellule, AM 1,5 (spectre solaire normalisé)","800 W/m², 20°C, AM 1,0","500 W/m², 50°C, AM 2,0"],answer:1,diff:2,explication:"STC (Standard Test Conditions) : irradiance 1000 W/m², température cellule 25°C, spectre solaire AM 1,5 (Air Mass 1,5). Ces conditions permettent la comparaison entre panneaux. En conditions réelles, la production est souvent inférieure (température cellule > 25°C → rendement ↓ pour Si cristallin : -0,4%/°C). NOCT (Nominal Operating Cell Temperature) : 800 W/m², 20°C air, vent 1 m/s.",tags:["STC","Puissance-crête","Wc","AM 1,5","Photovoltaïque"]},
  {id:"fed_pv2_2",prompt:"La technologie silicium monocristallin (mono-Si) se distingue du polycristallin (poly-Si) par :",choices:["Un rendement plus faible (8-12%) et un coût plus bas","Un rendement plus élevé (18-22%) et un coût de fabrication plus élevé — meilleure performance en faible luminosité","Un rendement identique et un aspect uniforme","Une durée de vie inférieure (5-10 ans)"],answer:1,diff:2,explication:"Mono-Si (monocristallin) : cristal unique, aspect uniforme, rendement 18-22% (cellule), durée de vie 25-30 ans, coût élevé. Poly-Si (polycristallin) : grains cristallins orientés différemment, aspect grenu bleuté, rendement 15-17%, moins cher. Technologies avancées : HJT (hétérojonction, rendement > 22%), bifacial (capture lumière face avant + arrière, +5-15% production), PERC, IBC.",tags:["Monocristallin","Polycristallin","Rendement","Si","HJT","PERC"]},
  {id:"fed_pv2_3",prompt:"Un onduleur de chaîne (string inverter) dans une installation PV résidentielle :",choices:["Convertit l'AC en DC","Convertit le courant continu (DC) produit par les panneaux en courant alternatif (AC) 230V/50Hz injectés dans le réseau ou autoconsommés","Stocke l'énergie dans des batteries","Régule uniquement la température des panneaux"],answer:1,diff:1,explication:"Onduleur string (chaîne) : DC → AC (DC/AC). Inclut : MPPT (Maximum Power Point Tracking) = optimisation du point de fonctionnement de la chaîne, protection anti-îlotage (déconnexion réseau si panne), interface de monitoring. Micro-onduleurs (par panneau) : meilleure performance si ombrage partiel. Onduleur hybride : gère aussi les batteries.",tags:["Onduleur","String","DC/AC","MPPT","Anti-îlotage"]},
  {id:"fed_pv2_4",prompt:"L'autoconsommation avec vente du surplus permet :",choices:["De vendre TOUTE la production à EDF","De consommer prioritairement la production solaire puis d'injecter et vendre le surplus au réseau (obligation de rachat au tarif S06 ENEDIS)","D'être totalement indépendant du réseau","De stocker obligatoirement dans des batteries"],answer:1,diff:2,explication:"Autoconsommation individuelle avec vente surplus (art. L315-1 code énergie) : 1) Consommation prioritaire de la production PV 2) Surplus injecté au réseau et racheté par l'agrégateur ou EDF OA (tarif S06 env. 6-13 c€/kWh selon puissance). Avantages : réduction facture électrique (économie sur prix achat ~20 c€/kWh) + revenu du surplus. Autoconsommation totale sans injection : simplification administrative.",tags:["Autoconsommation","Vente surplus","S06","ENEDIS","Tarif rachat"]},
  {id:"fed_pv2_5",prompt:"Le raccordement d'une installation PV ≤ 3 kWc en autoconsommation avec vente surplus nécessite :",choices:["Aucune démarche administrative","Convention de raccordement ENEDIS (CACSI) + déclaration préalable mairie + contrat CRAE (contrat de raccordement, accès, exploitation)","Permis de construire systématique","Agrément du Ministère de l'Énergie"],answer:1,diff:2,explication:"Démarches installation PV ≤ 3 kWc : 1) Déclaration préalable mairie (si zone ABF ou > 3 kWc) 2) Demande de raccordement ENEDIS (Procédure Simplifiée ou CACSI) 3) Contrat CRAE avec ENEDIS 4) Consuel (organisme de contrôle électrique) si puissance > 36 kVA ou neuf 5) Attestation RGE (Reconnu Garant de l'Environnement) de l'installateur pour bénéficier des aides.",tags:["Raccordement","ENEDIS","CACSI","CRAE","RGE","Démarches"]},
  {id:"fed_pv2_6",prompt:"Le coefficient de performance (PR — Performance Ratio) d'une installation PV représente :",choices:["Le rendement des panneaux dans les STC","Le ratio entre l'énergie réellement produite et l'énergie théoriquement attendue sans pertes (PR > 80% = installation de bonne qualité)","La puissance crête installée","Le taux d'autoconsommation"],answer:1,diff:3,explication:"PR (Performance Ratio) = Énergie AC produite / (Puissance crête × Irradiation reçue). Pertes incluses : température (+0,4%/°C au-dessus 25°C), câbles, onduleur, ombrage, salissures, mismatch. PR moyen français : 75-85%. PR élevé > 80% = installation optimisée. Indicateur de suivi de performance et de détection de pannes.",tags:["Performance Ratio","PR","Pertes","Monitoring","Qualité installation"]},
  {id:"fed_pv2_7",prompt:"La protection anti-îlotage d'un onduleur PV est obligatoire pour :",choices:["Améliorer le rendement de l'onduleur","Protéger les techniciens réseau en cas de coupure (empêcher l'injection dans un réseau hors tension — danger électrique)","Protéger les panneaux de la surchauffe","Optimiser le taux d'autoconsommation"],answer:1,diff:2,explication:"Anti-îlotage (protection contre le fonctionnement en îlot) : si le réseau est coupé, l'onduleur doit se déconnecter dans les 2 secondes. Sans cette protection, l'installation continuerait d'alimenter le réseau local → danger électrique pour les techniciens ENEDIS travaillant sur le réseau 'coupé'. Normalisé : VDE 0126-1-1 (Allemagne), CEI 62116, VFR2019 (ENEDIS France).",tags:["Anti-îlotage","Protection réseau","Sécurité","Onduleur","ENEDIS"]},
  {id:"fed_pv2_8",prompt:"Le stockage par batterie au lithium dans une installation PV résidentielle présente comme principal inconvénient :",choices:["Une durée de vie illimitée","Un coût élevé (3 000-8 000 € pour 5-10 kWh) et une durée de vie limitée (3 000-6 000 cycles, 10-15 ans)","Une puissance limitée à 100 W","L'impossibilité de se charger depuis le réseau"],answer:1,diff:2,explication:"Batterie lithium-ion (LFP, NMC) résidentielle : avantages = densité énergétique élevée, pas d'effet mémoire, charge/décharge rapide, monitoring intégré. Inconvénients : coût élevé (~800-1000 €/kWh utile), durée de vie 10-15 ans (3000-6000 cycles à 80% DoD), gestion thermique (ne pas exposer à > 40-50°C). Rentabilité souvent difficile à court terme sans tarif de rachat bas.",tags:["Stockage","Batterie lithium","LFP","Cycles","Coût","Résidentiel"]},
  {id:"fed_pv2_9",prompt:"La puissance d'une installation PV à mettre en oeuvre pour couvrir une consommation annuelle de 3 000 kWh dans le Sud de la France (ensoleillement ~1 500 kWh/kWc/an) est d'environ :",choices:["500 Wc","2 kWc (3 000 / 1 500)","5 kWc","10 kWc"],answer:1,diff:2,explication:"Dimensionnement simplifié : Puissance (kWc) = Consommation annuelle (kWh) / Production spécifique (kWh/kWc/an). Productions spécifiques France : Nord ~900-1 000 kWh/kWc, Centre ~1 100-1 200, Sud ~1 400-1 500, PACA ~1 500-1 600. Ici : 3 000 / 1 500 = 2 kWc. En pratique, dimensionner selon le taux d'autoconsommation souhaité et l'orientation du toit.",tags:["Dimensionnement","kWc","Production spécifique","kWh/kWc","Ensoleillement"]},
  {id:"fed_pv2_10",prompt:"La norme NF C 15-100 impose pour les installations PV raccordées au réseau :",choices:["Un disjoncteur ordinaire suffit","Un dispositif de protection différentielle adapté (DDR 30 mA type A ou B selon l'onduleur), un parafoudre DC côté panneaux, et une protection AC côté réseau","Aucune protection spécifique","Uniquement un coupe-circuit DC"],answer:1,diff:3,explication:"NF C 15-100 + guide UTE C 15-712-1 (PV) : côté DC : parafoudre DC (si longueur > 10 m ou zone foudre), sectionneur DC, câbles DC homologués (double isolation PV, tension DC ≥ 1000V). Côté AC : DDR 30 mA type A (ou B si courant continu dans le résidu, selon l'onduleur), parafoudre AC, disjoncteur de branchement. Mise à la terre de la structure.",tags:["NF C 15-100","Parafoudre","DDR","Protection DC","AC","UTE C 15-712"]},
];

export const QB_FED_ISOLANTS_THERM = [
  {id:"fed_it1",prompt:"La résistance thermique (R) d'un matériau isolant est calculée par :",choices:["R = lambda × épaisseur","R = épaisseur / lambda (en m²·K/W) — plus R est grand, meilleur est l'isolant","R = lambda / épaisseur","R = 1 / (U × surface)"],answer:1,diff:1,explication:"Résistance thermique : R = e / λ (m²·K/W). e = épaisseur (m). λ = conductivité thermique (W/m·K). Plus λ est petit → meilleur isolant. Matériaux courants : laine de verre λ = 0,032-0,040 ; polyuréthane λ = 0,022-0,028 ; laine de roche λ = 0,035-0,045 ; ouate de cellulose λ = 0,038-0,042 ; aérogel λ = 0,015. Le coefficient U (W/m²·K) = 1 / (somme des R + R_si + R_se).",tags:["Résistance thermique","R","Lambda","Conductivité","Isolant"]},
  {id:"fed_it2",prompt:"Le coefficient de transmission thermique U (en W/m²·K) représente :",choices:["La chaleur stockée par le matériau","Le flux de chaleur traversant 1 m² de paroi pour 1°C d'écart de température — plus U est faible, meilleure est l'isolation","La résistance thermique totale","La densité du matériau"],answer:1,diff:1,explication:"U = coefficient de transmission thermique surfacique (anciennement coefficient K). U = 1 / R_total. Valeurs réglementaires RE2020 : murs ≤ 0,20-0,28 W/m²K, toiture ≤ 0,12-0,15 W/m²K, plancher bas ≤ 0,27-0,32 W/m²K, vitrage ≤ 1,0-1,3 W/m²K (double vitrage). Pont thermique : rupture locale de l'isolation → ↑ U local → condensation, moisissures.",tags:["U","Coefficient thermique","W/m²K","RE2020","Pont thermique"]},
  {id:"fed_it3",prompt:"La laine de verre (LDV) présente comme avantage principal par rapport à la laine de roche (LDR) :",choices:["Une meilleure résistance au feu (classée A1)","Un coût légèrement inférieur et une densité plus faible (pose plus légère) — mais performance feu légèrement inférieure","Une meilleure résistance à l'humidité","Une conductivité thermique 2 fois plus faible"],answer:1,diff:2,explication:"Laine de verre (LDV) : λ 0,032-0,040, densité 10-30 kg/m³, coût bas, pose légère, bonne isolation acoustique (fréquences moyennes). Laine de roche (LDR) : λ 0,035-0,045, densité 30-100 kg/m³, meilleure résistance feu (classée A1 = incombustible), résiste mieux à la chaleur (jusqu'à 700°C), meilleure tenue mécanique. Les deux sont réversibles mais sensibles à l'humidité.",tags:["Laine de verre","Laine de roche","Lambda","Densité","Résistance feu"]},
  {id:"fed_it4",prompt:"Le polyuréthane (PUR) projeté ou en panneaux présente comme caractéristique principale :",choices:["La conductivité thermique la plus élevée des isolants","La conductivité thermique la plus faible des isolants courants (λ 0,022-0,028 W/m·K) permettant des épaisseurs minimales","L'incombustibilité totale (classé A1)","Un coût très bas"],answer:1,diff:2,explication:"Polyuréthane (PUR/PIR) : λ = 0,022-0,028 W/m·K → meilleur isolant parmi les mousses synthétiques. Applications : toiture terrasse (panneaux PIR), isolation par l'extérieur (ITE), combles perdus (projeté). Inconvénients : combustible (classé E ou B selon formulation), prix plus élevé, émissions de CO2 à la fabrication. PIR (polyisocyanurate) : résistance feu améliorée vs PUR.",tags:["Polyuréthane","PUR","PIR","Lambda faible","ITE"]},
  {id:"fed_it5",prompt:"L'isolation thermique par l'extérieur (ITE) présente comme avantage principal :",choices:["Un coût très faible","L'élimination des ponts thermiques de structure et la conservation de l'inertie thermique des murs intérieurs","Une pose sans perturbation des occupants","La possibilité d'utiliser uniquement des matériaux biosourcés"],answer:1,diff:1,explication:"ITE (Isolation Thermique par l'Extérieur) : isolant posé sur la façade extérieure → avantages : 1) Suppression des ponts thermiques de structure (dalles, poteaux, refends) 2) Conservation de l'inertie thermique du mur (stockage de chaleur) 3) Surface habitable intérieure préservée 4) Rénovation sans déménagement. Finitions : enduit mince (ETICS), bardage ventilé. ITI (par l'intérieur) : moins chère mais ponts thermiques maintenus et surface habitable réduite.",tags:["ITE","Isolation extérieure","Ponts thermiques","Inertie thermique","Bardage"]},
  {id:"fed_it6",prompt:"L'ouate de cellulose, isolant biosourcé issu du papier recyclé, présente comme propriété spécifique :",choices:["Une conductivité thermique de 0,015 W/m·K (la meilleure du marché)","Une bonne capacité hygroscopique (gère la vapeur d'eau) + bon déphasage thermique (inertie élevée) + λ 0,038-0,042","Une résistance au feu naturelle sans traitement","Une densité nulle (isolant aérien)"],answer:1,diff:2,explication:"Ouate de cellulose : λ = 0,038-0,042 W/m·K, densité 25-55 kg/m³. Propriétés : 1) Hygroscopique : absorbe et rejette la vapeur d'eau sans perdre ses propriétés isolantes (régulation hygrométrique) 2) Déphasage thermique excellent (> 8-10h en forte épaisseur) 3) Bonne isolation acoustique. Traitement retardateur de feu (sels de bore). Pose : soufflage en vrac, insufflation en murs, projection humide.",tags:["Ouate de cellulose","Biosourcé","Hygroscopique","Déphasage","Cellulose"]},
  {id:"fed_it7",prompt:"En acoustique du bâtiment, l'indice d'affaiblissement acoustique Rw (en dB) d'une cloison représente :",choices:["Le bruit émis par la cloison","La capacité de la cloison à atténuer les bruits aériens — plus Rw est élevé, meilleure est l'isolation phonique","La réverbération dans la pièce","L'absorption sonore du matériau"],answer:1,diff:2,explication:"Rw (pondéré) : indice d'affaiblissement acoustique aux bruits aériens. Norme NF EN ISO 140. Valeurs réglementaires NRA (Nouvelle Réglementation Acoustique) habitation : DnTA ≥ 53 dB (bruits aériens entre logements). Isolation vibratoire (bruits d'impact) : Ln,w. Matériaux à fort Rw : béton (50-60 dB), double paroi laine de roche (65-70 dB). Double vitrage : Rw 30-42 dB.",tags:["Acoustique","Rw","Affaiblissement acoustique","dB","NRA"]},
  {id:"fed_it8",prompt:"Le pont thermique de liaison (dû à la jonction entre deux parois) est caractérisé par :",choices:["Une surisolation locale","Une zone de forte déperdition thermique locale (coefficient psi Ψ en W/m·K linéique) pouvant créer des risques de condensation et moisissures","Une amélioration du coefficient U","Aucun impact sur la performance thermique globale"],answer:1,diff:2,explication:"Pont thermique : rupture de continuité de l'isolation. Types : de structure (dalle, poteau), de liaison (jonction mur/plancher, tableau de fenêtre). Coefficient Ψ (psi) : déperdition linéique (W/m·K). Température de surface minimale : T_surface = T_int - Rsi × (T_int - T_ext) × U. Si T_surface < point de rosée → condensation → moisissures. Traitement : rupteur de pont thermique, ITE.",tags:["Pont thermique","Ψ","Condensation","Moisissures","Rupteur"]},
  {id:"fed_it9",prompt:"La réglementation RE2020 (Réglementation Environnementale 2020) remplace la RT2012 et introduit :",choices:["Uniquement des exigences thermiques plus strictes sur le U des parois","Des exigences sur le bilan carbone du bâtiment (ACV — Analyse de Cycle de Vie), le confort d'été (DH — Degrés-Heures) ET les performances thermiques","Des exigences uniquement pour les bâtiments > 1000 m²","La suppression des exigences de ventilation"],answer:1,diff:2,explication:"RE2020 (bâtiments neufs, depuis jan. 2022) : 3 indicateurs : 1) Bbio (besoin bioclimatique : isolation, compacité, orientation) 2) Cep (consommation d'énergie primaire) et Cep_nr (non renouvelable) 3) Icénergie + Icchantier (ACV, empreinte carbone matériaux et construction). Nouveau : DH (Degrés-Heures, confort d'été) + interdiction progressive du chauffage au gaz. Objectif : bâtiments bas-carbone.",tags:["RE2020","ACV","Carbone","DH","Bbio","Cep","Bâtiment neuf"]},
  {id:"fed_it10",prompt:"Le coefficient g (facteur solaire) d'un vitrage représente :",choices:["Sa résistance thermique","La fraction du rayonnement solaire incident qui est transmis à l'intérieur du bâtiment (0 = opaque, 1 = transparent total)","Son indice d'affaiblissement acoustique","Sa durée de vie"],answer:1,diff:2,explication:"Facteur solaire g (ou SHGC) : 0 à 1. g élevé → plus de chaleur solaire pénètre (favorable en hiver, défavorable en été). Double vitrage standard : g ≈ 0,62. Vitrage à contrôle solaire : g ≈ 0,20-0,35 (réduit les apports solaires → confort d'été). Compromis : g bas + TL (Facteur de lumière) élevé → vitrage sélectif. RE2020 : confort d'été (DH) favorise g plus faible + protections solaires.",tags:["Facteur solaire","g","Vitrage","Apports solaires","Confort d'été"]},
];

export const QB_FED_BEPOS_SDT = [
  {id:"fed_bp1",prompt:"Un bâtiment BEPOS (Bâtiment à Énergie POSitive) est défini par :",choices:["Un bâtiment qui ne consomme aucune énergie","Un bâtiment qui produit plus d'énergie qu'il n'en consomme sur l'année (bilan énergétique annuel positif)","Un bâtiment uniquement chauffé aux énergies renouvelables","Un bâtiment à faibles besoins de chauffage uniquement"],answer:1,diff:1,explication:"BEPOS : production annuelle d'énergie (PV, éolien, biomasse) > consommation annuelle (chauffage + ECS + éclairage + électroménager + auxiliaires). Étape supérieure au BEBC/BBC (Bâtiment Basse Consommation, Cep ≤ 50 kWhep/m².an) et au BPOS (Bâtiment à Faible Impact Environnemental). La RE2020 prépare la transition vers des standards BEPOS progressifs.",tags:["BEPOS","Bilan énergétique positif","BBC","RE2020","Énergie renouvelable"]},
  {id:"fed_bp2",prompt:"Le coefficient Cep (Consommation d'énergie primaire) de la RT2012 limite pour les logements neufs à :",choices:["100 kWhep/m².an","50 kWhep/m².an (modulo coefficient de modulation climatique et usage)","200 kWhep/m².an","20 kWhep/m².an"],answer:1,diff:2,explication:"RT2012 : Cep ≤ 50 kWhep/m²·an (5 usages réglementés : chauffage, refroidissement, ECS, éclairage, auxiliaires). Modulé par : localisation climatique (H1a/H1b/H2a/H2b/H3), altitude, type de logement. Coefficient de conversion : électricité = 2,58 ep/kWh (1 kWh électrique = 2,58 kWh énergie primaire). BBC Effinergie : Cep ≤ 40 kWhep/m²·an.",tags:["RT2012","Cep","50 kWhep","Énergie primaire","BBC"]},
  {id:"fed_bp3",prompt:"La ventilation mécanique contrôlée double flux (VMC DF) est recommandée dans les bâtiments performants car :",choices:["Elle ne nécessite aucune maintenance","Elle récupère la chaleur de l'air extrait pour préchauffer l'air neuf entrant (rendement 85-95%) — réduit drastiquement les pertes par ventilation","Elle supprime complètement le besoin de chauffage","Elle filtre uniquement les particules fines"],answer:1,diff:1,explication:"VMC double flux : l'air extrait (chaud, humide) passe par un échangeur thermique et cède sa chaleur à l'air frais entrant (rendement 85-95%). Avantage : réduction des pertes thermiques par renouvellement d'air (qui représentent 25-35% des déperditions en maison étanche). Entretien : remplacement des filtres (2 × /an minimum). EnergyPHI (Passivhaus) : VMC DF obligatoire.",tags:["VMC double flux","Récupération de chaleur","Rendement","Étanchéité","Ventilation"]},
  {id:"fed_bp4",prompt:"L'indice d'étanchéité à l'air n50 (ou Q4Pa-surf) mesure :",choices:["La résistance thermique de la paroi","Le renouvellement d'air dû aux infiltrations parasites (mesuré par test de pressurisation — porte soufflante)","La durée de vie du bâtiment","Le niveau d'isolation acoustique"],answer:1,diff:2,explication:"Test d'étanchéité à l'air (blower door test) : pressuriser le bâtiment à ± 50 Pa et mesurer le débit d'air. n50 (vol/h) : nombre de renouvellements d'air à 50 Pa. Q4Pa-surf (m³/h/m²) : débit à 4 Pa. RT2012 : Q4Pa ≤ 0,6 m³/(h·m²) MI / ≤ 1,0 collectif. Passivhaus : n50 ≤ 0,6 vol/h. Fuites principales : traversées (câbles, fourreaux), jonctions menuiseries, boîtes électriques.",tags:["Étanchéité","n50","Q4Pa","Blower door","Passivhaus","Infiltrations"]},
  {id:"fed_bp5",prompt:"Le système de gestion technique du bâtiment (GTB/BMS) de classe A (EN 15232) permet de :",choices:["Gérer uniquement l'éclairage","Réduire la consommation d'énergie de 25-30% par rapport à une installation sans régulation automatisée (gestion automatique et centralisée du chauffage, ventilation, éclairage, stores)","Surveiller uniquement les alarmes incendie","Remplacer la VMC"],answer:1,diff:2,explication:"GTB (Gestion Technique du Bâtiment) / BAS (Building Automation System) : classe A (EN 15232) = très éco-performante → économie 25-30% vs classe D (aucune automatisation). Fonctions : régulation chauffage/climatisation par zones, gestion éclairage (détection présence + lumière naturelle), stores (apports solaires), monitoring énergétique. RE2020 : GTB de classe B ou A obligatoire pour certains bâtiments tertiaires.",tags:["GTB","BMS","EN 15232","Classe A","Économies d'énergie","Automatisation"]},
  {id:"fed_bp6",prompt:"Le système de distribution par plancher chauffant basse température (PCBT) présente comme avantage principal :",choices:["Un temps de réponse très rapide (< 5 min)","Une émission de chaleur par rayonnement à basse température (35-45°C) compatible avec les pompes à chaleur — confort et efficacité énergétique optimisés","Un coût d'installation très faible","L'impossibilité de surchauffe"],answer:1,diff:2,explication:"Plancher chauffant basse température (PCBT) : tuyaux noyés dans la dalle, eau à 35-45°C (vs radiateurs 70-80°C). Avantages : 1) Compatible PAC (COP élevé à basse T°) 2) Rayonnement uniforme (confort, pas de courants d'air) 3) Inertie thermique. Inconvénients : inertie élevée (temps de réaction long), coût de pose élevé, incompatible avec certains revêtements (parquet épais). Association idéale : PAC + PCBT + isolation performante.",tags:["Plancher chauffant","PCBT","Basse température","PAC","Rayonnement","Inertie"]},
  {id:"fed_bp7",prompt:"La réglementation RE2020 impose un critère de confort d'été basé sur les DH (Degrés-Heures) qui correspond à :",choices:["La durée de la saison estivale","Le nombre d'heures × l'écart de température entre l'intérieur et le seuil de confort (26°C) — limite : 1250 DH pour logements","La consommation de climatisation","La température maximale extérieure"],answer:1,diff:3,explication:"DH (Degrés-Heures de chaleur) : somme sur l'année de [(T_intérieur - T_réf) × durée]. Seuils RE2020 : DH ≤ 350 DH (niveau confortable) et DH ≤ 1250 DH (exigence minimale). Passé ces seuils → climatisation requise ou refus de permis. Moyens de respecter les DH : inertie thermique, protections solaires (stores, débords de toit), sur-ventilation nocturne, vitrage à faible g.",tags:["RE2020","Degrés-Heures","Confort d'été","DH","Inertie","Protections solaires"]},
  {id:"fed_bp8",prompt:"La pompe à chaleur air/eau (PAC air/eau) à coefficient de performance saisonnier (SCOP) de 3,5 signifie :",choices:["Elle consomme 3,5 kWh électriques pour 1 kWh de chaleur","Elle produit 3,5 kWh de chaleur pour 1 kWh électrique consommé en moyenne sur la saison de chauffage","Elle a un rendement de 350% uniquement à +7°C extérieur","Elle fonctionne uniquement quand T° ext > 3,5°C"],answer:1,diff:1,explication:"SCOP (Seasonal Coefficient of Performance) : COP moyen sur toute la saison de chauffage. SCOP = 3,5 → 1 kWh électrique produit 3,5 kWh thermiques. Réglementation : PAC labellisée si SCOP ≥ 2,5 (Chaleur Renouvelable). SCOP typiques : PAC air/air 2,8-4,5, PAC air/eau 2,5-4,0, PAC géothermique 3,5-5,0. Aidée par : MaPrimeRénov' si SCOP > 3,0 pour rénovation.",tags:["PAC","SCOP","COP","Air/eau","Coefficient de performance","Efficacité"]},
  {id:"fed_bp9",prompt:"L'énergie solaire thermique (chauffe-eau solaire individuel CESI) couvre typiquement quelle fraction des besoins en eau chaude sanitaire (ECS) en France ?",choices:["10-20%","50-70% (taux de couverture solaire, complété par un appoint)","90-100%","5% uniquement"],answer:1,diff:2,explication:"CESI (Chauffe-Eau Solaire Individuel) : capteurs solaires thermiques + ballon de stockage + appoint (électrique ou gaz). Taux de couverture solaire : 50-70% des besoins ECS annuels (variable selon la localisation et l'exposition). Dimension type famille de 4 personnes : 4-6 m² de capteurs + 200-300 L de ballon. Aide financière : MaPrimeRénov', crédit d'impôt (ex-CITE), éco-prêt à taux zéro.",tags:["CESI","Solaire thermique","Eau chaude sanitaire","Taux de couverture","MaPrimeRénov"]},
  {id:"fed_bp10",prompt:"Le label Passivhaus (maison passive) exige principalement :",choices:["Une consommation de chauffage < 100 kWh/m².an","Une consommation de chauffage ≤ 15 kWh/m².an + besoin thermique ≤ 10 W/m² + n50 ≤ 0,6 vol/h + Cep ≤ 120 kWh/m².an","Uniquement des panneaux solaires","Un triple vitrage obligatoire partout"],answer:1,diff:2,explication:"Passivhaus (IGP, Darmstadt) : critères cumulatifs : 1) Besoin chauffage ≤ 15 kWh/m².an (ou puissance de pointe ≤ 10 W/m²) 2) Cep ≤ 120 kWh/m².an (tous usages) 3) Étanchéité n50 ≤ 0,6 vol/h 4) Confort thermique : T_surface parois ≥ 17°C. Moyens : super-isolation, ponts thermiques supprimés, VMC DF (rendement ≥ 75%), menuiseries triple vitrage Uf ≤ 0,85 W/m²K, orientation bioclimatique.",tags:["Passivhaus","15 kWh/m².an","n50","VMC DF","Triple vitrage","Label"]},
];

