export const FICHES_FED = [
  {id:"fed_f1",title:"Systèmes domotiques et GTB",bloc:"Bloc 2",tags:["Domotique","KNX","GTB","BIM"],duree:20,niveau:"Fondations",qbank:"fed_systemes",
    contenu:"**KNX — Standard domotique :**\n• Protocole bus sur paire torsadée (TP) ou IP\n• Adresse individuelle (localisation) + adresse de groupe (fonction)\n• Télégrammes numériques : capteurs → bus → actionneurs\n• Configuration via ETS (Engineering Tool Software)\n• Applications : éclairage, chauffage, volets, comptage énergie\n\n**DALI :** contrôle numérique de l'éclairage (gradation, adressage individuel, scènes)\n\n**GTB (Gestion Technique du Bâtiment) :**\n• Supervision centralisée (Modbus RTU/TCP, BACnet/IP)\n• Automates programmables (régulation CVC)\n• Comptage et reporting énergie\n• Maintenance prédictive\n\n**BIM :** maquette numérique collaborative 3D\n• Logiciels : Revit, ArchiCAD\n• Niveaux LOD (Level of Development) : LOD 100 à LOD 500\n• BIM 4D (planning), 5D (coûts), 6D (exploitation)\n\n**SysML :** modélisation systèmes (9 diagrammes)"},
  {id:"fed_f2",title:"Énergie électrique et installations",bloc:"Bloc 2",tags:["Énergie","Électrotechnique","Protection","Réglementation"],duree:22,niveau:"Intermédiaire",qbank:"fed_energie",
    contenu:"**Puissances électriques :**\n• P (W) = puissance active (travail utile)\n• Q (VAR) = puissance réactive (champs magnétiques)\n• S (VA) = puissance apparente (S² = P² + Q²)\n• cos φ = P/S. Objectif : cos φ proche de 1\n\n**Protection des installations (NF C 15-100) :**\n• Disjoncteur : protection surintensité (court-circuit + surcharge)\n• Différentiel : protection contacts indirects (fuite vers terre)\n  - Type AC : courants sinusoïdaux\n  - Type A : + pulsatoires (lave-linge, VE)\n• Mise à la terre : écoulement des courants de défaut\n• Schémas de liaison à la terre : TT (France résidentiel), TN-S (tertiaire)\n\n**Réglementation thermique RE 2020 :**\n• Bbio (besoin bioclimatique)\n• Cep < 100 kWh/m²/an\n• IC (impact carbone)\n• DPE : A (< 70) → G (> 420 kWh/m²/an)\n\n**Pompe à chaleur :** COP = Pthermique/Pélectrique > 1\n**VMC double flux :** échangeur chaleur (rendement > 80%)"},
  {id:"fed_f3",title:"Réseaux et câblage structuré",bloc:"Bloc 3",tags:["VDI","Réseaux","Câblage","Protocoles"],duree:15,niveau:"Fondations",qbank:"fed_systemes",
    contenu:"**Câblage VDI (Voix-Données-Images) :**\n• Topologie en étoile (centralisé en baie de brassage)\n• Câbles catégorie 6 ou 6A (bande passante 250/500 MHz)\n• FTP (blindé) en environnement industriel, UTP en tertiaire courant\n• Longueur max poste de travail : 90 m + 10 m cordons = 100 m\n\n**Protocoles de communication :**\n• Modbus RTU : liaison série RS485 (maître-esclave)\n• Modbus TCP : Modbus encapsulé dans Ethernet\n• BACnet/IP : bâtiments tertiaires, interopérabilité\n• KNX/IP : KNX via réseau Ethernet existant\n• MQTT : IoT, domotique connectée (publish/subscribe)\n\n**Wi-Fi en bâtiment :**\n• 2.4 GHz (longue portée, plus d'interférences)\n• 5 GHz (plus rapide, portée réduite)\n• PoE (Power over Ethernet) : alimentation et data sur un seul câble"},
  {id:"fed_f4",title:"Analyse et définition d'un système (SysML / FAST)",bloc:"Bloc 1",tags:["SysML","Analyse","Modélisation","Examen"],duree:18,niveau:"Avancé",qbank:"fed_systemes",
    contenu:"**Diagramme des exigences (SysML) :**\n• Capture les fonctions souhaitées et contraintes\n• Liaisons : satisfies, refines, deriveReqt\n\n**Diagramme de blocs (BDD) :**\n• Structure du système (composants, interfaces)\n• Boîte noire → boîte blanche\n\n**Diagramme de cas d'utilisation :**\n• Acteurs + cas d'utilisation + associations\n\n**FAST (Function Analysis System Technique) :**\n• Décomposition fonctionnelle\n• Fonctions de service (FS) : rendues à l'utilisateur\n• Fonctions techniques (FT) : internes au système\n\n**Dossier d'analyse :**\n1. Mise en situation\n2. Diagramme des interacteurs\n3. Diagramme FAST\n4. Diagramme des exigences\n5. Architecture solution"}
  ,{id:"fed_f6",title:"🎓 Annale 2024 — Thermique, hydraulique, eau & combustion",bloc:"Bloc 3",tags:["Annale 2024","Thermique du bâtiment","Résistance thermique","Coefficient U","Reynolds","Eau glycolée","Adoucisseur","Combustion","Méthane","CO","CTA","GTB"],duree:28,niveau:"Avancé",qbank:"fed_thermo2024",
    contenu:"**Contexte (E41+E42 2024 — Musée des Beaux-Arts de Dijon) :**\nRénovation d'un bâtiment patrimonial : forte isolation, CTA double flux, groupes d'eau glacée, sous-station.\n\n**Transfert thermique :**\n• Conduction (solide), convection (fluide), rayonnement (électromagnétique)\n• Rth = e/λ (m²·K/W). Multicouche : Rtot = ΣRth\n• U = 1/Rtot (W/m²·K). RE 2020 : U mur ≤ 0.20, U toit ≤ 0.13\n• Déperditions : Φ = U × S × ΔT\n\n**Hydraulique — Eau glycolée :**\n• MPG (mono propylène glycol) 30% : protection gel ≈ -15°C, non toxique\n• Vitesse v = qv / (π × D²/4)\n• Reynolds Re = ρvD/μ : < 2300 = laminaire, > 4000 = turbulent\n\n**Chimie de l'eau — Adoucisseur :**\n• TH (titre hydrotimétrique) = dureté Ca²⁺ + Mg²⁺. 1°f = 0.1 mmol/L CaCO₃\n• Eau dure → tartre → pertes thermiques circuits chauffage\n• Résine échangeuse de cations : (1) adoucissement R-Na⁺ + Ca²⁺→R-Ca²⁺+Na⁺, (2) saturation, (3) régénération à la saumure NaCl\n\n**Combustion du méthane :**\n• Complète : CH₄ + 2O₂ → CO₂ + 2H₂O (ΔH = -890 kJ/mol)\n• Incomplète (manque O₂) → CO (monoxyde de carbone) : inodore, incolore, mortel\n• CO fixe Hb × 200 > O₂ → hypoxie cérébrale. Détecteur CO obligatoire\n\n**CTA double flux :**\n• Récupérateur de chaleur : air extrait ↔ air neuf (pas de mélange)\n• Rendement 60-90%. Obligatoire RE 2020 tertiaire\n• Batteries chaudes + batteries froides : traitement hygrothermique\n\n**GTB — Régulation PID :**\n• P = proportionnel (erreur), I = intégral (élimine erreur statique), D = dérivé (anticipation)\n• Points TOR (tout-ou-rien) + analogiques (4-20 mA, 0-10V)\n• Protocoles : Modbus RTU/TCP, BACnet/IP"}
  ,{id:"fed_f7",title:"Pompes à chaleur (PAC) : cycles, COP et réglementation",bloc:"Bloc 2",tags:["PAC","COP","SCOP","Cycle frigorifique","Fluides frigorigènes","F-gas","RE 2020"],duree:22,niveau:"Intermédiaire",qbank:"fed_pac",
    contenu:"**Principe de la PAC :**\n• Capte les calories d'une source froide (air, eau, sol) → les restitue à une source chaude\n• 1 kW électrique → 3 à 5 kW thermiques (selon le COP)\n\n**Performances :**\n• COP = P_thermique_utile / P_électrique_consommée (en chauffage)\n• EER = P_froid / P_élec (en refroidissement)\n• SCOP = COP saisonnier (intègre les variations de T° extérieure sur l'année)\n• RE 2020 : SCOP ≥ 2.5\n\n**Cycle thermodynamique (ordre) :**\nÉvaporation (source froide) → Compression → Condensation (source chaude) → Détente\n\n**Bilan thermique :**\nP_chaud = COP × P_élec ; P_froid (captée) = P_chaud - P_élec\n\n**Types de PAC :**\n• Air/Air, Air/Eau, Géothermique eau/eau (COP le plus élevé)\n• Chiller = production d'eau glacée 7/12°C pour tertiaire\n• PAC air/eau + plancher chauffant (35-45°C) = optimum COP\n\n**Fluides frigorigènes :**\n• R32 (PRG 675) remplace R410A (PRG 2088)\n• F-gas UE 517/2014 : restrictions progressives HFC à fort PRG\n• R290 (propane, PRG=3), R744 (CO₂, PRG=1)\n• Certification obligatoire pour techniciens manipulant les fluides"}
  ,{id:"fed_f8",title:"Électrotechnique avancée : moteurs, variateurs et puissance réactive",bloc:"Bloc 2",tags:["Moteur asynchrone","Variateur de fréquence","VFD","Loi cubique","cos φ","TGBT","NF C 15-100","DALI"],duree:22,niveau:"Avancé",qbank:"fed_electro2",
    contenu:"**Moteur asynchrone triphasé :**\n• Cage d'écureuil : robuste, sans balais, courant d'appel 5-8 × In au démarrage direct\n• Glissement s = (Ns - N) / Ns (quelques %)\n\n**Variateur de fréquence (VFD) :**\n• Redresseur → bus DC → onduleur IGBT → AC fréquence et tension variables\n• Rapport V/f constant → maintien du flux magnétique\n• Génère des harmoniques → différentiels type A ou B\n\n**Loi cubique (pompes/ventilateurs) :**\n• Q ∝ N ; ΔP ∝ N² ; P ∝ N³\n• -20% de vitesse → économie de 48.8% sur la puissance absorbée\n• Intérêt majeur des VFD sur les applications CVC\n\n**Puissance réactive :**\n• P (kW) : travail utile ; Q (kVAR) : champs magnétiques ; S (kVA) = √(P²+Q²)\n• cos φ = P/S. Objectif : cos φ > 0.93 (pénalité ENEDIS si < 0.93)\n• Compensation par batteries de condensateurs → ↑ cos φ → ↓ courant I → ↓ pertes Joule\n\n**Protections et installations :**\n• NF C 15-100 : normes BT (France)\n• Différentiel type B : VE, PV, onduleurs (courants DC continus)\n• Schéma IT : neutre isolé → 1ère faute non dangereuse (hôpitaux, industrie)\n• TGBT : armoire principale alimentée depuis le transformateur HTA/BT\n\n**Éclairage LED/DALI :**\n• DALI : protocole numérique 2 fils, adressage individuel, gradation 0-100%, scènes\n• LED : 80-120 lm/W vs halogène 15 lm/W ; driver courant constant\n• Tarif Tempo EDF : 22 jours rouges (HP × 10) → délestage CVC en jours rouges"}
  ,{id:"fed_f9",title:"GTB avancée : protocoles, régulation et IoT",bloc:"Bloc 2",tags:["BACnet","Modbus","KNX","IEC 61131","PID","OPC-UA","LoRaWAN","IoT","PT1000"],duree:22,niveau:"Avancé",qbank:"fed_gtb2",
    contenu:"**Protocoles de communication GTB :**\n• BACnet/IP (ASHRAE 135) : TCP/IP, objets BACnet (Analog Input, Schedule, Trend Log)\n• BACnet MS/TP : RS485 2 fils, jusqu'à 127 maîtres\n• Modbus RTU/TCP : maître-esclave ; Holding registers (4xxxx) = R/W (consignes)\n• KNX adresse individuelle : Zone.Ligne.Appareil (ex: 1.2.5) ; adresse groupe : fonction\n\n**Automates et programmation (IEC 61131-3) :**\n• Ladder (LD) : schéma contacts électriques (historique)\n• FBD : blocs fonctionnels\n• ST (Structured Text) : texte Pascal-like\n• SFC (Grafcet) : processus séquentiels\n• Cycle automate : lecture E/S → traitement programme → écriture sorties\n\n**Régulation automatique :**\n• TOR avec hystérésis : évite les oscillations rapides (ex: chaudière ON à 19°C, OFF à 21°C)\n• Correcteur P : erreur statique résiduelle en régime permanent\n• PID : P + I (élimine erreur statique) + D (anticipe les variations)\n• PT1000 : sonde température, R = 1000 Ω à 0°C, variation ≈ 3.85 Ω/°C\n\n**Supervision GTC et IoT :**\n• OPC-UA : interopérabilité automates ↔ superviseurs ↔ cloud\n• GTC : synoptiques animés, alarmes, historiques, rapports énergie\n• LoRaWAN : capteurs sans-fil longue portée, faible consommation (batterie 5-10 ans)\n• MQTT (publish/subscribe) : protocole IoT cloud\n• VDI cat 6A : 100 m max (90 m câble + 10 m cordons), 10 Gbit/s"}
  ,{id:"fed_f5",title:"Physique appliquée : électricité, thermique, hydraulique",bloc:"Bloc 3",tags:["Physique","Électricité","Thermique","Hydraulique","Acoustique"],duree:20,niveau:"Intermédiaire",qbank:"fed_physique",
    contenu:"**Électricité fondamentale :**\n• U = R×I (Ohm), P = U×I = R×I² = U²/R\n• Lois de Kirchhoff : nœuds (ΣI=0), mailles (ΣU=0)\n• Valeur efficace : Ueff = Umax/√2 → Umax = 325 V pour 230 V\n• Triphasé : S = √3 × UL × IL\n\n**Thermodynamique et isolation :**\n• Rth = e/λ (m²K/W). En série : Rtot = ΣRth\n• Coefficient U = 1/ΣRth (W/m²K). Plus U est petit → meilleure isolation\n• RE 2020 : U mur ≤ 0.20, U toit ≤ 0.13, U vitre ≤ 1.4\n• Ponts thermiques = points faibles (angles, liaisons)\n\n**Mécanique des fluides :**\n• Bernoulli : P + ρgh + ½ρv² = Cte\n• Poiseuille : Q ∝ r⁴ (régime laminaire)\n• Reynolds : Re = ρvD/η. < 2300 = laminaire\n• Darcy-Weisbach : pertes de charge = f × L/D × ρv²/2\n\n**Acoustique :**\n• Niveau sonore L = 10×log(I/I₀) dB\n• +3 dB = ×2 l'intensité\n• Rw = affaiblissement acoustique aérien (dB)"}
  ,{id:"fed_f10",title:"Thermique du bâtiment : déperditions, isolation et RE 2020",bloc:"Bloc 1",tags:["Déperditions thermiques","Coefficient U","Ponts thermiques","RE 2020","Bbio","DPE","Inertie","Isolation","Blower door"],duree:24,niveau:"Intermédiaire",qbank:"fed_thermique_bat",
    contenu:"**Déperditions thermiques totales :**\n• ΦT = Φ_transmission + Φ_renouvellement d'air\n• Transmission : Φ = U × S × ΔT (W/m²K × m² × K)\n• Pont thermique linéique : ΦPT = ψ × L × ΔT\n\n**Composants du coefficient U :**\n• U = 1 / (Rsi + Σ(e/λ) + Rse)\n• Rsi (surface intérieure) ≈ 0.13 m²K/W ; Rse (surface extérieure) ≈ 0.04 m²K/W\n• Plus U est petit → mieux isolé\n\n**Valeurs RE 2020 :**\n• Mur extérieur : U ≤ 0.20 W/m²K\n• Toiture/plancher haut : U ≤ 0.13 W/m²K\n• Plancher bas : U ≤ 0.27 W/m²K\n• Vitrage : Uw ≤ 1.40 W/m²K\n\n**Indicateurs RE 2020 :**\n• Bbio : besoins bioclimatiques (chauffage + refroidissement + éclairage intrinsèques)\n• Cep < 100 kWh_ep/m²/an (5 usages : chauffage, froid, ECS, éclairage, auxiliaires)\n• IC (Impact Carbone) : ACV du bâtiment sur 50 ans\n\n**Inertie thermique :**\n• Matériaux lourds (béton, brique) → fort déphasage thermique → confort d'été\n• Déphasage > 10h (ITE + béton) → pic de chaleur extérieur arrive atténué la nuit\n\n**DPE :** A (< 70) → G (> 420 kWh/m²/an). Passoires F & G : interdiction location progressive 2025-2034\n\n**Étanchéité à l'air :**\n• Test blower door : Q4Pa ≤ 0.60 m³/h.m² (maison BBC)\n• Conductivités λ : laine de roche 0.033-0.040, PUR 0.022-0.025, PSE 0.030-0.038"}
  ,{id:"fed_f11",title:"Aéraulique et ventilation : VMC, CTA, débits et pertes de charge",bloc:"Bloc 2",tags:["VMC simple flux","VMC double flux","CTA","Débit d'air","Pertes de charge","DTU 68.3","Filtration","Aéraulique"],duree:22,niveau:"Intermédiaire",qbank:"fed_aero_ventil",
    contenu:"**Types de VMC :**\n• Simple flux A (SF-A) : débits fixes selon arrêté 1982/DTU 68.3\n• Simple flux B (SF-B / hygroréglable) : bouches variables selon HR\n• Double flux : récupération chaleur échangeur (rendement 75-95%)\n• T° air neuf préchauffé = T_amb + η × (T_int - T_ext)\n\n**Débits réglementaires minimaux (DTU 68.3) :**\n• Cuisine : 45-90 m³/h d'extraction\n• Salle d'eau : 15-30 m³/h\n• WC : 15 m³/h\n• Logements ≥ 5 pièces : débit global min 135 m³/h\n\n**Pertes de charge aérauliques :**\n• Régulières : ΔPr = f × (L/D) × ρv²/2\n• Singulières : ΔPs = ξ × ρv²/2\n• Pression dynamique : Pdyn = ρv²/2 (Pa)\n• Vitesses recommandées : galerie principale 6-8 m/s, terminaux 2-4 m/s\n\n**CTA (Centrale de Traitement d'Air) :**\n• Filtration (G4 puis M5/F7), chauffage, refroidissement, humidification\n• Batterie chaude (eau chaude) + batterie froide (eau glacée ou DX)\n• Free cooling nocturne : refroidissement sans compresseur (T_ext < T_int)\n\n**Qualité de l'air :**\n• Filtres EN ISO 16890 : G4 (grossier) → F7 (fin) → H13 (HEPA)\n• Débit par personne : 25-36 m³/h/pers (bureau, NF EN 13779)\n• CO₂ < 800 ppm (IDA 2) / < 1000 ppm (IDA 3)"}
  ,{id:"fed_f12",title:"Réseaux hydrauliques : chauffage, ECS et pompes",bloc:"Bloc 2",tags:["Pompe centrifuge","HMT","Vase d'expansion","Plancher chauffant","ECS","Légionellose","Équilibrage hydraulique","Vanne 3 voies","Robinet thermostatique"],duree:24,niveau:"Intermédiaire",qbank:"fed_hydraulique",
    contenu:"**Pompes centrifuges :**\n• Point de fonctionnement = intersection courbe pompe (HMT/Q) + courbe réseau (ΔP/Q)\n• HMT (Hauteur Manométrique Totale) = hauteur statique + pertes de charge\n• Pompes en parallèle : double le débit ; en série : double la HMT\n• BEP (Best Efficiency Point) = rendement maximal\n\n**Vase d'expansion à membrane :**\n• Absorbe la dilatation de l'eau (4.3% de 10°C à 90°C)\n• P_gonflage gaz = P_statique du circuit\n• Volume vase : calculé selon EN 12828\n\n**Circuits de chauffage :**\n• Plancher chauffant hydraulique (PCH) : T° départ 35-45°C, idéal pour PAC\n• Vanne 3 voies mélangeuse : mélange eau chaude + retour → T° départ régulée (courbe de chauffe)\n• Robinet thermostatique : régulation locale par pièce (mécanique, sans électricité)\n• Équilibrage hydraulique : STAD / registres d'équilibrage par départ\n\n**ECS collective :**\n• Production : T° ≥ 60°C (destruction Legionella)\n• Distribution : T° ≥ 50°C en tout point (arrêté du 3 mai 2007)\n• Legionella prolifère entre 25-45°C\n• Mitigeur anti-brûlure ≤ 50°C en sortie\n\n**Dimensionnement EF :**\n• Méthode des UC (DTU 60.11 / NF EN 806-3) : simultanéité\n• Vitesse max : 0.5-1 m/s (distribution) ; pertes de charge < 30 Pa/m"}
  ,{id:"fed_f13",title:"Froid et climatisation : cycle de réfrigération, fluides et réglementation",bloc:"Bloc 2",tags:["Diagramme de Mollier","EER","Surchauffe","R32","R290","F-gas","DRV","Tour aéroréfrigérante","TEWI","Réversibilité","Point de rosée"],duree:24,niveau:"Avancé",qbank:"fed_froid_clim",
    contenu:"**Cycle frigorifique — Diagramme de Mollier (h-log P) :**\n• Point 1 (sortie évaporateur) → compression isentropique → Point 2 (sortie compresseur)\n• Point 2 → condensation isobare → Point 3 (sortie condenseur, liquide sous-refroidi)\n• Point 3 → détente isenthalpique → Point 4 (mélange liquide-vapeur basse P)\n• COP = (h1-h4)/(h2-h1) ; EER = idem en mode froid\n\n**Sécurités :**\n• Surchauffe aspiration : 5-10°C (évite le coup de liquide → destruction compresseur)\n• Sous-refroidissement condenseur : 5-10°C (améliore le COP)\n\n**Performances :**\n• EER = P_froid / P_élec ; SEER = EER saisonnier\n• Réversibilité : vanne 4 voies (inverseur de cycle)\n• Chiller : eau glacée 7/12°C pour tertiaire ; TAR = meilleur COP\n\n**Fluides frigorigènes :**\n• R32 : PRG=675, remplace R410A (PRG=2088)\n• R290 (propane) : PRG=3, A3 inflammable\n• R744 (CO₂) : PRG=1, haute pression\n• F-gas UE 517/2014 : quotas HFC, attestation de capacité obligatoire\n\n**Réglementation F-gas :**\n• Contrôle étanchéité : 5-50 t éq. CO₂ → annuel ; > 50 t → semestriel\n• Registre d'installation obligatoire\n• DRV/VRF : une UE + multi-unités intérieures (tertiaire)\n\n**Psychrométrie :**\n• Point de rosée Td : T° de condensation (risque sur surfaces froides)"}
  ,{id:"fed_f14",title:"Énergies renouvelables : solaire, PV, géothermie et réglementation",bloc:"Bloc 1",tags:["Solaire thermique","CESI","PV","Onduleur","MPPT","STC","Géothermie","CET","Biomasse","Free cooling","RGE","Fonds Chaleur"],duree:24,niveau:"Intermédiaire",qbank:"fed_enr",
    contenu:"**Solaire thermique :**\n• CESI (Chauffe-Eau Solaire Individuel) : taux de couverture 50-70%\n• Capteur plan : η ≈ 40-70% selon ΔT et ensoleillement\n• Capteurs à tubes sous vide (CPC) : meilleures performances par faible ensoleillement\n• CET (Chauffe-eau thermodynamique) : PAC air/eau intégrée, COP ≈ 2.5-3.5\n\n**Photovoltaïque (PV) :**\n• Rendement silicium monocristallin : 18-22% (≈ 200 Wc/m²)\n• STC : G = 1000 W/m², T = 25°C, AM 1.5\n• Onduleur : DC → AC (MPPT + synchronisation réseau 50 Hz)\n• Productivité France : 950-1400 kWh/kWc/an (selon région)\n• Performance Ratio (PR) ≈ 75-85%\n\n**Géothermie :**\n• Très basse énergie : sol ≈ 12-15°C → PAC eau/eau, COP 4-5\n• Sondes verticales : 50-200 m ; capteurs horizontaux : 0.8-1.2 m\n• Géothermie de surface : chauffage/climatisation\n\n**Autres ENR :**\n• Biomasse : bilan carbone quasi neutre (cycle court), λ EP = 0.6\n• Éolien : P ∝ v³ (loi cubique). Cp_Betz max = 0.593\n• Coefficient énergie primaire (RE 2020) : électricité = 2.3, gaz = 1.0, bois = 0.6\n\n**Aides et certification :**\n• RGE obligatoire pour bénéficier de MaPrimeRénov' et CEE\n• Fonds Chaleur ADEME : ENR thermiques pour collectivités/entreprises\n• Autoconsommation collective (REACo)\n• Indexation tarif rachat : contrats EDF OA (Obligation d'Achat)"}
  ,{id:"fed_f15",title:"Réglementation du bâtiment : RE 2020, DTU, F-gas, accessibilité",bloc:"Bloc 3",tags:["RE 2020","BBC Rénovation","CEE","F-gas","DTU","CONSUEL","Garantie décennale","Acoustique","Loi Elan","PCAET","RGE"],duree:22,niveau:"Intermédiaire",qbank:"fed_reglementation",
    contenu:"**Réglementation thermique :**\n• RE 2020 (depuis janv. 2022 maisons/logements) : Bbio + Cep < 100 kWh_ep/m²/an + IC carbone\n• BBC Rénovation (Effinergie) : Cep ≤ 80 × Ccoef kWh/m²/an\n• DPE opposable depuis juil. 2021. Interdiction location passoires G : 2025, F : 2028, E : 2034\n\n**Financement rénovation :**\n• CEE : obligations des fournisseurs d'énergie → financent travaux éligibles (isolation, PAC...)\n• MaPrimeRénov' : subvention État via ANAH, cumulable CEE\n• Fonds Chaleur ADEME : ENR thermiques tertiaire, collectivités\n• RGE obligatoire pour aides fiscales\n\n**Normes techniques :**\n• DTU = Document Technique Unifié (règles de l'art par corps de métier)\n  - DTU 68.3 (VMC), DTU 60.11 (plomberie), DTU 45.11 (isolation réseaux)\n• NF EN 12831 : calcul des déperditions thermiques (puissance de chauffage de base)\n• NF C 15-100 : installations électriques BT (France)\n• CONSUEL : attestation de conformité électrique avant mise en service ENEDIS\n\n**Réglementation frigorigènes :**\n• F-gas UE 517/2014 : attestation de capacité obligatoire, registres, contrôles étanchéité\n• Contrôle : annuel (5-50 t éq. CO₂), semestriel (> 50 t)\n\n**Acoustique :** DnT,A ≥ 53 dB entre logements. REI 60 (résistance au feu planchers)\n\n**Responsabilité :** garantie décennale (10 ans, vices compromettant l'ouvrage)\n\n**Urbanisme :** Loi ELAN (2018) : 20% logements neufs accessibles PMR, 100% évolutifs\n\n**Énergie locale :** PCAET obligatoire pour EPCI > 20 000 hab. (transition énergétique locale)"}
  ,{id:"fed_f17",title:"🎓 E5 — CTA & VMC double flux : formules, variateurs, équilibrage aéraulique",bloc:"Bloc 4",tags:["E5","CTA","VMC","Double flux","Variateur SSD 650","Anémomètre","Kistock RF","Puits canadien","Aéraulique","Wesper"],duree:28,niveau:"Avancé",qbank:"fed_e5_cta",contenu:"**CTA double flux — rappels clés :**\n\n**Formules :**\n• Puissance air : P = **0,34 × qv × ΔT** (kW, qv en m³/h, ΔT en °C)\n• Débit à l'anémomètre : qv = **V × S × 3600** (m³/h, V en m/s, S en m²)\n• Efficacité échangeur : **η = (Ts - Text) / (Tr - Text)** × 100%\n\n**CTA Wesper PR90 (salle de spectacle Limours — sujet CCF) :**\n• Débit soufflage : 5 000 m³/h (salle) / 8 000 m³/h max constructeur\n• Débit air neuf : 3 000 m³/h (air extérieur + puits canadien)\n• Variateur soufflage : SSD Drives série 650 — paramètre **P6** = fréquence max (réglage prioritaire)\n• Variateur extracteur : OCS 900, 900 W, 5A @ 40°C\n• Régulation : TREND IQ3xcite 96 → T°, CO₂, débit via boîtes de mélange BM/BM2\n\n**VMC double flux (sujet CFA) :**\n• Débit de base T3 : **90 m³/h** | pointe : **105 m³/h** | sur-ventilation : **300 m³/h**\n• DTU 68.3 : tolérance ± 10% des débits de conception\n• Ordre de réglage : mesurer débits totaux AVANT les bouches\n\n**Débit réglementaire :**\n• Salle de spectacle : **18 m³/h/occupant**\n• Bureaux : 25-30 m³/h/personne\n\n**Puits canadien :** conduit enterré (~12-14°C sol) → préchauffage air ext en hiver, rafraîchissement en été. Branché sur boîte de mélange BM de la CTA.\n\n**Réglage bouches (TP4) :** agir sur l'obturateur intégré à la bouche → re-mesurer → documenter dans Kistock RF."}
  ,{id:"fed_f18",title:"🎓 E5 — Équilibrage hydraulique : vanne TA, ECBT & débitmètres",bloc:"Bloc 4",tags:["E5","Vanne TA","Kv","ECBT","Équilibrage","TESTO 922","PCE-HAWA30","Glycol","Circulateur","Débit"],duree:25,niveau:"Avancé",qbank:"fed_e5_hydraulique",contenu:"**Formules hydrauliques essentielles :**\n• **P = qv × 1,163 × ΔT** (kW) — puissance eau (qv m³/h, ΔT °C)\n• **qv = P / (1,163 × ΔT)** — débit pour puissance donnée\n• **Kv = 0,01 × q / √ΔP** (q en l/h, ΔP en kPa) — réglage vanne TA\n• **Débit réel = q_CBI / √γ** — correction glycol (γ = densité fluide)\n\n**Exemples de calcul :**\n| P (kW) | ΔT (°C) | qv (m³/h) |\n|---|---|---|\n| 30 | 10 | **2,58** |\n| 70 | 15 | **4,01** |\n| 9 | 5 | **1,55** |\n\n**Appareils de mesure :**\n• **TESTO 922** : thermomètre différentiel 2 canaux TC type K, ±(0,5°C + 0,3% v.m.), -50°C à +1000°C\n• **Thermomètres fixes GESA** : ±2°C, lecture directe sur circuit\n• **PCE-HAWA30** : débitmètre ultrasons clamp-on (externe, non invasif), ±2-3%\n• **Vanne TA STAD** : mesure par différence de pression ΔP → q via abaque\n\n**Règles d'installation vanne TA :**\n• Minimum **5D** en amont de toute perturbation (coude, pompe)\n• Minimum **2D** en aval\n• Purger les raccords de mesure avant lecture (éliminer bulles d'air)\n\n**Circulateur SALMSON SCX 32-80 :**\n• 3 vitesses : 1900 / 2280 / **2665** tr/min (vitesse 3 = max)\n• Triphasé 400V/50Hz, 2 pôles\n\n**Équilibrage réseau :** chaque branche doit recevoir son débit nominal ± 5-10%. Sans équilibrage : branches courtes volent le débit des branches éloignées."}
  ,{id:"fed_f19",title:"🎓 E5 — Régulation & chaudière : RMH760B, loi d'eau, combustion",bloc:"Bloc 4",tags:["E5","RMH760","LPB","Loi d'eau","Droite de chauffe","Fioul","PCI","Gicleur","Siegert","Condensinox","ACS"],duree:30,niveau:"Avancé",qbank:"fed_e5_regul",contenu:"**Régulateur Siemens RMH760B :**\n• Communication : bus **LPB** (Local Process Bus, 2 fils, protocole propriétaire Siemens)\n• Extension : module RMZ781\n• Logiciel PC : **ACS** (connexion via OCI700 USB)\n• Schéma type **H3-2** : chaudière + 1 circuit régulé par V3V + loi d'eau\n\n**Loi d'eau — régime 60/40 (Text_base = -5°C) :**\n| T_ext (°C) | T_départ réseau |\n|---|---|\n| -5°C (base) | **60°C** |\n| +5°C | ~52°C |\n| +15°C | ~44°C |\n| +20°C | **40°C** |\n\n• Pente : (60-40) / (-5-20) = **-0,8°C/°C**\n• Abaissement nuit : -3°C (consigne 21°C → 18°C)\n• Anti-gel : 9°C\n• Saison chauffe : 12/10 → 28/03\n\n**Fioul domestique (FOD) :**\n• PCI = **41 992 kJ/kg** ≈ 11,7 kWh/kg\n• PCS = 44 780 kJ/kg\n• Densité ≈ 840-850 kg/m³\n• Composition : C 84,3% / H 12,4% / S 0,5% / O₂ 2% / N₂ 0,8%\n\n**Débit gicleur :**\n**q (l/h) = Calibre (Usgal/h) × 3,78 × (P_pulv/7)^0,5**\nExemple : 1 Usgal/h sous 7 bar → 3,78 l/h\n\n**Analyse de combustion (4 mesures clés) :**\n1. **CO₂%** ou O₂% → excès d'air\n2. **CO** (ppm) → qualité combustion (max 100 ppm)\n3. **T° fumées** (°C) → pertes sensibles\n4. **Indice Bacharach** (fioul) → suies (max 4 admis)\n→ Calcul rendement PCI par formule de **Siegert**\n\n**Chaudière condensation :**\n• Rendement PCI ≥ **94%** requis\n• Mise en service : tablette **CozytouchC** (Atlantic) = C6 40%\n• Vérifier T° fumées < 55°C (condensation effective)"}
  ,{id:"fed_f20",title:"🎓 E5 — GTB/KNX : programmation ETS5 & domotique (EVA Studios)",bloc:"Bloc 4",tags:["E5","KNX","ETS5","Adresse physique","Adresse de groupe","Scénario","Actionneur","Variation","ARGUS","Luxmètre","EN 12464"],duree:25,niveau:"Avancé",qbank:"fed_e5_knx",contenu:"**Démarche de programmation ETS5 (C6 — 40% de la note) :**\n1. Créer projet (médium TP)\n2. Ajouter appareils depuis le catalogue (référence MTN, ABB...)\n3. Affecter **adresses physiques** (1.1.1, 1.1.2...) via bouton de programmation\n4. Configurer les objets de communication de chaque appareil\n5. Créer les **adresses de groupe** (0/1/1, 0/1/2...)\n6. Lier objets → adresses de groupe\n7. Télécharger dans chaque appareil\n8. Tester en temps réel (moniteur de bus ETS5)\n\n**Projet EVA Studios (sujet E5 KNX CFA 2026) :**\n| Adresse | Appareil | Référence |\n|---|---|---|\n| 1.1.1 | Commande 8 touches S1 | MTN6284xx |\n| 1.1.2 | Commande 8 touches S2 | MTN6284xx |\n| 1.1.3 | Actionneur commutation | MTN647593 |\n| 1.1.4 | Actionneur store (VR) | MTN649802 |\n| **1.1.5** | **Actionneur variation** | MTN649350 |\n| 1.1.6 | Détecteur ARGUS 360° | MTN6309xx |\n\n**Circuits commandés :**\n• E1, E2 : éclairage gradable (variation 0-100%)\n• E3 : télérupteur (commutation ON/OFF depuis S1 ET S2)\n• VR : volet roulant (descente/arrêt, montée/arrêt)\n• Scénario 1 : E1+E2 à 20% + descente VR\n\n**Maintenance KNX — protocole diagnostic :**\n1. Analyser le symptôme\n2. Vérifier tension bus : **29-31V DC** entre fils KNX\n3. Test communication ETS5 (lecture/écriture)\n4. Vérifier câblage physique\n5. Tester appareils individuellement\n6. Conclusion + action corrective\n\n**Éclairage — normes :**\n• EN 12464-1 : couloirs ≥ **100 lux**, bureaux ≥ 500 lux\n• Mesure au **luxmètre** en plusieurs points → valeur moyenne Ēm"}
  ,{id:"fed_f21",title:"🎓 E5 — ECS solaire : régulateur SKSC3, PT1000, performances",bloc:"Bloc 4",tags:["E5","ECS solaire","SKSC3","Sonnenkraft","PT1000","Glycol","Légionellose","Rendement capteur","CS10","Arrêté 2007"],duree:22,niveau:"Intermédiaire",qbank:"fed_e5_ecs",contenu:"**Régulateur SKSC3 Sonnenkraft :**\n• 8 entrées sondes **PT1000** (F1 à F8) + 1 entrée ensoleillement **CS10**\n• 4 sorties relais dont 3 sorties **pompe tachymétrique** (variation de vitesse)\n• Alimentation : 230V AC/50Hz\n\n**Affectation des entrées (CCF Limours) :**\n| Entrée | Rôle |\n|---|---|\n| F1 | Retour panneau |\n| F2 | Ballon ECS |\n| F7 | Aller panneau |\n| F4/F5/F6 | Eau chaude / mitigée / froide |\n| F8 | Volumètre V40 |\n| CS10 | Rayonnement solaire |\n\n**Identification sondes PT100 vs PT1000 :**\n• Mesure à l'ohmmètre (câble déconnecté)\n• À 0°C : PT100 = **100Ω** / PT1000 = **1000Ω**\n• À 20°C : PT100 ≈ 107,8Ω / PT1000 ≈ **1078Ω**\n\n**Fluide caloporteur :** eau glycolée à 20% (protection antigel ~ -8°C)\n\n**Régulation différentielle :**\nPompe ON si T_F7 (aller panneau) − T_F2 (ballon) > seuil haut (ex: 5°C)\nPompe OFF si ΔT < seuil bas (ex: 2°C)\n\n**Rendement capteur solaire :**\nη = Pu / Pi = **(qv × 1,163 × ΔT)** / **(G × A_capteur)**\n\n**Réglementation légionellose (Arrêté 3 mai 2007) :**\n• T° production ≥ **60°C**\n• T° distribution ≥ **50°C** en tous points\n• Purge thermique périodique\n• Carnet sanitaire obligatoire pour ERP"}
  ,{id:"fed_f16",title:"🎓 Guide Épreuve E5 — Intervention sur les systèmes (4h coeff. 5)",bloc:"Bloc 4",tags:["E5","C6","C7","C8","Kistock RF","CozytouchC","Bilan thermique","COP","Combustion","Échangeur","Appareils de mesure","Sécurité","Annales 2026"],duree:35,niveau:"Avancé",qbank:"fed_e5_bilan",
    contenu:"**Épreuve E5 — Cadre général :**\n• 4 heures, coefficient 5, note sur 20, épreuve ponctuelle\n• Jury présent TOUTE l'épreuve → vous êtes interrogés en continu\n• Structure TOUJOURS identique en 3 parties (tous les sujets 2025-2026)\n\n**Compétences évaluées et leur poids :**\n| Compétence | Poids | Ce qu'il faut faire |\n|---|---|---|\n| C6 — Outils numériques | **40%** | Maîtriser Kistock RF / tablette CozytouchC |\n| C7 — Essais & mesures | 30% | Protocole + appareils adaptés + sécurité |\n| C8 — Vérifier performances | 30% | Calculer + comparer constructeur + interpréter |\n\n**Sujets tombés (sessions 2025-2026) :**\n• CTA/PAC York (RJ41) : bilan batterie chaude, bilan PAC complète\n• Chaudière fioul basse T° : bilan générateur + combustion, émetteurs, échangeurs sanitaires\n• Chaudière gaz Condensinox : bilan générateur + combustion, échangeurs (plaque + multitubulaire)\n• PAC air/eau Atlantic Alféa Excellia R410A : calcul COP chaud/froid, comparaison constructeur\n• Chaudière granulés Froling : bilan générateur biomasse, enjeux environnementaux\n• Chaudière gaz condensation Atlantic : mise en service CozytouchC, rendement ≥ 94%\n\n**4 étapes le jour J :**\n1. **Prise en charge (~45 min)** : Compléter schéma de principe, rédiger nomenclature, définir procédure + appareils, identifier capteurs GTC\n2. **Mise en service + mesures (~1h30)** : Mettre en fonctionnement via GTC, attendre stabilisation, relever températures/débits/pressions/HR\n3. **Enregistrement numérique (~45 min)** : Configurer Kistock RF (ou tablette CozytouchC), lancer l'enregistrement, exporter les données\n4. **Calculs + analyse (~1h)** : Calculer puissances/rendements/COP, comparer valeurs constructeur, interpréter écarts, conclure\n\n**Formules indispensables (à maîtriser les yeux fermés) :**\n• **Puissance eau :** Φ = ṁ × Cp × ΔT (Cp_eau = 4186 J/kg·K, ṁ en kg/s)\n• **Puissance air :** Φ = q × ρ × Cp × ΔT (ρ_air ≈ 1,2 kg/m³, Cp_air ≈ 1005 J/kg·K)\n• **COP PAC :** COP = Φ_utile / P_absorbée\n• **Rendement chaudière PCI :** η = Φ_utile / Φ_absorbée (Φ_abs = qm_combustible × PCI)\n• **Débit massique :** ṁ = Q × ρ (Q en m³/s)\n• **Efficacité échangeur :** ε = ΔT_réel / ΔT_max (ΔT_max = T_chaud_entrée − T_froid_entrée)\n• **Pertes fumées (Siegert) :** qA = (T_fumées − T_air) × (A₁/CO₂ + B)\n• **Débit air (CTA) :** Q = v × S\n\n**Données de référence :**\n• T_ext hiver = −4°C (HR 90%) | T_ext été = 35°C (HR 40%)\n• T_int hiver = 20°C | T_int été = 26°C | Cep_ref = 58,4 kWhep/m²/an\n• PCI gaz naturel ≈ 10,2 kWh/m³N | PCI fioul ≈ 11,89 kWh/kg\n\n**Appareils de mesure — lesquels choisir :**\n| Appareil | Mesure | Quand |\n|---|---|---|\n| Thermo-hygromètre | T° + HR air | CTA, ambiance |\n| Thermomètre laser | T° surface (sans contact) | Tuyaux, échangeurs |\n| Thermomètre à contact | T° surface précise | Départ/retour eau |\n| Analyseur de combustion | O₂, CO₂, CO, T° fumées | Chaudière gaz/fioul |\n| Débitmètre PCE-HAWA30 | Débit eau | Circuits hydrauliques |\n| Anémomètre à hélice | Vitesse d'air | Gaines, soufflage |\n| Pince ampèremétrique | Puissance électrique | Compresseur PAC |\n| Kistock RF | Enregistrement multi-capteurs | C6 — toujours utilisé |\n\n**Erreurs fatales à éviter :**\n• ❌ Relever avant stabilisation thermique (attendre 10-15 min minimum)\n• ❌ Oublier les conversions d'unités (L/h → kg/s avant de calculer Φ)\n• ❌ Ne pas comparer aux valeurs constructeur (C8-3 = cœur du sujet)\n• ❌ Rester silencieux face au jury (argumenter même si incomplet)\n• ❌ Omettre les règles de sécurité (EPI, consignation, risque brûlure, frigorigène)\n• ❌ Ne pas conclure chaque partie (conformité ? améliorations ?)\n\n**Checklist avant de rendre :**\n☑ Schéma de principe complété + légende\n☑ Procédure rédigée avec appareils justifiés\n☑ Consignes de sécurité mentionnées\n☑ Relevés effectués APRÈS stabilisation\n☑ Tableau de mesures complet (T°, débits, pressions, HR)\n☑ Analyse de combustion effectuée (si chaudière gaz/fioul)\n☑ Kistock RF / tablette configuré + données exportées\n☑ Tous les calculs avec unités cohérentes (SI)\n☑ Comparaison systématique valeurs mesurées / constructeur\n☑ Écarts IDENTIFIÉS et EXPLIQUÉS\n☑ Résultats dans diagramme de l'air (si CTA)\n☑ Conformité réglementation vérifiée (Arrêté 3 mai 2007, RT existant)\n☑ Au moins 2 propositions d'amélioration concrètes\n☑ Conclusion générale rédigée"}
  ,{id:"fed_f16",title:"Photovoltaïque avancé : technologies, raccordement et optimisation",bloc:"Bloc 2",tags:["Photovoltaïque","STC","Onduleur","MPPT","Autoconsommation","PR","NF C 15-100","RGE"],duree:22,niveau:"Avancé",qbank:"fed_photovoltaique2",
    contenu:"**Technologies PV :**\n• Mono-Si : rendement 18-22%, durée de vie 25-30 ans, coût élevé\n• Poly-Si : rendement 15-17%, coût inférieur, aspect grenu bleuté\n• HJT (hétérojonction) : rendement > 22%, faible coefficient T°\n• Bifacial : capture lumière face avant + arrière (+5-15%)\n• PERC, IBC : technologies haute performance\n\n**Conditions standard (STC) :**\n• 1000 W/m², 25°C cellule, spectre AM 1,5\n\n**Composants système :**\n• Onduleur string : DC/AC, MPPT, anti-îlotage obligatoire\n• Micro-onduleurs : 1 par panneau, meilleur si ombrage partiel\n• Onduleur hybride : gère aussi les batteries\n\n**Performance :**\n• PR (Performance Ratio) = E_AC produite / (Pc × Irradiation). PR > 80% = installation saine\n• Dimensionnement : Puissance (kWc) = Consommation (kWh) / Production spécifique (kWh/kWc)\n\n**Raccordement et démarches :**\n• CACSI + CRAE + déclaration mairie + Consuel + RGE\n• Autoconsommation avec vente surplus : tarif S06 ENEDIS\n• Anti-îlotage : déconnexion en 2 s si réseau coupé\n\n**NF C 15-100 + UTE C 15-712-1 :**\n• DC : parafoudre DC, sectionneur, câbles PV double isolation ≥ 1000V\n• AC : DDR 30 mA type A/B, parafoudre AC, disjoncteur de branchement\n\n**Stockage batteries :**\n• Lithium (LFP/NMC) : 800-1000 €/kWh, 3000-6000 cycles, 10-15 ans"}
  ,{id:"fed_f17",title:"Isolation thermique et acoustique — matériaux et réglementation",bloc:"Bloc 2",tags:["Isolation","Lambda","Résistance thermique R","Coefficient U","ITE","RE2020","Pont thermique","Acoustique"],duree:20,niveau:"Avancé",qbank:"fed_isolants_therm",
    contenu:"**Paramètres thermiques fondamentaux :**\n• Conductivité thermique λ (W/m·K) : plus λ est petit → meilleur isolant\n• Résistance thermique R = e / λ (m²·K/W)\n• Coefficient U = 1 / R_total (W/m²·K) : plus U est bas → meilleure isolation\n\n**Principaux isolants et λ :**\n• Laine de verre : λ 0,032-0,040, légère, bon rapport Q/P\n• Laine de roche : λ 0,035-0,045, incombustible (A1), meilleure résistance feu\n• Polyuréthane (PUR/PIR) : λ 0,022-0,028, plus mince, combustible\n• Ouate de cellulose : λ 0,038-0,042, biosourcé, hygroscopique, déphasage élevé\n• Aérogel : λ ≈ 0,015, le meilleur isolant, très coûteux\n\n**Types d'isolation :**\n• ITE (par l'extérieur) : supprime les ponts thermiques, préserve l'inertie → IDÉAL\n• ITI (par l'intérieur) : moins chère, ponts thermiques maintenus, surface réduite\n• Isolation rampants/combles : soufflage en vrac (ouate, laine), vrac lié\n\n**Ponts thermiques :**\n• Coefficient Ψ (psi) W/m·K : déperdition linéique\n• Risque : condensation + moisissures si T_surface < point de rosée\n• Traitement : rupteurs de pont thermique, ITE\n\n**Réglementation RE2020 :**\n• Murs ≤ 0,20-0,28 W/m²K, Toiture ≤ 0,12-0,15, Plancher ≤ 0,27-0,32\n• Vitrage ≤ 1,0-1,3 W/m²K, Facteur solaire g optimisé\n• DH (Degrés-Heures) ≤ 1250 pour confort d'été\n• ACV (bilan carbone), Bbio, Cep et Cep_nr\n\n**Acoustique :**\n• Rw (dB) : affaiblissement aux bruits aériens\n• Ln,w : bruits d'impact\n• NRA : DnTA ≥ 53 dB entre logements"}
  ,{id:"fed_f18",title:"BEPOS, RE2020 et systèmes de distribution efficaces",bloc:"Bloc 2",tags:["BEPOS","RE2020","BBC","Passivhaus","VMC double flux","PAC","PCBT","GTB","Étanchéité","DH"],duree:22,niveau:"Avancé",qbank:"fed_bepos_sdt",
    contenu:"**Niveaux de performance énergétique :**\n• BBC (RT2012) : Cep ≤ 50 kWhep/m².an\n• RE2020 (2022) : Bbio + Cep/Cep_nr + Icénergie (ACV carbone) + DH (confort d'été)\n• BEPOS : production annuelle > consommation annuelle\n• Passivhaus : ≤ 15 kWh/m².an chauffage + n50 ≤ 0,6 vol/h + VMC DF ≥ 75%\n\n**RE2020 — 3 indicateurs clés :**\n• Bbio : besoins bioclimatiques (isolation, compacité, orientation)\n• Cep_nr : consommation énergie primaire non renouvelable\n• Icénergie : empreinte carbone des matériaux et de la construction (ACV)\n\n**Étanchéité à l'air :**\n• n50 ≤ 0,6 vol/h (RT2012 MI : Q4Pa ≤ 0,6 m³/h/m²)\n• Test blower door obligatoire pour BBC et labels\n\n**Ventilation :**\n• VMC simple flux hygroréglable (type B) : base\n• VMC double flux : récupération chaleur 85-95% → indispensable bâtiment performant\n\n**Systèmes de distribution :**\n• PAC air/eau : SCOP 2,5-4,0, compatible basse T°\n• Plancher chauffant BT (PCBT) : eau 35-45°C, compatible PAC, rayonnement\n• CESI (solaire thermique) : 50-70% des besoins ECS\n\n**Gestion et pilotage :**\n• GTB classe A (EN 15232) : économie 25-30% vs sans automatisation\n• Régulation par zones, gestion éclairage, stores, monitoring\n\n**Confort d'été RE2020 :**\n• DH ≤ 1250 : inertie thermique, protections solaires, g faible, sur-ventilation nocturne"}
];

